insert into public.lesson_records (lesson_record_id, student_id, course_id, staff_id, lesson_date, start_time, end_time, title, content, homework, memo) values
  ('cfa166fd-e112-53c8-b589-1c8b7cd78e99', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-08', '16:30:00', null, '通常 / 完成形を見て細分化して考えることに慣れる', '完成形を見ながら、それぞれのスプライトの動きを見たまま説明してもらい、それをコードの言葉に直してみるというのを繰り返してみました。 「旗を押したらゾンビが右を向いている」「だるまさんがころんだと終わりまで言う」 「言葉が終わったら左を向く」と口に出させ、「右を向いている」というのはコードでいうとどういうことか、と促すと、自分でコードを組むことができました。どこから手を付けたらよいのかわからなかった動きが、自分でできる範囲でコード作成できることに、少し意外そうな様子を見せていました。 同じように、プレイヤーの動きを作成し、このゲームではどういうときにアウトになるか、その動きはどのスプライトのどのコードにあたるのか、と質問をしていくと、少しずつ細分化の思考に慣れていったようでした。 「習ったことがあるブロック」「習っていない（あるいは忘れてしまった）ブロック」の意識がとてもハッキリしているため、「コスチューム#」などは、「今回初めて使うから」と説明するようにすると、素直に受け入れられるようでした。 人見知りはするけれど、基本的には先生にそばにいてほしいタイプなので、細分化をするところからの自走はまだ無理ですが、細分化をして使用するブロックを確認するところまで一緒にやると、その後の組み立ては自分でやってくれるようになりました。', '完成を目指す', 'タイピング: 指をケガしていたため省略
盛り上がり: 先週の時点では何から作成したらよいのか見えていなかったのが、写経ではなく自分で考えてプログラムできたことが満足そうでした。'),
  ('1f13cabc-1d30-5159-9ec4-c23700a2556b', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-08', '16:30:00', null, '通常 / 完成形を見ながらの細分化＆複数のスクリプトの並列に慣れる', '今日は新しい課題に入ると告げると、一瞬「大変」という反応をしましたが、今日は動画ではないことを説明してゲームをさせたところ、予想以上にゲームの構成がわかりやすかったのが嬉しかったのか、細分化の話にも積極的にのってきました。 アルくんの動きを要素ごとにわけて考えるのも楽しそうで、メモを取った細分化の用紙を見ながらスムーズにコードを作成していました。 壁にあたったら跳ね返る歩数のところで一瞬躓きましたが、それ以外は「ずっと」の入れ忘れ、「待つ」ブロックの入れ忘れなどにもコード実行してみてから自分で気づいていました。実行後に動作のおかしいところを発見し、該当のコードを見つけることが問題なくできていました。そうちゃん自身もそれに気づいたようで、「今回は簡単だったから自分でいろいろできた！」と嬉しそうでした。 ゲームクリアやゲームオーバーなども自分でアレンジを加えながら作成して、スプライトの動く速さによる難易度の調整までして、満足して授業を終えていました。', null, 'タイピング: プレイグラムの練習モードを一通り済ませて、少し飽きたようだったので、教室の高学年の子に人気だからといって寿司打を見せたらとても喜んでいました。自分の現在のレベルより少し上だけど、クリアできないわけではないという難易度が気に入ったとのことで、次回もこれをやりたいとのことでした。
盛り上がり: 自分で細分化してコードを作成するのが予想以上にはかどっていました。よくわからない状態で写経するよりも、こちらの方が圧倒的に楽しそうでした。'),
  ('523806b4-9be4-5b3d-99dd-7e5c2612a08f', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-08', '16:30:00', null, '通常 / 宇宙バトルを復習して作ろう', '先週コードづくりが全然だったので、コードを作らせることを優先しました。野球の形で作ろうとしましたが、わからないとのことだったので、結局元の素材に戻りました。コスチュームなどいろんなところに手を出すが、頭の整理が追い付かなくなるので、結局拗ねて諦めちゃうことが何度かあったので、今日は踏ん切りつけて選び出す前に止めました。動画は一連の動き説明文があるとこまで見せ、文章に対応するコードが選べるか試してみました。ほとんど、コードが忘れていて、一から教えました。特に、スプライトの位置をゲーム画面上で動かして終わりになることが多かったので、座標を使って最初に決めることを意識させました。ほぼ付きっ切りでなんとか宇宙バトル１までの工程は完成できました。', null, 'タイピング: 新エリアに進みました。
盛り上がり: 球が自由に動かせるように魔改造されていました。'),
  ('a4c453e5-2290-5b72-88cc-3805d0f86f1f', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-08', '16:30:00', null, '通常 / アルスタジオ/プラットフォーマゲームの基礎スキル オリジナル作品 前回欠席の前は、もう少し作り込みたいとのことだったので、希望するようならそちらを。 なんとなくいじり続けるのではなく、最初に今日の目標を決めて。 次の教材に入るのならprg20番台または機械学習', '機械学習についてはあまりよくしらないようでした。画像認識についてはあまりピンとこないようでしたが、テキストをふまえつつ説明すると仕組みはなんとなく理解してくれたようです。まずモノを認識するプログラムを動かしました。確信度の考え方が新しかったようです。埴輪や眼鏡を映して検証していました。 その次にじゃんけんのプログラムを作りました。背景をきちんと白にして把握させていたので良かったです。リストはほぼ使ったことがなかったようですが、考え方は把握できたようです。判定の部分は時間がなかったので、解説しながらテキストを見て進めました。タイピングが多かったものの、全て自力で取り組めていました！', null, 'タイピング: 集中して取り組めていました。'),
  ('6bc5dc92-0d0d-50d3-b77e-64c6fcaced53', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-08', '16:30:00', null, '通常 / かくれんぼゲームを完成させよう', '先週までで、探し当てる機能はできていたので、時間制限や探知など作っていきました。特に、変数や不等号の迷いなく作れていました。動画が一通り終わったら、隠れる人を増やすなどのアレンジ提案をしたが、もう完成したらしくプラスアルファは気が進みませんでした。 時間が半分ほど余ったので、だるまさんが転んだの細分化をやらせました。だいたいの動きを把握できていましたが、細かい主語や方向が抜けていたので、主述の関係をしっかり描くようにできました。これをもとに次回作っていく予定です。', '細分化をもとにだるまさんがころんだ', 'タイピング: よくやっていました
盛り上がり: キラキラな世界でかくれんぼゲームできました。'),
  ('b131959d-9789-5946-984b-de70b41ab2b2', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-06', '17:30:00', null, '通常 / 機械学習 導入～序章、第1章', '今回初めての機械学習についてのプログラムをScratchを通して学んでいきました。カメラを通してジャンケンの種類を機械に学習させていき、自身の出した手と機械で勝負をするプログラムを作っていきました。カメラで事前にグー、チョキ、パーと三つの手について学習させていきましたが、認識がなかなか上手くいってくれず少し苦戦している様子でした。ですので、機械学習の肝となってくるデータ数を増やしていき問題を解決することが出来ていました。ジャンケンもしっかりと勝負することができるようになっていたので、プログラムを完成させることが出来ていました。', null, '盛り上がり: ジャンケンの判定をしっかりとできるようにすることが出来ていたので、プログラムの完成を喜んでいました。'),
  ('d64c194a-b096-5e59-83f4-e42abc35904b', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-06', null, null, '通常 / クローンを活用したゲーム作成に慣れる', '先週から作成しているシューティングゲームは気に入っているようで、やりたいことも頭にあったのか、「今のところは自分でできそう」と言ってきて、熱心に自走できていました。 コスチュームのお絵描きをすることもありましたが、依然のように適当にお絵描きをするのではなく、コスチュームの色をグラデーションにして少し立体的に見せるなど、そうすけくんなりの必然性があって手を加えている様子が見られたため、お絵描きのときは様子を見ながら好きにさせておきました。必要な編集が終わるとすぐにコードに戻ってゲームの完成度を上げようとしていたので、他人が見てわかりやすいゲームを作ろうという意識はだいぶ育ってきていると思われます。 敵が自機に向かって飛んでくる速さなども、いろいろ試して難易度を調整していました。 「すべてを止める」ブロックの3つのコードの使い分けはまだ迷いが見られましたが、実際の動きを見ながら修正することはできていました。 クローンを使うことが面白いとのことで、次回以降ももう少しクローンの学習を続けてみたいそです。', 'クローンを使った学習を希望しています', '時間帯: その他
タイピング: 淡々と1度だけやっていました
盛り上がり: 満足のいくゲームが完成できたようで、スッキリした感じでした。 ゲーム中の画像効果など、面白いところを指摘すると、嬉しそうに該当のコードを見せて説明してくれたりもしていました。'),
  ('36f59dab-df4b-58c9-89d6-a337fe2856bb', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-02-06', '17:30:00', null, '通常 / 機械学習 導入～序章、第1章', '今回からScratchを用いての機械学習について挑戦していきました。日頃使われている顔認証やGoogleレンズなどの基礎となる内容についてScratchを通して学んでいきました。カメラを用いてジャンケンで何を出しているのかを機械学習させていき、プログラミングと組み合わせて勝敗判定をしていくことが出来ていました。現代社会においても使われている技術の初歩的な内容についての学習でしたので、身近にあるものと比較して考えながら学習を進めていました。', null, 'タイピング: 丁寧に打つことが出来ていました
盛り上がり: ジャンケンをカメラを通して機械と勝負することができていて、機械学習の基礎となるデータの重要性についてもしっかりと理解することが出来ていました。'),
  ('02fb149d-3c0e-5141-a4b7-7d247673defb', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-03', null, null, '通常 / 乱数の習得', 'サイコロとじゃんけんを順にやり、乱数について少し説明を入れると、その意味を感覚的に理解したようでした。スプライト同士のメッセージの流れも分かったようで、一通り完成したあとは、BGMとして自分の声を録音するなど軽くアレンジをしました。', null, '時間帯: その他
タイピング: 楽しくやっていました
盛り上がり: 楽しく集中しながら取り組めました。'),
  ('f706db6d-e558-5700-a8e4-b34b0f3082b3', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'bccc3401-27c9-585a-943b-e6cd207e8a46', '2024-02-03', null, null, '通常 / 機械学習の導入を学ぶ', '導入の際、大貴君とちひろ君に、身の回りの機械学習、画像認識が使われている例を考えてもらいましたが、なかなか思いつかないようでした。こちらからFaceIDなどいくつかの例を出すとようやく、そういうことか、と納得したようでした。 序章で教室の備品などの認識をさせたところ、候補や確信度の動きに興味を持ったようで、熱心に見ていました。 ジャンケンの形の登録も面倒がらずに熱心にやっていて、ほぼ認識できるようになったことを確認して少し満足気でした。 ジャンケンゲームのプログラムは完成例を見ながら作成していましたが、完成した後に一生懸命、グーチョキパーそれぞれの認識確率を出すコードを作成していました。', null, '時間帯: その他
タイピング: 問題なくできていました
盛り上がり: 画像認識そのものに加えて、確率などにも興味を持てたようで、熱心にコードをいじっていました。'),
  ('89ca2b40-3071-593e-98e6-0673ba4ab0d8', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-03', null, null, '通常 / ピンポンゲーム', '細分化されたものを見せながら進めました。それぞれの動きの様子を見せると基本的にすぐコードが書けていたのですが、次の手順に行こうとしてもアレンジに時間をかけることも多かったです。ボールを硬貨にして跳ね返るたびに種類を変えるなど、アイデア自体は面白かったです。メッセージを使うときに、その名前をとても長くしていたので「これを他の人が見たらびっくりしちゃうな」などと伝え、コードの読みやすさについての意識も持ってもらいました。', '検定練習問題 or 今回のゲームを完璧にお手本(細分化されたもの)通りに作り直してみる？', '時間帯: その他
タイピング: 熱中していました
盛り上がり: アレンジなど本筋以外に意識が向かっている様子でした。'),
  ('c81cec4b-601b-5e35-80a5-109c1d3a5da3', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-03', null, null, '通常 / 【Prg】29 カミナリをよけろゲームを作ろう！ 動画無しで、完成形だけ見ながらコードを考える練習', '動画を見ながら始めました。かみなりを落とす動作、あるくんの動きは丁寧にできていました。後半は、動画を見ないで取り組むように伝えました。はとがあるくんを連れていくところですが、鳩やあるくんの動きが速すぎて見本と違う感じになってしまいました。何度か改善してほしいところを伝えたのですが、内容が分からなかったのか、プログラム的に分からなかったのかあまり改善しませんでした。 学校で取り組んでいる製作（Javascriptかな？）の方に気持ちがあったようで、心ここにあらずでした。ゲームは完成しました。', null, '時間帯: その他
タイピング: しっかり取り組めました。'),
  ('d6bde091-b848-559f-a506-b9d92ecf8c98', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-02-03', null, null, '通常 / 基本的なスキルを確認しながらゲーム作成', '最初は【Prg】04 迷路脱出ゲームに取り組みましたが、先生の人数が足りずに自走していて混乱したようなので、本人の申し出もあり、基本操作コース02_名前を動かそうに切り替えました。 進め方がわからずにカードをペラペラしていたので、表面の文章を読ませ、1行ずつブロックを探していくことを教えたところ、自分の知っているブロックだ！となったようで、「もしかして、これって簡単？」と言いながら進めていました。 1つできたらスタンプを押すと、喜んで一気に取り組んでくれました。 拡張機能の「おんがく」を使うところだけ、初めてということで一緒にやりました。 使いたいブロックがどの分類にあたるかはよくわかっていて、的確に探すことができていました。そこを指摘すると嬉しそうに笑っていました。 コースの最後までできていたので、今日はスプライトの見た目や動きをいろいろ変えるスキルがきちんと身についていることがわかったね、ということを確認しました。 今日の内容は楽しかったようで、終わってからもカードを楽しそうに見直していたので、そのまま「名前を動かす」アレンジに入ることにして、自分の名前のスプライトを用意しました。', '名前を動かすアレンジから', '時間帯: その他
盛り上がり: ファイルの1行をコンプリートできたのがとても嬉しそうで、お母さんにも得意そうに見せていました。 自分の名前をローマ字スプライトで表示するのも嬉しそうでした。'),
  ('28407d17-958d-589c-9736-f0e3711f3ac1', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-03', null, null, '通常 / スクラッチではじめるきかい機械学習 機械学習の説明から入って', '機械学習についてはあまりよく知らなかったようなので、Googleフォトを例に説明しました。カメラにさまざまなもの（やかん、コップなど）を映して、どのように認識されるのかを一緒に確認しました。 次にじゃんけんのプログラムを作成しました。画像を学習させるのがあまりうまくいかず、何度か再学習させていました。勝敗判定のプログラムはうまくできていました！作成したプログラムはピンクの豚のコンピュータに直接保存しました。', null, '時間帯: その他
タイピング: 集中して取り組めました。'),
  ('ee3a3950-9c12-5cc9-bfcf-68419dd25be0', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-03', null, null, '通常 / 基本操作コース04_ゆうれいから逃走 細分化されたものを見せて、自分でできるところは自力で作成してみる（上下移動はできそうなので、うまく褒めて）', 'ゲームに興味を持ってくれたようです。上下左右に動かすプログラムは座標ではなく向きと歩数で作ってくれました。向きの考え方が少し苦手なようで、推すキーと角度の整合性をとるのに困っていました。またひっくり返らないようにするためのブロックを再度説明しました。音を鳴らすブロックもプログラムできていました。「もし」の使い方もおさらいしました。 次回、スコアを足したり終わりを作ったりして、ゲーム性を高めていく予定です。', null, '時間帯: その他
タイピング: とても熱心に取り組んでいました！ステージも進んだようです。'),
  ('913b9d71-2dc2-5157-bc2a-a938f90c034e', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-03', null, null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！続き 動画を見ずに自力で途中まで作成済み。そろそろ複雑な箇所で行き詰りかけているので、動画を必要な箇所だけ（ボールの動き）見せて整理させてもよいかも。', 'ボールの変数はすでにうまくできていましたが、ゴールのスプライトやステージの動きがまだ未完成だったので、動画を見ながら取り組んでもらいました。とても丁寧にできていて良かったです。背景の名前を番号にして最後にプログラムを調整したのですが、次のステージにいかないようです。背景にあるプログラムは大丈夫そうなので、条件分岐か変数の設定にミスがありそうな気がします。来週は見本を見つつ、ミスを見つけて直していきたいです。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('2e585b99-d58e-5000-aa6f-377cd090f2dd', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-03', null, null, '通常 / リストの使い方を学ぶ', '同様のクイズ問題を、リストを使わないでコードを書くとどうなるかというのを一緒にやってみて、条件分岐が大変なことになるのを実感してからリストの説明をして、リストのメリットを理解してもらってから作成に入りました。なぜリストを使うのか、ということは理解できたようでした。 タイピングが速いこともあり、リストの作成自体はとてもスムーズに進んでいました。 完成後に、正解の時の画像効果などを工夫して楽しんでいました。 リストは初めてだったものの、プログラム自体は易しかったせいか、余裕をもって取り組めたようでした。 あと2～3回は、今日学んだリストの機能を使って、他にどんなことができるか実践していくということを予告して終わりました。', 'リストの都道府県クイズ、リストでおばけのかくれんぼあたりを', '時間帯: その他
タイピング: よくできていました
盛り上がり: プログラムに余裕があったのか、最近多かった、終わった後に「ちょっと疲れた」という様子も見せることもなく、スッキリしたように授業を終えていました。 ゆうかちゃんの好きなデザインや画像効果を工夫してゲームの見た目を楽しくすることができたのが嬉しそうでした。'),
  ('0d8c6aa8-cdff-5430-811e-8b26ffab4a3f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-03', null, null, '通常 / ではないまで待つなどの習得', '基本は動画を見ながら進めましたが、重要なポイントは一緒に意味を確認しました。左キーと右キーを交互に押したら動くのを確認した、「右/左キーが押されたではないまで待つ」のブロックをなぜ入れているのかを確認しました。「このブロックがないとずるいことができちゃうね」と誘導すると、長押しで動くのを防いでいることに気づきました。', '続き', '時間帯: その他
タイピング: 収支を＋にすることを目指して何度も頑張っていましたが、達成できずに残念そうでした
盛り上がり: いつもより脱線する回数は少なく、集中度が高かったです。'),
  ('90d9523f-da35-5c2c-a3b1-fd833bb2484b', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-02-02', '18:40:00', null, '通常 / 検定４級 演習問題② サメの問題', '概ね前の問題の次に〜という文章に惑わされることなく、きちんと問題通りに解けていました。ただし「すべてを止める」というコードのバリエーションがわからず、「すべてを止める」を選択したためにお題通りに動かない！というフラストレーションにつながっていたようです。 最後今までやってきた問題で、３種類のパターンの止めるをテストが終わった後どの止めるだと動きが変わってくるのかを見比べてみました。', null, 'タイピング: なし
盛り上がり: わかるところはとてもよくできていたと思います！また30分決められた時間内でとても集中し行っていました！'),
  ('5e24c493-71a5-56a4-8a19-07fd2e30a958', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-02', '17:30:00', null, '通常 / 『スクラッチではじめるきかい機械学習 https://amzn.asia/d/7m2nX7b』より 内容「じゃんけんをしよう」 ①AI学習とは何か～から始める ② 画像でグーチョキパーを認識 大元のアドレス https://stretch3.github.io/', '機械学習について大枠を考えてもらった後、じゃんけんのプログラムを作成しました。機械に覚えさせるところをかなり丁寧に取り組んでいて、枚数が多いほど精度が高くなることも考えられていました。途中、リストや変数が多用されているプログラムがありましたが、内容は理解できているとのことでした。最後のじゃんけんの判定も、条件分岐や演算子を使って全て自力でプログラムできていました。', null, 'タイピング: 集中して取り組めていました。'),
  ('19c38797-f425-5f1d-b572-3d7cf705f4d9', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-02-02', '17:30:00', null, '通常 / 基本操作コース０８ さぁ踊ろう ＞＞前回に続きペンツール、スタンプ、コスチュームを変えるの部分 すこし本人的には内容は優しめかも。もし乗り気ではなかったら、ジャンプ基礎でもOK', 'コスチュームを変えるときに全て見た目をしていしていましたが、「次のコスチューム」を使うことで簡略化できることに気が付いてもらいました。BGMを加えるときは見た目とは別のスクリプトを設定して、プログラムを分かりやすくすることも説明しました。最初にスプライトの座標を設定するのはこちらが言わなくても取り組めていました。メッセージの使い方を忘れていたようです。 見た目のアレンジとして色を変えたり明るさを変えたりしていました。また応援するスプライトを作って画面がにぎやかになっていました。楽しく取り組めていました！', null, 'タイピング: 損でした！これからに期待です。'),
  ('1af23ebd-df30-5eb7-9bfc-25dd3ecdd958', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-02-02', '17:30:00', null, '通常 / リストにしようと思いましたが、前週の嫌がり方の話を聞いたので急遽 『【Prg】51 どこまでいける？ネコのお散歩』を一緒にやることにしました。', '言葉の理解などが少し苦手なため、ビデオで話している言葉を聞かない傾向がある。 ＞先生と一緒にやればいいのかな？と思いひとまず一緒にやることに。 途中で色々質問をしながら、これってどんな時につかう物だっけ？など聞きながら進めていきました。やってきた積み重ねは確実に覚えてはいるので、安心はしていますがコードの読み間違い、取り違えが少なからずあるのと、「自分で絶対こうじゃないか？_」という思い込みが激しいためバグに繋がる傾向。 ただ本人的にはゲームを作るという方が楽しいことには変わらないので、しばらくこのスタイルで行くか・・・悩みものです。', '今日のビデオが20:00で終わっているので次回はその続きから', 'タイピング: 気分が乗らないとのことで今日はなし
盛り上がり: 上下の動きはY座標だということを見破ったりしているので、どちらの向きに向かうなどのコードに関しては問題はないかと思います。'),
  ('01ba58fd-0be4-5808-9eb2-83fd64f6df33', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-02-02', '16:30:00', null, '通常 / リストを使いこなす！①デバック問題の音をつける②幽霊のかくれんぼで座標とリスト', '最初におやすみの週もあったので一旦復習。 模型を用意して説明したところだいぶ感覚がつかめたようで、音階という楽器の中にリストがあって、乱数を使用することを学びました。 その後、同じ要領だということをあらかじめ伝えておいて、幽霊のかくれんぼで同じようにリストを今度は変数の中にいれて幽霊を色々な場所に隠すという部分までやってみました。 まこちゃんの頭の回転が良かったため、うまくはまりとてもリストの使い方を理解したようではありました。', null, 'タイピング: 今日も元気よくタイピングできていました！
盛り上がり: ３問目に進んだ時に、質問と答えのリストを作っても自動的にはマッチングしないということを伝えると＞「掛け合わせ？」と先に言ってくれたので、ちゃんとリストとしての使い方を理解できているようです。 次回は質問のプログラミングを作ろうと約束したので、謎謎問題で作成します。'),
  ('522605f9-2019-5bd5-8603-9c4105de770b', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, null, '2024-02-01', '16:30:00', null, '休み（振替対象）', null, null, null),
  ('7782c8ee-0106-5135-a6e1-4680885617db', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-01', '17:30:00', null, '通常 / 表示の有無とメッセージの順序に慣れよう', '前回やったものの続きをやりたそうだったので、その続きをやりました。コスチュームについて、「ゲームスタート」の文字が消えた後に、棒人間のコスチュームを変えたいとのことだったので、前回少し触れたメッセージのやり取りとコスチューム変化について学びました。コスチュームを何個かつなげてもバグっていたので、「何秒待つ」をいれることで、難病表示するか決めることできると伝えたら、喜んでいました。そのあとも、場面転換をしたいとことで、同様にメッセージと表示する隠すで作っていきました。だんだんと先生の補助もいらずにメッセージと表示の関係を自力で作れていてがんばっていました。メッセージととコスチューム関連のコードに絞ってやりましたが、身についた気がします。', 'この後は、アルくんなどを動かしたいと要望があったが、きりがいいので基本操作コースを差し込んでもいいと思います。', 'タイピング: しっかり指を確認しながらやっていました。
盛り上がり: ずっと画面から目を離しませんでした。'),
  ('05eeae58-5d10-5908-8b07-0494bf52a2e5', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-01', '17:30:00', null, '通常 / チーズを探せ', 'まずは遊んでもらったところ簡単すぎるとのことで、自分が作る時にアレンジできるところはないか聞くと、取ると減点されるダミーのチーズを置きたいと言っていました。 そして素材のみから作り始めました。ネズミが一番つくりやすいのでヒントを読みながらやってもらいましたが、意外と苦戦していました。初期座標を決めるのとキーで動かすのがごっちゃになって、キーを押したときにも座標を固定してしまいました。まずは初期座標を決めて、次に上下左右の4つのキーが押されたときに動かすことを確認しました。動かすときに「～歩動かす」を使うことは分かりましたが、向きのことを忘れていたようでした。', '続き', 'タイピング: レッスン開始後すぐに始めていました
盛り上がり: 途中は集中があまりもたず休憩を入れたりしたのに対し、ラストは頑張っていました。'),
  ('b8e4eef2-74fb-53cd-a8d6-63446b8d125d', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-01', '17:30:00', null, '通常 / 機械学習の初歩を学ぶ', '自分のスマホがあるせいか、パスコードやFaceIDを例にした機械学習の話にわりとくいついてきました。 ジャンケンゲーム作成での画像登録も、熱心にやっていました。 も登録した枚数が10程度では認識が甘いこと、一般の例だと、一つの画像につき1000枚～10000枚くらい登録されているらしいという本の記述を見せたら、驚きながらも感心していました。 コード部分もよく覚えていて、こちらの簡単な口頭ヒントからきちんと作成できていました。 ジャンケンゲーム完成後は自由に画像認識を活用した作品作成を指示しましたが、悩んでいるようだったので、適当に教室にあるサボテン、はにわ、えんぴつ、はさみを渡したところ、はさみを危険物として警告させるシステムの作成を始めていました。', null, '盛り上がり: 自分でジャンケンゲームを作成した後に、改めてFaceIDや指紋認証の画像認識はすごい！と感心していました。Scratchが画面上のゲームだけではなく、一般に使われているような技術を実行できることを面白がっていました。'),
  ('76693a61-49ff-5587-b3c4-dd5a85b772d9', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-01', '16:30:00', null, '通常 / 宇宙バトルをできる限り自力で作ろう', '最初に一度は作ったことはある宇宙バトルを自力で作ると約束して作り始めました。少したってから様子をうかがうと、スプライトがただ増やしただけになっていたので、そこで追加するのをやめにしました。マウスで動かしてそのままな感じで止まっていたので、同友動きをするのか引き出しながら作り始めました。途中、砂まみれことがあって時間が少なくて、玉の初期位置を決めるところまでしか進みませんでした。明らかに、スプライトを動かすコードが抜けているので、座標とかを意識し再構築する必要があります。', null, 'タイピング: よく進められていました。
盛り上がり: 外で野球やサッカーなどのダイナミック動きをしたら頭を払おう'),
  ('064cf587-b738-5806-91ab-89a4db6fec29', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-01', '17:30:00', null, '通常 / 機械学習の初歩を学ぶ', '機械学習という言葉は初めて聞いたとのことでしたが、AIは？という質問に、すぐに「ChatGPT」と答えてきて興味を示していました。 まだ自分のスマホを持っていないから、と、パスコードやFaceIDの話ではあまりピンとこないようでしたが、予測変換の話をすると納得できたようでした。 ジャンケンゲーム作成では、なかなか正確な画像認識がされない理由を考えて、自分の背後が動かないように席をかえたり、画面にうつる範囲を調整したりと工夫していました。それでも登録した枚数が10程度では認識が甘いことにおどろいて、一般に使用されているやつだとどのくらい登録しているんだろうと少し引いていました。 コード部分はさすがに理解も早く、さくさく作っていましたが、リストには相変わらず苦手意識があるのか、ちょっと忘れているかも、と言い訳しながら作成していました。（リストの何番目などのブロックを探すのに少し手間取った程度） ジャンケンゲーム完成後は自由に画像認識を活用した作品作成を指示しましたが、悩んでいるようだったので、適当に教室にあるサボテン、はにわ、えんぴつ、はさみを渡したところ、はさみを危険物として警告させるシステムの作成を始めていました。', null, '盛り上がり: 新しい学習内容ということで、由希ちゃんと二人、こちらの話はよく聞いてくれました。 画像認識がすぐに完璧にできるわけではないというところも含めて、Scratchから少し世間一般への視点が意識できたようでした。'),
  ('a0c9a09e-f2b5-57f0-950a-6a50d543b038', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-02-01', '16:30:00', null, '通常 / キャッチゲーム完成', 'ボーナスポイントの仕組みを軽く復習し、最後のクリア画面を作りました。今まで使ったブロックを組み合わせるとできるので、少しヒントを出しつつできるだけ自力で作ってもらいました。前回やった不等号をまた使ったので、使い方にも慣れてきて不等号の向きについても理解していました。「すべてを止める」は初めてだったそうなので、これからも頻出だと伝えて覚えてもらいました。無事完成しました。 残り時間はだるまさんがころんだを進めました。まずは鬼を左に向ける方法が気になったようなのでそこからやりましたが、「回転方法を左右のみ」のブロックを初めて見た(あるいはやったけど忘れた？)そうです。それをつけないとスプライトが逆立ちしてしまうのを見せて、覚えてもらいました。', null, 'タイピング: 集中していました。
盛り上がり: キャッチゲームが完成したとき、とても満足感がある様子でした。'),
  ('f5fde799-3532-5887-a0ba-b5d5c1cc880d', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-02-01', '16:30:00', null, '通常 / かくれんぼゲームをしよう', '先週使ったメッセージを活用して、かくれんぼゲームを作りました。ゲーム内容も把握も細部まで使用がわかっていました。特に迷うことなく進められていましたが、メッセージ名の付け方に難ありで、似たような名前しか付けないので、その癖を少しは直したいところです。作っている最中に、不等号の条件の意味を尋ねてみても、即答できていたので、コードが理解して作れています。残り3分の1程度なので、次回には完成できそうです。', null, 'タイピング: そこそこ進んでいました
盛り上がり: コスチュームも自分好みにキラキラにさせていました。'),
  ('94b53d9f-8177-506a-bdb7-ba8d8536cc7d', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-02-01', '16:30:00', null, '通常 / ゲームの面白さをアップさせる', '時間いっぱいまで、動画を見ながらよく頑張っていました。 画像効果を使って敵が面白く消えるようにするのを楽しんでいて、効果を付け足したりBGMに凝ったりと、自分なりのアレンジを付け加えながら完成させていました。', null, 'タイピング: 得点を効率的にためようと、難しい課題に頑張って挑戦していました。 今日はWindowsPCでキーボードが大文字だったことに少しとまどっていましたが、自分でローマ字表を持ってきて頑張ろうとしていました。
盛り上がり: それなりのコード量だったためか、達成感もあったようで、途中なんども書いたコードを見直して嬉しそうにしていました。'),
  ('34acc16b-8260-532d-bd56-82d1b672471e', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-30', '17:30:00', null, '通常 / オリジナルプラットフォーマーゲーム/アルスパーク作成の続き', '前回まで作成していた内容を一旦完成させようとしていました。とりあえずゴールをつけて完成はさせることが出来ていたようでしたが、今後さらにアレンジを加えていく予定だそうです。そして、新たなゲームの作成に取り掛かっていました。現在ではスロットを置いてカジノ？のようなものを作ろうとしている様子でした。ですので、次回からはそちらのゲームの作成に力を注いでいくようです。', null, '盛り上がり: 新たなアイディアをものにすることが出来たようで、新しいゲームの作成に熱心になっていました。'),
  ('e9fc9eb4-98d5-5171-acbc-192e46f1b86e', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-30', '17:30:00', null, '通常 / ステップアップしたシューティングゲームを作成する', '今日はステップアップして新しいことをやろうと声掛けをすると、俄然のってきてくれました。椅子からずり落ちることもなく、熱心にレッスン時間を過ごせたと思います。 これまでよりも上級のシューティングゲームにチャレンジしたいとのことで、宇宙バトル3のチュートリアルは20分もかからずに終わらせていて物足りなそうにしていました。 このゲームのどこが物足りないかと質問し、自発的に画面のスクロールを学習することになりました。教材の完成例を見て大体のイメージはつかめたようだったので、背景をスプライトにする方法だけ教え、あとは自走させました。 背景スクロールができたあとは、嬉々として敵やビームなどを作り込んでいました。', 'ビームのクローンがきちんと戦闘機に向かうように修正する予定', '盛り上がり: 作成するゲームのレベルが上がったことが実感できたのか、今日は終始楽しそうに、だらけずに頑張っていました。'),
  ('c832d49a-4839-5804-b55e-634c85d04ae4', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-30', '17:30:00', null, '通常 / 『エラーで学ぶScratch』より上級～チャレンジ問題', 'Scratchのコードをデバッグする問題に挑戦していきました。最初の問題に関しては、デバッグ箇所にすぐ気づくことができていたので、スラスラと解き終えることが出来ていました。２問目に関しては、かなり悩んでいたようでセリフが出現しないというエラーが新たに出ているようでした。しかし、時間ギリギリになりながらもしっかりと自分で考え抜いて完成させることが出来ていました。', null, 'タイピング: 正確に打ち込むことができていました。
盛り上がり: セリフのエラーを悩んで解き切っていたので、とても嬉しそうでした。'),
  ('479c9c07-a38d-5b89-ab36-d7728b8dbef4', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-30', '17:30:00', null, '通常 / シューティングゲームに必要な基本的なスキルを確認する', 'シューティングゲームを自分で作れるようになることを目標に、復習から入るか新しいところからやるかを確認したところ、復習からやりたいとのことだったので、宇宙バトル2から入りました。復習範囲ということでスラスラと進めたためか、飴を取りに来る回数もいつもより少なく、集中してできていました。 宇宙バトル3に入ってからも、自分でチュートリアルを見ながら問題なく進めていて、完成してから先生を呼びにくるくらいでした。 説明もきちんと理解していて、問題なく作成できていることを褒めると嬉しそうに、これをアレンジしてみたいと言ってきました。 敵の数を増やしてインベーダーゲームのような見た目にしていましたが、弾が敵にあたったら、の判定をどうするか、というところで時間となりました。', 'たくさんの敵を倒せるシューティングゲームに改良する', '盛り上がり: 難易度がちょうどよかったのか、こちらがたまに様子を見に行くくらいでしっかりと自走できていました。アレンジも楽しそうにしていました。'),
  ('48deae25-8883-59d4-a03b-7a2fe68703aa', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-30', '16:30:00', null, '通常 / 【単元】リスト＿完成版 都道府県と県庁所在地クイズ', '前回行ったリストを使って都道府県と県庁所在地を一致させるクイズを作成していきました。リストを使い、ランダムに問題の表示をさせたり問題が重複しないようにプログラムを作成していきました。問題自体の難易度もそれなりではありましたが、本人はどのようにしてプログラムが動いているのかをしっかりと理解できている様子で作成し終えることが出来ていました。', null, 'タイピング: 的確に素早く打つことが出来ていました。
盛り上がり: 都道府県と県庁所在地をクイズで答えていくことで、自分自身の知識を確かめていました。'),
  ('1659f7a4-da54-5b0b-80cf-95a21db93907', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-30', '16:30:00', null, '通常 / 乱数と条件分岐、演算式の確認', '九九がすらすらと出てくるようになったところのようで、喜んで教材に取り組んでくれました。 どのスプライトにどのようなコードを書くべきかを、完成版をプレイした後で思い出しながら話してもらい、簡単な細分化を意識させてから作成に入りました。 条件分岐やメッセージの送受信、変数の設定などもよく覚えていて、ほとんど迷うことなく作成できていました。 コスチューム番号とコスチュームの数字が一致しているところは、あまりピンとこないようでしたが、実際の動きを見てなんとなく納得したようでした。 数字のコスチューム番号の乱数が1か所全角になっていたようで、実際に表示されているコスチュームと実際の数値が合わずに正誤判定がおかしくなっていたところは、自力では見つけられませんでしたが、バグを探すために変数を表示したりして確認する手順を一生懸命見ていました。', null, 'タイピング: 淡々とやっていました
盛り上がり: これまで学習した内容はだいぶ定着してきているようで、楽しんで作成する余裕がありました。ゲームと授業の切り替えも、かなりスムーズになりました。'),
  ('0491e5b5-5da3-56c5-bb26-85a3ca4efd07', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-30', '17:30:00', null, '通常 / 【Prg】51 どこまでいける？ネコのお散歩ゲーム 『エラーで学ぶScratch』より上級～チャレンジ問題', '前回までで進んでいた箇所からの続きを作成していきました。作成に関しては動画を見ながら順調に完成まで持っていくことが出来ていました。作成が終わった後はScratchのデバッグ問題に挑戦していきました。少し悩んでいる様子でしたが、プログラムの内容を分解して考えていったことで修正することが出来た様子でした。大小関係をしっかりと見極められたようで問題の理解もしっかりとすることが出来ていました。', null, 'タイピング: 素早く打ち込むことが出来ていました。
盛り上がり: デバッグをしっかりと考えて修正できたことで、問題の理解もより深まっていたので良かったと感じていたようです。'),
  ('8dc30438-1f2c-5339-a5ba-a3c8386bc901', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, null, '2024-01-30', null, null, '休み（未対象）', null, null, '時間帯: その他
備考: 下校時刻が遅かったため'),
  ('508e07e5-4d9e-564c-8658-716e1c590bac', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-29', '17:30:00', null, '通常 / prg04 迷路脱出ゲーム 最近あんまり来れていないので基礎の確認＆自力で作る', 'ゲームを結構面白いと感じてくれたようです。本人は動画や見本を見ながら作りたい様子でしたが、今日は自分で取り組んでもらいたかったので、一緒に話しながら何も見ずに作りました。 クリアや失敗のメッセージは完全に自分で考えることができていました。一方で、あるくんの動きに関してはかなり困っている様子で、「～へ行く」「～へ向く」の考え方が少し抜けている印象でした。自分の歩いているときを想像しながら作成してもらいました。左から右に動かす赤いバーは、秒数を変更することで速さを微調整していました。かなりこだわっていました。 こまかいプログラムのブロックについて少し忘れているようですが、プログラム全体を把握する能力が高いなと感じました。次週は壁に当たったときのあるくんの動きを作成していく予定です。', null, 'タイピング: 集中して何度か取り組んでいました。'),
  ('653128f3-0d21-5d15-bd5a-4cbd695fa2a7', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-29', '17:30:00', null, '通常 / クローンかリストを使ってみる。 クローンの場合→まゆねことスパイラル。 リストの場合→クイズ問題', 'ほぼリストをやったことがないとのことだったので、リストの使い方を確認しながらクイズ問題を作ることになりました。 入力されたアンサーとリストの答えを比較するプログラムはとてもよくできていました。問題を出題するときに変数を使うのが少し難しかったようなので、繰り返し単位と変数の使い方を一緒に確認しました。最後は自分で気がつくことができていてとても良かったです。 周りにギャラリーの多いにぎやかなクイズ問題を作ってくれました。今日で完成しました。', null, 'タイピング: 集中して取り組めていました。'),
  ('4885d56e-c281-5519-b04f-47382c7e6830', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-29', '16:30:00', null, '通常 / クローンを使ったキャッチゲーム（前回の続き） 落ちてきたものを消したり、変数を作ったりする。', '「端についたら消える」のブロックでうまくクローンが生成されていなかったので、座標で考えてもらいました。条件分岐と変数が混ざると少し難しいようです。スコアのプログラムはよくできていました。かごの動きも自分で作ることができていましたが、かごに沿ってあるくんを動かすのに苦戦していたので少しヒントを出しました。 次にアレンジとしてスピードアップのプログラムを作ってくれました。クローンの生産速度を秒数の変数を使ってうまくコントロールできていてすごかったです！クリア画面や落ちてくる範囲のコントロールも、変数を使って全て自分で考えてくれました。 今日で完成し、公開しました。とてもよくできています！', null, 'タイピング: 集中して取り組めていました。'),
  ('b8df8d9f-1584-593f-b516-0792c6cff378', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-27', null, null, '通常 / 段階を踏んで作品を完成させる', '前回の課題だった、スプライトを部分的に消していく作品については、現状では難しいということを説明したところ納得してくれました。ただ、今後制作を進めるうえで、お手本がないと僕には難しい、と言っていたので、次回以降に対応する予定です。 ゆうれいからの逃走は、次に何をすればいいのか完全にわかっていて、自分で最後まで作成してしまいました！ その後、オリジナルのレックウザvsアイウエオを作成していて、アイウエオが上下にのみ、かつ、ややランダムに動くというのを作りたがっていたため、射的ゲームを例に座標の乱数指定で動かす方法を試しました。これは気に入ったようで、喜んで作成していました。', null, '時間帯: その他
盛り上がり: ゆうれいからの逃走を一人で作れたのがとても自信になったようで、お父さんにも真っ先に報告していました。 家で作成しているゲームの手直しと、教室での課題をよくがんばっていました。'),
  ('2079a570-a1a0-5aec-a288-e733ac19a88e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-27', null, null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！', '前回までで完成していた部分から次のステージに進む部分に関してのデバッグから始めていきました。結果として名前で判定していた部分の数字を全角で打ち込んでいたことが原因でしたので、コードの組み合わせとしては間違っている箇所はありませんでした。湊太君も同じような内容で次のステージへ行けなかったようでしたので2人同時に解決することが出来ました。本人としても、完成した作品のアレンジをしていく際に打ち間違いに関してはかなり気をつかてアレンジしていました。', null, '時間帯: その他
タイピング: かなり速く打つことが出来ていました。
盛り上がり: アレンジの内容で独自のゲームルールを追加したりなどかなり楽しんでいる様子でした。'),
  ('8b05c17e-0ed0-595b-812f-33ac60f39a92', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-27', null, null, '通常 / 座標や向きなどの確認をしながらピンポンゲームの作成', '前回、にじいろピンポンを覚えているのでピンポンゲームはすぐにできそうと言っていたのですが、実際に作成となると、わからないところがあるのを知られるのが気になったようで、一人じゃ作れないからと引き気味になっていました。 一緒に確認しながら作っていこうと誘うことで、やる気になってくれました。 最初に完成版をプレイさせたところ、自分なりに細分化して作りやすいところから始めたがり、アルスタジオに準備したステップごとのプログラムは勧めてもあまり見たがらず、自分のやり方で進めていました。細分化された個々のコードはほぼ合っているのですが、パドルでボールを跳ね返すところが難しかったようで、かなりてこずっていました。ボールをだ円形のスイカにしたせいもあるのか、跳ね返る動作がなかなか思うようにいかずに最後の0.5秒待つブロックを外したがり、そのための不具合を面白がっていました。', 'スコアの入り方がおかしいときがあるバグを修正', '時間帯: その他
タイピング: 授業前に頑張って済ませていました
盛り上がり: 作成自体は盛り上がっていました。乱数や演算式のところでは、丁寧にやすのりくんに教えたりもしていました。'),
  ('aff9e389-1b7e-5b46-8955-cb1a96e9d91b', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-27', null, null, '通常 / デバッグステージ8のリストあり 前回は見本のコードをうつして作成をしたので、今日は自分で少しでも考えることを目的に', '前回作ったプログラムでは、ボールが台に触れるとブロックへワープしてしまう仕様になっていたので修正しました。本人はあまり違和感に気づけていなかったので残念です。 リストはほぼ扱ったことがなかったようなので、使い方の説明をしました。こちらが再現してほしいことを見本を含めて説明しましたが、理解するのが難しかったようです。話しながら論理をつめていくと、プログラムすることができました。乱数と「〇番目」の考え方も詳しく説明しました。 リストをあまり使ったことがないようだったので、今後クイズなどを作成しても良いかなと思います。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('d19ab702-91e3-58d3-a604-1a1325ed3fb2', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-27', null, null, '通常 / 【Prg】31 風船わりゲームを作ろう！ 前回学習したクローンを軽く思い出してから作成', '前回一緒に作ったスパイラルを使ってクローンの使い方を復習しました。大枠は覚えてくれていた様子です。その後、風船わりゲームを動画を見ながら取り組んでもらいました。途中、コウモリのサイズが小さくなってしまうなど問題があったそうです。ネットワークの不調で動画が止まってしまったりしましたが、最後まで終えられたようです。集中して丁寧に作れていたので良かったです。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('478ea41a-3875-5661-99cc-db577a30a480', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-27', null, null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！', 'ボールが移動する際の慣性のついた動きがどのようにして動いているのかがイマイチ理解できていないようでした。動画を見ながら作成してましたが、途中まで独自にコードを組んでいたので動画を見ながらの作成はあまり進めることができなかったようです。とりあえずボールの移動に関する変数の部分は完成させることができていたので、次回以降でボールの慣性の動きからの部分を完成していければ良いと思います。', null, '時間帯: その他
タイピング: 素早く鬱ことができていました。
盛り上がり: 慣性の動きについて疑問のようでしたが、原理については理解することができていたようなので次回作っていきたいと言っていました。'),
  ('27fe1255-5d51-53eb-ad6a-2570912a595c', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-27', null, null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！ 次のステージに進めないバグを解消 終わったら【Prg】23 走り幅とびゲームを作ろうで、～ではないまで待つの復習', '最初からもう諦めモードでしたが、一緒に取り組んでみました。こちらからプログラムについて質問するとかなり的確に答えられていました。中身の大枠については理解できていた様子です。問題のありそうな箇所を絞り込むこともできていました。ひとりでやっていると途中でやめてしまいましたが、話しながら進めるときちんと取り組めていました。 最終的にはコスチューム名の書き方がよくなかったことが原因でした。最後にアレンジとしてクリア画面を表示してもらいました。', null, '時間帯: その他
タイピング: かなりやる気がなさそうでしたが、取り組んでもらいました。'),
  ('b308ce32-6fa2-5c2b-b211-c0d4883d75f4', '7076a58d-dc61-5064-9f4d-9241fde86003', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-27', null, null, '振替 / プログラミングを楽しむ', 'ロボット授業の後に遊んでいたScratchの電車ゲームをやりたがったので、この時間はロボットの振替といって授業時間であることを説明し、今日の課題が終わったらゲームタイムにするという提案をしたところ、俄然やる気になっていました。 ゆうれいからの逃走の完成版を見せた後、1ステップごとに教材を見せ、さっきとどこが変わったか、何をすればよいと思うかと問いかけながら進めました。プログラミングのスキルがあるわけではないため、口頭でのやりとりになりましたが、次に何をすればよいのかというのは概ね把握できているようでした。 ひでとしくんが口頭で述べることを聞いて、該当するブロックを説明して作成するというやり方でしたが、楽しそうにできていました。 変数についても最初はぴんとこないようでしたが、ゲームをやっていて変わっていく数の話の中で、得点やヒットポイント、取ったアイテムの数などを例に出すとイメージがわいたようでした。 40分くらいでゲームが完成し、とても満足したようでした。 残り時間はスイカゲームなどをして楽しんでいました。', null, '時間帯: その他
盛り上がり: ゲームを作るということに、最初はしり込みしていましたが、すぐに楽しそうにのめり込んでいました。'),
  ('c828b218-27e9-5a8f-9400-2d76b8d5a97b', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-27', '16:30:00', null, '通常 / 【Prg】47 シュンカンきおく順番当て演算＿変数＿定義を使って場合分け', 'リストを使ってタッチした順番の判定を利用したゲームを作成していました。動画を見ながら作成していきましたが、順調に作っていき授業内に完成させることができていました。コードの内容に関しても質問したところ、しっかりと理解できているようで解説することができていました。前回まで挑戦していた内容より少し簡単なこともあってか、気持ち的にも楽に作ることができていたようです。', null, '盛り上がり: 止まることなく最後まで作り上げることができていたので、出来には満足している様子でした。'),
  ('b0f0fc4f-e83d-5bd9-88d7-f12b8d65ca2c', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-25', '17:30:00', null, '通常 / ゆうれいから逃走', '前に作ってから間が空いたので、一度プレイして全体像を思い出してもらってから続きをやりました。細分化されたものを見せるとやはりイメージしやすいようでした。10点取ったらゲームクリアにするため、「～まで待つ」と等式の使い方を覚えてもらいました。背景なども軽くアレンジして完成しました。', null, 'タイピング: またレッスンが始まる前にやっていました
盛り上がり: 少し疲れて眠い様子でしたが、アメや水などのリフレッシュを入れるとなんとか頑張れたようでした。'),
  ('dc1455a0-888c-5e92-9eb8-bcea8c461c30', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-26', '18:40:00', null, '通常 / 検定問題４級−１', '自分から検定問題がやりたいと選択。最初に検定のやり方を説明、何問かは一緒に解く際のコツをみながらやってみました。 馬の動きからは、自分で作成。ほぼ問題通りにコードを書くことができていました。', '来週は検定問題②', 'タイピング: タイピング自体はとても慣れた様子。長文も目指せるか？
盛り上がり: アレンジ問題の際に、思い浮かばないかな？と思ったものの今まで学んできた変数を使ってタイマーを作ったり、動きを複雑にして捕まりにくくしたりと自分なりにアレンジを楽しんでいました。バグに繋がってしまったものの、ゲームを楽しくしようとする考え方は力がとてもついてきているという実感がありました'),
  ('ccf09059-8fc6-511a-9dbb-b746370857f4', '7ac1ed6d-2eb1-56f7-aa62-e5d1ce95a957', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-26', '17:30:00', null, '振替 / １級の過去問を前回実施。本人に聞いてみて今日は何をやりたいか？を選んでもらう方が良いかも？ ①自分の作品作成 ③アルスパーク＞PRG猫のお散歩ゲーム（定義、かつ） https://www.youtube.com/watch?v=ix3OzRHW0RE', '手首の回転限界に合わせて銃の回転限界を作るのに苦心していました。プログラムを見ると条件分岐と変数が多用されていました。マウスで回転させるのとプログラムで回転を制限するのは相反する動作なので、プログラムの優先順位づけが大切なことを伝えました。 紙に自分で計算したり図を描いたりして分析していてとても良かったです！', null, 'タイピング: 集中して取り組めていました。'),
  ('8ad10f1c-0e33-5b97-a143-68a7274e6727', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-26', '17:30:00', null, '通常 / PRG サッカーゲーム https://app.arstudio.fun/projects/28923/editor 今までは当たる判定などを細かくしていたが、今度は球などの動きが滑らかになるのを実践。 当たる判定よりも動き自体が難しくなるので、ケイトくんにその辺りを最初に説明すること', 'RPGサッカーゲームで遊んでもらい、少し作成してもらったのですがあまり気が乗らない様子だったので、リストの使い方の演習も兼ねてはるくんと同じ問題に挑戦してもらいました。リストを使うのはほぼ初めてだったようですが、箱と紙の教材のお陰で考え方がだいぶ理解できたようです。とくに〇番目という考え方は新鮮だったようです。最後にアレンジとしてクリア画面を変数を使って作成してくれました！時間まで頑張っていてよかったです！', null, 'タイピング: 本人がどうしてもやりたくないとのことでスキップしました。来週また必ず。'),
  ('c2d7c292-5ffc-55b4-810d-97a2c0e69eb8', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-26', '17:30:00', null, '通常 / リストの続き～ 言葉の理解が難しい子なので、紙をちぎってわかりやすいように教材を準備 音階とリスト https://app.arstudio.fun/contents/52348 の問題を１音だけでもできあがるように持っていきたい', 'ゲームで遊んでしまい、始めるまでにいつもより少し時間がかかりました。準備された教材（箱と紙）でリストの考え方を説明し、プログラムするように促しましたがかなりやりたくない様子でした。音をならすときに乱数をもってこれたのが良かったです。最後はブロックの色を変えたり、ボールの色を変えたりしてアレンジしてもらいました。けいとくんと話ながら取り組めていて楽しそうでした。 最後に聞いたところ、リストは「だいっっきらい」とのことです。', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 自分が作って公開した作品を見せてもらいました！'),
  ('83a7457d-15f7-5574-b492-9e91a05da0e4', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-26', '16:30:00', null, '通常 / 先週の続き PRG星とりゲーム https://youtu.be/x-jvMTccKFI', '丁寧に動画を見て進められていてよかったです。途中、音を選ぶのにかなり時間がかかっていました。半角カタカナを知らなかったようなので、使い方を説明しました。変数の使い方も大丈夫そうです。ただ、クローンした先の固有の変数として使われているのか、そうでないのかの違いをまだ理解できていないようなので、もう少し余裕ができたら共有したいです。 もう少しですがまだ完成していません。', null, 'タイピング: 集中して取り組めていました。'),
  ('62873b4f-9eea-5be7-8801-3c9e169ede82', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-26', '17:30:00', null, '通常 / 基本操作コース６＞メッセージを使うことに慣れる&文字を打ち込むことに慣れる', 'メッセージの概念を説明する時に、最初にこんにちはを２人同時に書かせてみて、被ってしまうことが本当にこの紙芝居の中でいいのか？ということから導入。順番に行って欲しいのになんでだろう？＞メッセージを使うと順番にすることができることを確認しました。 同時に「送る人」「受け取る人」が必ずいて成り立つことも理解したようでした。', '次回は背景が変わるメッセージを送る〜音を録音まで', 'タイピング: 真ん中のキーの列はタイピングに慣れてきた様子。3文字までの単語系のタイピングもだんだん上手くなってきました。
盛り上がり: メッセージは何回も使ってもいいのか！そうするとアニメっぽくできるんだね！と話していたのが印象的でした。'),
  ('15eda314-99e7-5a9f-9260-01447549a90f', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-26', '17:30:00', null, '通常 / 多角形と円を描いてみる', '前回三角形を終わっているので、今日は多角形から。低学年のため角度と繰り返すを使うことで図形を書くことができるということを説明。 角度に関しては正直分かってはいないと思いますが、図形を書くために度と繰り返しのコードが必要なのだなということはわかってくれたようです。 最後にオリンピックの図形をかいてもらうことをチャレンジ。 スタート地点を工夫することに苦労していたようでしたが、なんとか５つ丸を書くことができました。', '角度を使う系のゲームでもいいかも', 'タイピング: まだ長文は難しいみたいで、ミスタイプをしていた感じ。短文は大丈夫そうなのでここから練習していけばいいかなと思います。
盛り上がり: チャレンジ問題ができた時にとても嬉しそうにしていたのが印象的でした。'),
  ('cf0b1cb4-7414-5c9f-8894-67545965fd87', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-26', '16:30:00', null, '通常 / 前回のPRG星取りゲームの続き、動いていない部分があったので自分で見返しどこが違ったのかを確認する（バグの原因は何か？）を突き止めてみる', '見本と見返して、どの部分が違ったのかを確認してもらうことにしました。 見返したことにより、スタートのボタンが１っこしかないという考え方だとどの動きが動いたらいいのかコンピューターがわからなくなる＝バグになるという理解したようでした。 また少しだけ時間があったので、むらっちのバレーボールゲームを少しだけ紹介。 ボールがどういう動きと同じなのかを少し時間をかけて考えてもらいました。 最初はジャンプと同じだということに気が付かなかったようでしたが、今まで自分で作ってきた作品とおなじだということがわかると、とても嬉しそうにしていました。', 'おやすみ中の宿題として見本をみてもいいから「バレーボールゲーム」を作成してもらうことにしました。', 'タイピング: 上位２％の中に入るほどの腕前！
盛り上がり: 言葉で理解することにとても長けていると思います、コードを読み解く力がありそこからの分析を自分なりにしていたのがとても良かったと思います。'),
  ('2c20fdcf-6c0d-520e-af9a-035ecd7c07b1', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-25', '16:30:00', null, '通常 / モンスターハントの続き', 'スコア以外の変数の使い方を復習しました。変数名にもあった「フラグ」という言葉は知らなかったようなので、上げたり下げたりできる旗の機能だと伝えました。乱数で座標を決めるブロックが入れ子になったりもしていましたが、きちんと構造や意味を理解していました。動画の19:22まで進めました。', '続き', 'タイピング: 今日はタイピングをたくさんやりたいといってやっていました
盛り上がり: 多少難しいところも集中してできていました'),
  ('c9fe3bcc-57c2-542b-8033-4edc5cebef0b', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-25', '17:30:00', null, '通常 / 的あてゲーム', '承太郎君とともに的あてゲームを作りました。ゆきちゃんの方が途中でだれずにずっと集中していました。途中わからない所は教えあっていたりしていてよかったです。同じペースで進めていたので、残り4分の1程度です。', '21分以降', 'タイピング: 速いです'),
  ('2d85a44f-ffbd-5eb5-9217-d7b68e13250f', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-25', '17:30:00', null, '通常 / 的あてゲームを作る', 'このゲームはクローンとリストまで組み合わせたものになるので、ためになると思います。動画を見ながらでしたが、あまり遠近感を出したゲームを作っていなかったので、新鮮でした。音が英名で見つからない問題ありましたが、集中してできていました。残りは、4分の1程度で次には終わりそうです。', '21分以降', 'タイピング: 義理お得にならない'),
  ('cb75c892-211a-548a-9cd3-f6d45dba9464', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-25', '16:30:00', null, '通常 / キャッチゲームの続き', 'まずは、「～キーが押されたとき」で作っていた左右移動を「もし～キーが押されたなら」に変えてもらいました。それでスムーズに動くようになったのを確かめてもらいました。 それが終わると手順に戻り、キャッチするところから順に動きを見せながら進めました。「～に触れたら」や「変数を1ずつ変える」などのブロックは今までにもやったので、使うべき場面でしっかり使えていました。ただ、ブロックを置く場所はたまに間違えていたので、「この動きはいつする？」などと問いかけると直せていました。 ボーナスポイントをつけている途中で終わりました。', '続き', 'タイピング: ノーミスに近い精度でできていました
盛り上がり: 今見えているお手本の動きがどうやったら再現できるのか、集中して考えられていました。'),
  ('046824c3-2a41-5598-8d5f-1e219da3f46d', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-25', '16:30:00', null, '通常 / 状況を整理して、アルくんの冒険作り続けよう', '前回鳥散らかっていたので、作ったところを復習がてら質問して答えるようにしました。以外にも、どこまで作っていたか敵の判定まで答えられていて覚えていました。一通りゴールまで作ると、アレンジとして段差を作ることをしたので、2の方へ進みました。そこで、また敵の動きをコードを作ると、また複製し始めました。るいくんは、とりあえずいっぱい複製して、画面上で位置をバラバラにして、スタートを押すと、一か所にまとまって、思い通りにならず、やる気もそこで落ちる癖があります。その後、コードをいじりたくないとなって結局複製したものを全部消すパターンが起こりやすいです。なので、やる気が落ちた時にどうフォローすればいまいち不安定です。', null, 'タイピング: 河童が仲間になるところまで進みました'),
  ('ad1a5056-e9d7-57b3-a8f5-0f5048cb474a', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-25', '16:30:00', null, '通常 / ゲームの仕様を考えて作成する', '作成途中のゲームをプレイしてもらって、このあとゲームとしての面白さや精度を上げるには何をすればよいのか、この後どんなことを作り込んでいきたいのかを考えて口に出してもらいました。 話していくうちにやりたいことが見えてきたようで、時間をくださいと言って一人で黙々と作成を始めていました。 ステージの背景を変えた時に、スプライトの出方が変わってしまったようで、リストアを繰り返したりと混乱した様子が見られましたが、自分で各スプライトのコードを見直して、最終的には納得のいくところから作りなおすことができていました。 ジャンプだけでなく姿勢を低くして敵をよけるなどのコスチュームの使い方がオリジナリティがあって面白く、そこを指摘すると嬉しそうにしていました。 変数や座標の使い方にもだいぶ慣れてきたようで、質問もなく作成できていました。', 'もう少し作り込みたいとのことでした。', 'タイピング: 普通に特訓をした後、なぜか、時間をかけるタイピングの記録にチャレンジしていました
盛り上がり: 自分のアイディアでゲームを面白くしていく、というのが楽しかったようで、熱心に取り組んでいました。'),
  ('c84ccb9f-23eb-547d-804c-35d140682398', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-25', '16:30:00', null, '通常 / メッセージを使ったストーリーを作ろう', '今までゲーム系ばかりだったので、メッセージを使ったアニメーションを作りました。あいまいな使い方だったので、しっかりと学ばせました。教材のアニメーション作りは、不向きだと感じたので、オリジナルに作る気でした。会話の内容はなりっ立っているか別にして、口語のやり取りがしっかりと組めていたので良かったです。ただ、お話づくりだけと感じてしまうと少し飽きが感じていたので、動きのやり取りは少なく、ゲーム作りの方がむいているきがします。だから、次はメッセージが主体のゲームを作った方がいいと思います。', null, 'タイピング: 進んでできてました
盛り上がり: 名前付けがかなり個性的でした。'),
  ('f8c49549-1b0e-5f9b-8ff9-94122badbe9c', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-23', '17:30:00', null, '通常 / バグに注意してゲームを完成させる', '今日は1時間前に来室して、エアコンの下、夢中でゲームをしていたせいか、授業開始時には顔も紅潮していて疲れていたようでした。 前回の続きが作れるのは嬉しそうでしたが、動画を見るのがだるそうだったので、途中から完成例を見せて自分で付け加えるコードを考えるやり方に切り替えました。 ヒントとして完成例のコードを見たがってはいましたが、全部をじっくり見てうつすのではなく、パッと見て参考にして、自分で考えながら作成しようとすることはできていました。 今日は少し甘えも出たのか、やたらとうなったり声を出したりしていましたが、話を合わせながら相手をしていると、自分でバグを見つけて直したり、付け加えなければいけないコードを作成したりすることはできていました。', null, '盛り上がり: なんだかんだ言いながらもゲームを完成させることができて、満足げにしていました。'),
  ('6684acf2-bcac-5e36-9a7f-7792174a9412', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-23', '17:30:00', null, '通常 / 定義の使い方や論理演算式の使い方の確認', '今日の目的の確認をした後は、動画を見て淡々と進めていました。 集中力もよく続いて、時間いっぱい使って完成させていました。 定義を使うところで確認のために作業を見ていましたが、迷いなく作成できていて、はるちゃん自身も「悩むところはとくにない」とのことでした。', '完成した作品を見直す時間がなかったので、次回一緒に見直しする約束をしています', 'タイピング: よく打てていました
盛り上がり: 動画を1.5倍で流しながら、ものすごい集中力で一気に完成させていました。'),
  ('502d096b-0882-5b53-9322-11c17428bd21', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-23', null, null, '通常 / JavaScriptの学習を進める', '今日は自分から、久しぶりにJavaScriptをやってみたいと申し出てきました。 久しぶりすぎてログインアカウントを忘れていたようで、こちらの記録を見返してログインしました。 動画や資料の出し方は自分で覚えていて、教科書と動画を並行して見ながら進めていました。 4章の内容自体で、特に困った点等はなかったようでした。45分ほどで最後まで終えて、その後はScratchの電車ゲーム系をいじっていました。', null, '時間帯: その他
タイピング: 遅刻してきたため省略
盛り上がり: 久しぶりのJavaScriptで、それなりに楽しめたようです。 最初のログインで手間取った時も、先生二人とよくしゃべっていました。'),
  ('e2189ec7-6129-5a4d-bf6f-b29a8ae2fe0c', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-23', '17:30:00', null, '通常 / オリジナルプラットフォーマーゲーム', '２つ目のステージや、1つ目のステージから二つ目のステージへの移動についてのプログラムを作っていました。キャラクターのダメージ判定やリセットに付いては上手くいっていたようですが、ステージの転換に伴ってのオブジェクトの変更がうまくいっていないようでした。ですので、続きを作成していく際にはこの箇所から修正していく必要が出てくるのではないかと感じています。', null, 'タイピング: ほとんどミスをすることなく正確に打ち込むことができていました。
盛り上がり: 1部ではあるがやりたいことをしっかりと落とし込むことができていたようなので、続きからもしっかりと組み込んでいこうとしているようだ。'),
  ('08d80248-50d0-58ff-95fa-0494efe2c255', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-23', '16:30:00', null, '通常 / 問題の多いクイズ屋さん', 'リストの基本的な使い方についてレッスンのエキスパートで学んでいました。リストをどのようにして扱うのか、どのようにして増やしたり消したりを使っていくのかを理解することができていました。自分自身でクイズの内容を調べたりしていて様々なカスタムを施していました。本人の中でのやりたいことやしたいことを明確にして表現することができていました。', null, 'タイピング: 素早く打ち込むことができていました。
盛り上がり: 作りたいクイズの問題をプログラム内にしっかりと落とし込むことができていたので、喜んでいました。'),
  ('4b35ee18-3382-5792-9ab4-63922c342cf2', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-22', '17:30:00', null, '通常 / デバックステージに挑戦。', '1~4はほぼ自力で取り組めていて良かったです。まだ座標の＋－に自信がなかったようです。花びらのプログラムも8枚ぴったりで止められていたのでよかったです。5ではオレンジの個数に気が付けていたのですが、プログラムに落とし込むのが難しかったです。「クローンの生産数」と言い換えると気が付くことができていました。6は自分で解決できていました！時間のカウント方法は少し困っていました。7、8はこちらからかなり助言をしました。7は地面の考え方、8では問題の見つけ方と座標の考え方を共有しました。アレンジとして花びらの色を1枚ずつ変えてもらいました。', null, 'タイピング: 集中して取り組めていました！何回も挑戦できていて良かったです。'),
  ('f1741517-6924-552e-86b3-0727c53e5ade', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-22', '17:30:00', null, '通常 / デバックステージに挑戦。', '1は変えたい点に気が付きにくかったようです。1~4は問題なくプログラムを変えられていました。5ではすこし苦戦していました。みかんの量をクローンの数につなげるのが難しかったようですが、気づくとすぐにプログラムできていました。6では直したい部分を明瞭にするようにこちらが問いかけると、しっかりできていました。7、8はうまくプログラムをなおせていました。とくに8は座標と演算の組み合わせに注目できていました。最後のアレンジとして音を追加してもらいました。色ごとに違う音がなるようにも工夫してくれました！', null, 'タイピング: 98点純2級で悔しそうでした。'),
  ('df50b053-2b89-5dd7-9b0e-5f91fa648a86', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-22', '16:30:00', null, '通常 / まゆげねこ、スパイラルでクローンの使い方を確認。クリアできればキャッチゲームをクローンを使って考えてみる。 デバッグでクローンの考え方ができているとのことなので、その使いどころを一緒に話してあげれればGOOD', 'まゆげねこでクローンの基本的な使い方を確認しました。本体を動かしてクローンをスタンプのようにして使っていたので、本体は生産するだけでクローンを動かす考え方を共有しました。クローンする度に色を変えるプログラムもうまくできていました。 スパイラルは最初に動かし方を一緒に確認した後、全て自分でプログラムできていました。スライダーを使うのが気に入ったようで、大きさや色にも変数を当ててオリジナル作品を作って楽しんでいました。 キャッチゲームでは、落とすクローンのプログラムはよくできていましたが、本体の座標の設定の仕方に苦戦していました。基本の部分は良くできたので、あとは落ちてきたものを消す、変数をつけるなどしていきたいです。キャッチゲームをやっていないようなので...', 'クローンを使ったキャッチゲームの続き', 'タイピング: 集中してとりくめていました！'),
  ('cd4586fa-a2b8-5d93-8aef-5c6ed7a8de3f', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-22', '17:30:00', null, '通常 / 基本操作コース04', '今回の授業で作成していった内容に関しては、本人が説明する前に次に必要なコードを当てることができたりとかなり余裕な感じで作っていくことができました。本人的にも内容を理解しながら作ることができていたようです。音の処理において、終わるまで鳴らすというコードの性質をイマイチわかっていなかったようなので、その箇所においては丁寧に説明していきました。', null, 'タイピング: ミスも少なく素早くクリアすることができていました。
盛り上がり: サクサクと終わらせることができて、内容もしっかりと理解することができていたようなので満足していたようでした。'),
  ('c32725e6-3f1f-575c-8fc5-e83ff29c3704', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2024-01-15', '17:30:00', null, '休み（未対象） / 体調不良とのこと', null, null, null),
  ('63ca8acc-11de-5f9b-bf49-bff517b032c0', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-20', null, null, '通常 / 脱出ゲーム完成', 'まずは動画通り最後まで終わらせました。「または」の入れ子やコスチュームの名前での条件設定など、ポイントになりそうなところは意味を確かめました。 その後、次のステージに行けないというバグが見つかったので修正に入りました。メッセージの流れなども考えて怪しい場所を絞り込んだりもしていたのですが、最後まで原因を見つけるには至りませんでした。', null, '時間帯: その他
タイピング: あおしくんと同じものを初めてやりました。楽しいけど難しいと言っていました。
盛り上がり: あおしくんと積極的に協力しながらやっていました。'),
  ('fed60c6f-5115-5525-ae3e-7bb469a7431f', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-20', null, null, '通常 / 脱出ゲーム完成', '最後まで一通り動画に沿って作り、その中で矢印の動きも作りました。そのとき、「または」を何個も入れ子にしたものと「幽霊の効果」ブロックは初めて見たようなので意味を確認しました。 そのうえで、次のステージに進めないというバグがあったので原因を探りました。いろいろなスプライトを見てお手本のコードと照らし合わせたのですが、どこが間違っているのかわからなかったようです。それ以外の部分は完成していそうです。', null, '時間帯: その他
タイピング: 楽しくやっていました。
盛り上がり: スクラッチのゲームで遊んでしまうときもありましたが、集中してやっている時間も多かったです。'),
  ('0714a39c-f6b1-5fb8-967a-8400aba758cf', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-20', null, null, '通常 / プラットフォーマーゲームをもう少し作り込みたいならそちらを、完成でよいということであれば 【Prg】34 ビルのすきまを抜けようゲームを作ろう！', 'プラットフォーマゲームを見せてもらいました。まだ完成していない様子でしたが、本人が次に移りたいとのことだったので、ビルのすき間を抜けようゲームに移りました。 とぶ部分の変数の使い方が面白いかなと思ったのですが、はるくん的には面白くなかったようです。途中鳥が勝手にゲームオーバーになってしまうバグがありました。動いているプログラムから逆算して条件を見て、動かない理由を考えてもらいました。該当のプログラムは見つけられたようでしたが、条件を確認して理由を探すのはまだ慣れていないようです。他に詰まった点はなく、時間中に最後まで取り組むことができました。 考えるのが苦手な印象です。', null, '時間帯: その他
タイピング: あまりやりたくない様子でしたが取り組めました。'),
  ('75eeaed9-63ab-597d-8cef-1cfb63d215ba', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-20', null, null, '通常 / 基本的なスキルの確認', '冬休みに自宅で作成していた作品の質問がある！と張り切っていたので対応しました。 スプライトを部分的に消していきたいという要望は保留にしましたが、スプライトが消し終わった後のセリフやコスチューム変更は、メッセージを使ってできるということを学習し、メッセージを受け取った後のコードはスラスラと作成して満足そうにしていました。 ゆうれいからの逃走は、最初のスプライトと背景を決める際に、背景を大量にコピー＆ペーストをしてPCが固まるのを繰り返していました。なぜ背景画像をコピーして並べる必要があるか、本人が説明しきれなかったので、とりあえず教室では、背景はなるべくそのまま使うようにということで合意しました。 矢印キーでスプライトを上下左右に動かすのは得意なようで、何も参考にせずに、あっという間に作成して得意そうにしていました。', '②基本操作コース_04ゆうれいから逃走02から', '時間帯: その他
タイピング: 英文字もしっかり読んで、よく打てています
盛り上がり: 今日はやりたいことがあり、新しい教材にも興味を持てたためか、離席も少なめで、こちらの話も聞こうとする姿勢が見られました。 質問もすべて解決はできませんでしたが、対応しようとしていることはわかったようで、素直に教材の方に切り替えることもできていました。'),
  ('c3ff451c-5700-5312-acf0-5d2410c15e41', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-20', null, null, '通常 / コード探求【ではないまで待つ】 レース順位ゲーム または、次に進みたそうなら コード探求【もし●●なら】 だるまさんがころんだ ・細分化に誘導 ・スモールステップで', '遊んでもらって、どのようなゲームなのかのあくんに説明してもらいました。「まけ」と「クリア」に区別をつけるために、鬼のプログラムから作成することにしました。 コスチュームの変更の仕方や、表示非表示、コスチュームを変えるときの「見せるための時間」などを思い出してもらいました。負けやクリアのプログラムを作るには難しかったようなので、条件分岐から一緒に考えました。最後に作ったプログラムを見返して「もし」を2回作っているのを確認しました。考えるのはできているけど、どこから手を動かしたらよいのか分からない印象です。 かなり難しい内容でしたが、1時間しっかり集中できていました。ゲームの核の部分はできているので、本人の希望によってはアレンジもありかなと思います。', null, '時間帯: その他
タイピング: 2回ほど挑戦していました！すごい！'),
  ('75efd79d-b071-5f1f-8bd2-51ada9cdbaf5', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-20', null, null, '通常 / くじ引き デバッグステージ1～8、8上級の代わりにどれかをアレンジ', 'ステージ1~6では、自分が改善したい点をしっかり見つけて、それっぽいプログラムの場所を探すことができていました。その中でも1~4は自力で解決できていました。ステージ5のクローンはほぼ知らなかったようなので解説しました。ステージ6では入力も頑張っていました！ 7、8はかなり苦戦していました。条件分野が曖昧なようです。とくにステージ8では不等号を使いますが、考え方をよく知らない様子だったので詳しく説明しました。お花アレンジもリクエストに応えてくれてうまくプログラムできていました！', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('4405719b-530b-52b7-9427-ee6a192c625b', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-20', null, null, '通常 / prg30番台前半から選んで', 'prg30番台ではかなりクローンが使われていますが、使い方をほぼ知らない様子だったのでよい機会だったのでクローンをやることにしました。 まゆねこで親分と子分の説明をしました。クローンを作って表示させることはできましたが、コスチュームを変えるのは少し難しかったようです。次にスパイラルに挑戦してもらいました。考え方が難しかったようなので、角度と動きに分けて説明しました。スライダーを使った変数も活用できました。 最後にアレンジとしてコスチュームを切り替えて色が変わるプログラムを作ってくれました！なんとなくクローンも分かったようです。', null, '時間帯: その他
タイピング: 集中して取り組めていました！'),
  ('be4bbc1d-c5b6-54f7-9c45-1838d672f8bd', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-20', null, null, '通常 / バグの修正', 'バグを直さないといけないことはすぐに思い出したのですが自力では見つからなかったので、検定の答え合わせの要領で一緒に確認しました。また、だいきくんは「ゴーストが動かないんだからゴーストのコードだけ見ればいいはず」と言っていましたが、「他のスプライトをメッセージをたくさんやりとりしているからそれが送られてなかった場合は？」と聞くと納得して他のスプライトも調べました。最終的にリストや変数の名前の間違いが2,3個見つかって直しましたが、ゴーストが一瞬しか表示されないことは変わりませんでした。', null, '時間帯: その他
盛り上がり: やらないといけないことは理解してるけど、これだけ直らないとちょっといやになると愚痴を言っていました...'),
  ('5f144a6a-91de-5c65-9a9c-47f2bf54ada4', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-20', null, null, '通常 / コード探求、条件分岐の理解', '幽霊のクローンの数を増やして「ゲームの難易度が上がった！」と喜んでいたので、この教材の目的を話して軌道修正しました。 虫が左右の端に触れたら跳ね返る、と作成して「何か違う？」となっていたので、完成品の虫がどういう動きをしているのかをよく見せて、まずは「めいろにあたったら向きを変える」というコードを作成することができました。 めいろの角にあたった時に、虫がその場で回転し続けてしまうバグを発見することはできましたが、その後どうしていいのかは思いつけなかったようなので、ネズミの動きを参考にするというヒントを出しました。 めいろの特定の位置にくると、虫が同じところを回るだけになってしまうという問題点も自分で見つけることができました。解決のためには「もし～なら～でなければ」を使うということまでは想像がついたようですが、「でなければがついたブロックは使ったことがないのでわからない」と言い切っていたので、知らないことを一緒にやって学ぶために教室にきていると説明してなだめたら、話を聞く姿勢になりました。乱数は好きなので、乱数を使って動きを変えるということは面白かったようでした。 ゲームオーバーとゲームクリアのスプライトを作成して、ねずみが虫にあたったらゲームオーバーというコードをゲームオーバースプライトに作成しようとしていたので、メッセージの使い方を確認しました。', 'にじいろピンポンをよく覚えているとのことなので、基本操作コースのピンポンで復習を', '時間帯: その他
タイピング: 家でもずいぶん頑張っているようで、ローマ字で単語を打つことにも慣れてきているようでした
盛り上がり: 3回目にしてゲームが完成できたのは、とても嬉しそうでした。 やりたかったアレンジも一通りできて、満足していました。'),
  ('4511cf33-8440-5bc3-9944-479f989a0454', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-20', null, null, '通常 / 細分化からの作成に慣れる', 'デバッグステージがよくできていたので、動画を見ずにわかるところまで作成していくことを目標に設定しました。 ゲームをプレイして、どのようなゲームなのか、どのスプライトがどのような動きをしているのか、口頭で説明することができたので、ボールの動きやステージのコード、鍵のコードなど、これまでの知識でできるところを自力で進めてもらいました。 加速を変数を使って制御するところも、一緒に完成形のコードを読みながら作成することができていました。', '続きから完成を目指して', '時間帯: その他
タイピング: よくできていました
盛り上がり: 完成形をプレイしたときは、難しそうという顔もしていましたが、話をしながら細分化をすると、意外とこれまでの知識でできるということが理解できたのか、一人でどんどん自走することができていました。'),
  ('66adba4e-7638-508d-b79c-390b0999a357', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-20', null, null, '通常 / くじびきの問題', '1～8のほとんどをスムーズに進めていきました。3の花を描く問題では、360÷45=8という計算に基づいて繰り返しの回数を8回にできていて、角度や繰り返しに関する理解は十分でした。8の上級はさすがに少し難しかったようで少し考えていましたが、リストを使うというヒントを出すと、音の番号をリストに入れて乱数で取り出していました。リストの活用法をまた一つ習得できたと思います。', null, '時間帯: その他
盛り上がり: 淡々と問題を解き進めていました'),
  ('a7f015f9-f763-579e-bd85-530611e1b566', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-19', '17:30:00', null, '通常 / 図形の問題', 'ペンツールを使って様々な図形を描いたり、同時に描いたりしていきました。本人としては、角度をどのようにして何回繰り返せば思った通りの図形が描けるのかを試行錯誤していました。幸いに、デバッグ問題の３問目でペンツールを使った問題が出ていたのでその内容を参考に作っていました。最終的には三角を3つ使ってトライフォース（ゼルダのやつ）を作りました。位置調整などに苦労していたようでしたが、授業内に完成させることができていました。', null, 'タイピング: 集中して取り組むことができていました。
盛り上がり: トライフォースを作るのにかなり時間を使っていたので少し焦っていましたが、時間内に完成させることができていたので、満足している様子でした。'),
  ('6c2f5530-c766-5605-b011-eea07b26b123', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-19', '18:40:00', null, '通常 / 【Prg】04 迷路脱出ゲームを行う', '動画を見ながら作成していましたが、つまづくことなくスラスラと作成していくことができていました。動画の内容を30分ほどで作成し終えることができていたので、残りの時間は作品のアレンジをしていきました。ステージをカラフルにしていたので、色指定で止まるプログラムで作られていたので「または」を使い対応していました。結果として、本人も満足のいくものが完成していたようでした。', null, 'タイピング: 間違わないように気をつけてタイピングをしていました。
盛り上がり: アレンジで自分の入れたい内容をしっかりトイレ切ることができていたのでとても満足していました。'),
  ('51598b78-c62b-5b7b-9597-c28b7974c25b', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-19', '17:30:00', null, '振替 / デバック問題初級からできるところまで', '１〜６問目までを行いました。概ねヒントを渡せば「わかった〜」と言い、試行錯誤しながら答えを導き出していました。発想力はとてもよく問題もスラスラとけていたので、今後は少しずつ難しい問題にもチャレンジしても良いかなと思いました', null, 'タイピング: 最初はやはりタイピングの仕方を忘れていたようで、タイピングパネルを乱暴に扱っていましたが慣れていくごとに平常心を取り戻したかんじではありました。
盛り上がり: 頭の回転はとても早い方なので、とても楽しく問題を解いていました！'),
  ('c2bd2514-b85e-5138-ad04-30b9803b95e6', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-19', '17:30:00', null, '通常 / 先週わからなかったリストを使って音階を作る https://app.arstudio.fun/contents/52881', '最初ビデオを見ていたのですが、言葉の理解ができなかったようだったので途中から私が模型をよういしながら基礎的な部分をりかいしてもらいました。 実際のものがあると、理解はできるようなので何回か質問し「１〜のものはどれ？」などリストの拾い方を一旦復習。 その上で質問&答えのリストを作って何番目の〜のコードを使うことにトライ。 何回もやることで慣れていくのだと思いますが、まだまだ難しいと言っていたので、これから少しずつ模型を用意しながらリストの問題を多めにやっていくといいかなと思いました。', '来週は音を鳴らすにはリストの使い方をどのように扱うか、です。', 'タイピング: スムーズにおわっていました
盛り上がり: 模型を用意した部分はとてもハキハキと答えてくれていたので概ねリストってこんなもんかな？みたいな感覚は掴んでくれたように思います。'),
  ('edf1cce4-411f-50c0-ad82-5c915bb58915', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-19', '17:30:00', null, '通常 / 当たり判定を工夫したシューティングゲーム', '敵キャラクターの判定を別に作成し、中心部に弾がヒットした際にダメージを受けるという判定にしていきました。内容の理解自体はすんなりとすることができており、それ以外の内容に関しては本人のレベルでは余裕な内容だったのでサクサクと作っていくことができていました。', null, 'タイピング: 集中して取り組むことができていました。
盛り上がり: キャラクターの判定をしっかりと見極めて作ることができていたので、満足していました。'),
  ('30b8df5d-557d-5381-a654-fd86c36534f7', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-19', '16:30:00', null, '通常 / リストの動画が見れたらリストを一回勉強＞先週やったチャレンジ問題の音がでる～というのを一緒にやってみるのがいいかも もちろん分からないと思うのでそこを一緒に解くというフェーズにいってもいいかな https://app.arstudio.fun/contents/52881', '今日は一度ビデオを見ながらリストの基本を見てもらいました。少し難しい内容だったので理解できているかは不安がありましたが、概ね理解はできていたようです、 箱の概念がどうしても難しいので、今度の授業では音を鳴らす部分までやり切って欲しいと伝えて、実践は来週となりました。', '音階をつけるという部分を全部やる', 'タイピング: いつも通り楽しくできていたようです！
盛り上がり: 新しい単元になるので不安だったようではありますが、ビデオ学習するのは好きなようなので真剣にビデオを見ていました。'),
  ('020174db-7091-576e-ad16-e2d2fe2cd099', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-19', '16:30:00', null, '通常 / 地球を隕石からまもれ', '動画を見ながら作成していきました。難易度はそこまで高くなかったのでつまづくことなく作り続けていましたが、量が多いので途中までという結果となっていました。次回も続けて作成していけば恐らく完成まで持っていけると思います。', null, 'タイピング: スラスラと打つことができていました。
盛り上がり: 本人としては、イマイチ進めることができなかったので不満そうでしたが、スラスラと作れていたので苦しそうではありませんでした。
備考: 10:40~'),
  ('967ea3de-c13c-593f-adc8-4259da5e2c6a', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-19', '16:30:00', null, '通常 / Prg星とりゲーム', '今回は比較的簡単なものを作成していきました。本人的にも難易度が自身の実力では十分クリアすることが容易なものでしたので、スラスラと作成することができていました。1からしっかりと作成していったので、少し時間はかかっていましたが本人は余裕でクリアすることができていました。', null, 'タイピング: 単語ごとで速度にばらつきが起きることもなく、正答率に関してもそれなりに高い数字を出していました。
盛り上がり: 作成しているものがサクサクとできていくので、作っていて楽しかった様子でした。'),
  ('5921f8bc-e769-59f1-9cb6-722196bbb2e2', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-19', '16:30:00', null, '通常 / 先週のゲームではなく、Prg】49 ジャンプゲーム＿演算＿リスト機能で記録を残すhttps://www.youtube.com/watch?v=o0rbOkuCCtY でリストの復習にしました', '今日はリストの復習をしようか！と話したところ先週のゲームは簡単だったという話だったのでリストの動画はみずにPRG からリストを使っているゲームに限定して復習することにしました。本人はゲームを試してみたときは難しいと言っていたのですが（ゲームで遊ぶこと自体も）作ってみたい！ということだったので、作成を開始してもらいました。 動画を見ている最中はとても熱心にしていて、楽しそうでした！今日は26：23のところまでなので次回はそこから。', null, 'タイピング: 4000円以上お得に打てたそうです！
盛り上がり: どこか見落としたかも！と言ってきちんとコードが書けたかどうか確認をしていました。昔よりはるかにバグを作らないようにしようという努力が見られるのと、ゲーム自体のバグっぽくないのか？という新たに問題提起する余裕まで見えていることにとても嬉しく思いました。'),
  ('7d78cb84-cc93-58fb-ba14-cbc46681f65a', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-15', '16:30:00', null, '振替 / くじびきの問題(2回目)', '周りの子がまだくじびきをやっているので、デバッグステージとは別の問題でくじびきをもう一度やってもらうことにしました。主に「座標を～にする/～ずつ変える」といった座標の動きを扱い、どのブロックを使えばいいのかは比較的すぐわかっていました。ただ、「ずっと」の繰り返しの中身を何にするのかがピンと来ていないようだったので、旗を押した後からの流れを一緒に確認して、どの動きをずっと繰り返すのか問いかけました。また等速ジャンプの問題にも挑戦して、ヒントとしてジャンプの動きをスローモーションで見せると、上に行ったあと下に行くということを理解しました。', null, '盛り上がり: またくじを引けると聞いてやる気が出ていました。難しくても嫌にならずに「こうじゃないかな？」と色々試したりしていて、よく集中できていたと思います。'),
  ('fd3f59f7-afea-581b-adf6-43f366b243d7', 'dde71f8d-9a45-59f5-8dec-651fc1c86850', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-18', '17:30:00', null, '通常 / 教室に慣れる', 'レッスン前にたまたま開いたデバッグステージ2がうまく動かないのを不思議がっていたので、間違いを見つけて直すためのプログラムだということを説明したところ、とてもやりたがったので、座標の説明をしながらチャレンジしてみました。完全に理解できたわけではなさそうですが、座標に+－があること、それによって動く向きが変わることはなんとなくわかったようで、y座標のブロックを直したら、同じようにx座標のブロックを直すことができました。 今日は作りたい作品の計画をバッチリとたてて来室したようだったので、とりあえず希望に沿う形で進めました。新しいブロックを使用するたびに、今日覚えたこととして再確認をしたため、同様なコードの2回目以降は少しですが自走することもできていました。 表示と隠す、ずっと、○○に触れたら、メッセージ、音楽を鳴らす、スクリプトを止める、のコードと、コスチュームの編集や新しいスプライトの作成などを学習しました。', '今は「これを作りたい！」ということで頭がいっぱいなので、とりあえず作品の完成まで補助をしつつ、基本操作コースの該当箇所を絡めてスキルの習得とチェックを並行して進めたいと思います。作品を作る過程でスキル習得の重要性を理解させ、基本操作コースの流れに持っていけるようにしていく予定です。', 'タイピング: 最初だけ、タイピングはできない、としり込みしていましたが、ゲームをしながら覚えてみない？と持ち掛けたら、素直にハマっていました。F、G、H、Jのキーを左右の人差し指で打つことを覚えて、タイピング道場を楽しそうに進めていました。 使用したWindowsパソコン（♡マークのもの）のキーボード表記が大文字だったこともよかったのかもしれません。
盛り上がり: タイピングもプログラミングも、終始ワクワクといった感じで集中して取り組んでいました。お母さんにも得意げに、今日できるようになったことを報告していました。'),
  ('6fcd87f4-980f-587f-b904-a119500c9f86', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-18', '17:30:00', null, '通常 / デバッククイズ', '5くらいまで順調に解けていました。６の時間を刻むことに以外にも悩んでいました。７，８についても5分程度で解けていました。上級チャレンジについては、最初はノーヒントで挑んでもらいましたが、乱数は触れても全く手つかずだったので、リストとのヒントを与えました。そこで、教えたら、番目で乱数が使えると自らできたのよかったです。', null, '盛り上がり: 福引楽しみにしていたが、すべて参加賞でした'),
  ('1ab532b3-53af-551c-b31d-162e82f28a71', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-18', '16:30:00', null, '通常 / キャッチゲーム', 'アルスタジオ上の細分化されたものを見せながら進めると動きがイメージしやすいようでした。今回は座標の内容が多いので、x座標とy座標の違い、「～にする」と「～ずつ変える」の違いなどを復習しながら進めました。初めてスクラッチで不等式をやったようですが、学校の算数では習ったようで意味を覚えていました。一方で、負の数については慣れていないようで、-をつけ忘れたりなどしていたので、とりあえずは「y座標が+なら上の方、-なら下の方」というイメージを持ってもらいました。キャッチするボウルを左右に動かすのは今までにもやったことだったので、自分の力で作って自信を持っていました。', null, 'タイピング: 集中していました
盛り上がり: 少しずつゲームができていくのが楽しそうでした'),
  ('4c9aa5b3-9520-5f81-ab66-0b2c5a0ccb2f', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-18', '16:30:00', null, '通常 / アルくんの冒険を作る', '最初遊んでもらったときは、とても気に入ったらしく、動きについて質問しても、細具体的に聞けば、ある程度は答えてくれました。動画見ながら作っていても、動画終わった時に目をつけられていなければ、フリーに作ってしまい、動きがおかしくなってしまうことがありました。そこは、ちょくちょく見ながらフォローしたら、そこそこ進んでくれました。コードを作る際、「動きだから青」とコードの種類別に迷わず選べるようになったことがよかったと思います。コードの大枠の見分けは意外と身についていない子がいたりするので良かったです。そして、最後は完成まで行けました。', null, 'タイピング: 今日は長くたっぷりできました。'),
  ('346beb61-38ad-55a8-8e2e-1240eaae26ef', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-18', '17:30:00', null, '通常 / prg30～40番台から選ばせて →話した結果クローンに焦点を当てて練習することにしました。', 'リストとクローンの話を聞いたところ、クローンの使い方がイマイチよくわかっていないとのことだったので、①まゆねこ②DKアートスパイラル③デバックステージ5を使ってクローンの練習をしました。 ①でクローンの考え方、見た目の変え方、本体とクローンの関連性について説明しました。作品もうまく作れていました。 ②は①を踏まえてまずは変数なしでプログラムを作ってもらいました。完全に自力でできていました。変数をスライダーで値を変える方法も説明しました。 ③ではクローンの部分はとてもよくできていました。クローンの生産スピードについて説明しました。ゲームクリアの画面を表示させるときに「ずっと」「もし」でやるとうまくいかなかったので、「まで待つ」を使って書き換える方法を説明しました。クリア条件の不等号の扱いはまだ苦手なようです。', null, 'タイピング: とてもお得でした！すごい！'),
  ('36ab5c8d-0c8b-51ca-aba6-99be8abae588', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-18', '16:30:00', null, '通常 / プラットフォーマゲームの基礎スキル習得 続き ブロックの上に乗ったらジャンプのスクリプトを止めているので、そのあと下まで降りられるようにコードを修正していく予定', '自分が作ったジャンプのプログラムの原理を忘れかけていたようなので、もう一度説明しました。地面にいるときの動作とそうでないときの動作で分ける考え方を説明しました。自分で作りたいものがあって手は動かせるけど、その前にうまく分析ができていない様子でした。 ジャンプではなく、「上に行く」と「下に行く」に分けて考えてもらい、それが起こる条件といつまで続くのかを考えてもらいました。最後に「もし～」を使ったプログラムを「もし～でなければ～」に統合したのですが、本人はあまりしっくり来ていないようです。慣れが必要かな。', null, 'タイピング: 集中して取り組めていました。'),
  ('0f89a59f-0819-5ae6-a66e-ea5d6c0998ef', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-18', '16:30:00', null, '通常 / 【Prg】12 モンスター・ハントゲームを作ろう！ 変数の違った使い方を知る 座標の上級へ', '最初に注目してほしい変数の使い方を説明しました。いつも使っているスコアと比較すると少しわかりやすかったです。（変数の加算され方の違いを説明すると「なるほどぉ」と言っていました）乱数と座標の組み合わせも考え方は理解できているようだったので、迷路チーズの話をして思い出してもらいました。途中、音選びにかなり時間をかけていました。楽しそうでよかったです。動画は9:35まで進みました。', null, 'タイピング: あまりやりたくない様子でしたが、やっていました。'),
  ('a646c77d-d6ce-562f-b8c9-e963d86e729f', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-18', '16:30:00', null, '通常 / ジャンプゲームを復習しよう', '半年前に1度やっていましたが、復習のために再度行いました。ジャンプという動きの作り方を完全に身についていなくて、初めてやるような上がり続けてしまう、１つの繰り返しの中に上がり下がりを作り動かないなどのミスが目立ちました。教えながら、なんかやったことがある気がするようなリアクションもなかったので、すっぽり抜けていた感じでした。ジャンプ以外のスコア付けや敵の動きなどは、ほかにも共通して作っていたのかそこはスムーズに作れていました。だから、ジャンプ体系の動きを身に着けるために、ある程度はほかのジャンプ系のゲーム短い周期で作った方がいいと思います。', null, 'タイピング: よく進んでいました
盛り上がり: 背景がにぎやかなものになっていました。'),
  ('cb0fda54-db09-511f-9cba-c84d4c7adf02', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-18', '17:30:00', null, '振替 / くじびきの問題', '最初の方はスラスラ進みました。途中でクローンやリストなど初めて見るスキルが登場して、そのたびに難しそうと言っていましたが、そのスキルについて軽く説明するとすぐに理解して問題も解けました。ステージ7には少し苦戦しましたが、着地しているときにだけ飛べるとヒントを出すと、条件分岐や色の判定を理解して修正できました。ステージ8は、ゲームオーバーのメッセージが間違って送られていることを手掛かりにバグの箇所を特定していて、論理的な考えができていました。', null, '盛り上がり: 最初はレッスンを始めることを渋っていましたが、問題が解けたらくじびきができることを伝えるとやる気を持って始めてくれました。'),
  ('b54b8bb5-e878-51c2-b6e9-fe692a5a893e', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2024-01-18', '17:30:00', null, '休み（未対象）', null, null, null),
  ('3dfd6e4e-2616-5164-8b8c-e4470dbdc06a', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-16', '17:30:00', null, '通常 / くじ引き問題', '今回のデバッグでは、８問目の上級問題であるリストを使って音を追加する内容にかなり苦戦している様子でした。リストへの追加方法をイマイチ理解していなかったようで、その箇所がわかったところすんなりと解くことができていました。本人としては、その箇所が難しかっただけらしく他の問題に関してはこれといって悩むことなく完成まで持って行くことができていました。', null, '盛り上がり: 最後の問題をどのようにして解くのかがわかった際には、自分の引っ掛かっていた部分が解決してスッキリとしていました。'),
  ('af749cc0-b69e-527b-8d26-9369146ff505', '7d01236e-620e-5177-a6f4-af325a582aae', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-16', '17:30:00', null, '通常 / くじ引き問題でデバッグに取り組む', 'ステージ5あたりから、毎回挙手してヘルプを求めていましたが、おかしいところはどこか、そこをどうしたいのか、そのためにはどういうコードを探して直せばいいのか、と細かく発問していくと、その先は自分でできていました。全体の中からポイントを見つけるのがやや不慣れな様子でしたが、一つ一つのコードや条件分岐の仕組み、座標などはきちんと覚えていて、道筋をつけるのに手助けをすると、6の条件分岐や8の座標の論理式なども自力で直すことができていました。', null, '盛り上がり: 8上級の代わりの課題において、8のブロックをゾンビに変え、インベーダーゲームのような見た目にして、楽しそうにアレンジをしていました。'),
  ('de386007-7bd7-50f1-a9ba-d32d546f03d3', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-16', '16:30:00', null, '通常 / くじ引き問題', '今回のデバッグ作業では、自分で直す箇所をしっかりと見つけることができていました。苦戦していた箇所は７問目の色を変えて足場に立たせるデバッグでしたが、本人としてはこの方法に気づけていなかったことが悔しかったようです。その他のデバッグに関しては、これといって止まるようなこともなくスラスラとデバッグをすることができていました。', null, 'タイピング: 比較的早く打つことができていました。今回はデバッグをやるために早めに切り上げていました。
盛り上がり: １箇所つまづいてしまいましたが、全体的には順調に修正することができていたので満足していました。'),
  ('2b9811bb-57db-565c-b0ff-65a68818c523', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-16', '17:30:00', null, '通常 / くじ引き問題でデバッグに取り組む', '文章ではなく実際のプログラムを見て考えるのは得意なようで、とてもスムーズに進めていました。1問完成したら先生を呼ぶのもとても積極的で、普段の倍はよくしゃべっていました。 7については「おかしいところはどこか」「そのためにはどういう動きを制御しているコードを探せばよいか」という問いかけが必要でしたが、その後は自分で解決できていました。 8上級の代わりにどれかをアレンジするという課題を出したところ、3の図形を描くコードを工夫して、とても面白い作品に仕上げていました。', null, '盛り上がり: こういう問題形式は楽しかったようで、今日はとにかくよく話して説明してくれました。 お迎えのお父さんにも、くじで当てた景品を嬉しそうに見せて、来週からもがんばると言って帰っていきました。'),
  ('1a12d2cc-0329-5633-b9f2-09d556c81638', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-16', null, null, '通常 / くじ引き問題でデバッグに取り組む', '久しぶりのこちらからの課題でしたが、素直に始めてくれました。 さすがに問題は簡単だったようで、3～8まであっという間でしたが、8上級で音階を入れるのと同時に、ボールの動きがすぐに水平近くになってしまうのを解決しようと、時間をかけて熱心に取り組んでいました。 検定で同じような問題があったので、それを応用してみた、と、久しぶりによく話しながら見せてくれたので、せっかくだからと公開を勧めたところ、ちょっと嬉しそうに操作していました。', null, '時間帯: その他
盛り上がり: 8上級問題が納得のいくように仕上がったようで、自分が工夫したところなども久しぶりによくしゃべって説明してくれました。 パイナップルが当たったのも、まんざらでもない感じでした。'),
  ('27461188-1b35-5893-90f7-6413872204fd', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-16', '17:30:00', null, '通常 / くじ引き問題', 'デバッグ内容に関しては、スラスラと解き進めることができていました。しかし、問題６の正解と不正解の出力が逆になっている箇所に関してはかなり悩んでいる様子でした。本人としても、その間違いよりも先にタイマーが進んでいない間違いの方を先にデバッグしていたので、本人としてはデバッグ箇所がどこなのかがわからないような状態でした。ですが、少しづつヒントを出しながら解いて行ったところ、自力で解くことができていました。他の問題に関しては特につまづくこともなく解き切ることができていました。', null, '盛り上がり: つまづいてしまった原因を自分の中で見つけ出せていたようなので、対策をしっかりとしていました。'),
  ('e4282a4c-02ca-5771-8c1b-0551434b911e', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-16', '16:30:00', null, '通常 / くじ引き問題でデバッグに取り組む', 'ゲームをしておかしいところを指摘するのも、コードを見てどこを直せばよいのか見つけるのも、とてもスムーズにできていました。これまでやってきたことが、頭の中でだいぶつながってきたようで、ステージ6の条件分岐の間違いなども、リストの説明を受けずに自分でパッと見つけて直せていました。 ステージ7、8あたりも「ここがおかしい」とピンポイントでブロックを指定することができていました。 8の上級はさすがに難しいので、1つアレンジで1問にカウントしました。', null, 'タイピング: 拗音の練習をしていました
盛り上がり: 難易度がちょうどよかったのか、終始楽しそうに取り組めていました。
備考: 久しぶりにお母さんがお迎えにいらしてました。今日の様子を話すと、家では話さないからわからなくて、と喜んでいらっしゃいました。'),
  ('84fbf815-ae32-5a2f-9bc5-f7dc965c4d7f', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2024-01-16', '17:30:00', null, '通常 / くじ引き問題', 'デバッグ作業の修正箇所を見つける速度も早く、修正も迅速に行うことができていました。最後の問題であるリストを付け加える箇所においても素早く対処することができ、この時間の中では最も早く終えることができていました。本人としても問題の難易度はそれほど高くなかったようで、デバッグを終えてから「これでいいの？」といった感じで少し疑問に思っていたようでした。', null, '盛り上がり: この時間帯で最も早く終えることができていたので、自分が1番だということを喜んでいました。'),
  ('b398f074-b800-5cf8-beec-f2d97c101cf8', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-15', '16:30:00', null, '振替 / くじびきの問題', '1～4は簡単に終わりました。5では本題のクローンの量を調整した後、キャラクターの動きも直したいと言って、歩くスピードを変えたり向きを変えたりというアレンジをしていました。6ではリストを初めて見たそうですが、軽く説明を入れるとそこまで苦戦せずにできました。一番苦戦したのは7で、どこを直したらいいのか見当がつかないという感じでした。着地しているかどうか判定すればいいとヒントを出すと試行錯誤ののちにひらめいて解けました。時間を少しオーバーしてしまったのですが、最後まで行きたいと粘って8までやりきりました。', null, 'タイピング: スムーズに打てるようになってきています
盛り上がり: 今までに習ったことをたくさん使いたいという気持ちがあり、モチベーションは以前より上がってきていると思います'),
  ('5fcf3078-907c-587d-a4e2-17179676ee94', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-15', '16:30:00', null, '通常 / デバックステージ1から', '1はゲーム内容が理解しきれず、どこを修正するのかが分からないようでした。2~3、4は自分で改善場所を見つけてプログラムすることができました。説明してもらいましたが論理的でとても良かったです。5も自分で完全に修正できてました。クローンの考え方もよくできています。6も自分で修正箇所をみつけて取り組めていました。7はすこし苦戦しました。条件分岐が重なると少し苦手なようです。8は問題箇所を見つけられていたので、一緒に確認して改善しました。音楽のプログラムもヒントを出すと自力で最後までできていました。 いろいろ試してたまたまうまくいくこともあるようですが、プログラムを自分で確認できていてとても良いです！', null, 'タイピング: 集中して取り組めていました。
盛り上がり: 参加賞をすぐにかばんにしまっていました。'),
  ('0a55fd56-7b52-52ff-9414-b13f9ded1faa', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, null, '2024-01-15', '17:30:00', null, '休み（未対象）', null, null, null),
  ('8d20bc32-c4aa-56e0-9780-7819711fd666', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-13', null, null, '通常 / くじびきの問題', 'お兄さんのゆうとくんに引けを取らないペースで進めていき、最後はステージ8の途中までできました。ステージ3では完成形の花がイメージできなかったようですが、その形だけ見せると、繰り返しの回数が足りないことをすぐに見抜きました。ステージ7では、ジャンプができないということはすぐ分かったようですが自分で新しくジャンプのコードを作っていたので、元からあるからこれを修正しようと伝えるとできました。', null, '時間帯: その他
タイピング: 楽しそうでした
盛り上がり: ゲームのバグを見つけたときによく面白がっていました'),
  ('71dd766f-ad34-5072-9e4f-307117dcdeb1', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-13', null, null, '通常 / くじびきの問題', 'ゲームを遊ぶとすぐにバグっているところを指摘して修正に入っていました。ステージ2では、「～キーを押したとき」だと動きが遅いからと言って、「ずっと」と「もし～」を使って直していました。全体的にペースが速めで、問題が解けた後に軽くアレンジしたりもしつつステージ8まで終わりました。一番苦戦していたのが7でしたが、着地しているかどうか判定するという考え方を教えるとできました。', null, '時間帯: その他
タイピング: 日本語の単語を打つのにも手慣れてきました
盛り上がり: たくさん景品を当ててびっくりしていました。'),
  ('2b4bab5b-2dfb-53cd-9f20-0768b4ff8313', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-13', null, null, '通常 / くじびきの問題', '基礎を確認するという意味でステージ1から飛ばさずにやりましたが、1～4あたりまではあまり止まらずにできました。5ではクローンを落とす部分の長いコードに釣られて迷っていましたが、問題はどこにあるのか一緒に整理すると解けました。6ではリストを初めて見たようなので意味を説明し、使っているリストを表示しながら挙動を確認すると、納得してデバッグできました。7ではけっこう悩んでいたので、「着地しているかどうかでジャンプできるか判定している」とヒントを出すとできました。色に触れる判定の使い方を学べたと思います。8の途中で時間が終わってしまいました。', null, '時間帯: その他
盛り上がり: 真剣に考えていました'),
  ('c4fa3920-089b-579e-bb31-72e7bd541d5b', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-13', null, null, '振替 / くじびきの問題', '3,4はすぐに終わらせて簡単だと言っていました。5では過去に作ったバックパックを使ってみかんの軌道を複雑にしていましたが、一応5でやるべきことは達成しました。6では、「～と聞く」と「答え」を初めて見たそうなので意味を説明しましたが飲み込みが速く、さくっと終わらせていました。7と8も難しいわりにはそこまで苦戦せず、8の上級チャレンジもできました。リストを使うのがめんどくさいと言っていましたが使いこなせているようです。', null, '時間帯: その他
タイピング: 集中していました
盛り上がり: もっとレベルの高いことをやりたいという気持ちがあふれていました'),
  ('00b1bf9c-537c-541d-8d03-7eb6e1920bb6', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-13', null, null, '振替 / デバッグステージの解説、ステージ1～', '1、2はとてもスムーズに取り組めました。3は繰り返しの単位にあまりピンと来なかったようです。最後はあちこちの数字を変えていろんな花を作っていました。4はあまりピンと来なかったようですが、キーボードの話をすると気づいてくれました。5、6はプログラムをよくみて取り組むことができていました。7、8ではなかなか手が進まなかったようなので、条件分岐に注意するように伝えました。楽しく取り組めたようです。', null, '時間帯: その他
タイピング: 集中して取り組めていました。'),
  ('8859cc99-9b32-55bb-b2d1-c8e6adb6eae2', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-13', null, null, '通常 / くじ引き問題でデバッグに取り組む', '4でいきなり難しく考え始めて、しばらく悩んでいましたが、5分ほどたって、「もしかして…」と正解を出し、拍子抜けしたのか頭を抱えていました。 それ以降は要求されるレベルがわかったのか、スムーズに解いていました。 6のタイピング問題で、かかった時間が緑の旗が押されたときから始まってしまい、説明の間もカウントが進むのが気になると言って、そちらも丁寧に直していました。 8上級の正解を見せたら、「リストと乱数を使う以外考えられない、正解を真似した感じにしかできない！」と妙にツッコミを入れていましたが、最終的には全問解ききっていました。', null, '時間帯: その他
盛り上がり: 久しぶりに時間いっぱい、ひたすらScratchに熱中していました。 久しぶりすぎて忘れてる！と言いつつも、楽しそうにできていたと思います。'),
  ('445528d4-8e79-5fd0-8068-c8118ac82e75', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-13', null, null, '通常 / くじ引き問題でデバッグに取り組む', 'どこがおかしいか、それを解決するためにはどこをどのように直せばよいのか、といった道筋を見つけるための発問は必要でしたが、口頭できちんと答えることもできていて、一度も離席せずに8問がんばって解いていました。 6のタイピング問題なども、リストと答えを使った演算式の意味を説明したら、あとは自分で条件分岐の問題に気づいて直すこともできました。 5のクローン作成のところだけ、しばらく悩んでいて演算式を入れようとしたりしていたので、繰り返しの処理について何度か説明をしました。 8のy座標については、わりとすぐに気づくことができました。', null, '時間帯: その他
盛り上がり: 途中で飽きたりダレたりすることもなく、頑張って8問解ききっていました。 5等の商品がディズニーものだったので、スティッチの折り紙を嬉しそうに選んでいました。'),
  ('53e74e1e-28bf-5d60-a3a0-653c4cc9dca8', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-13', null, null, '通常 / くじ引き問題でデバッグに取り組む', 'これまでの学習内容が定着したのか、的確にデバッグを進めることができていました。 リストや「答え」ブロックの意味など、習っていない部分は補足説明をしましたが、それだけで着目点に気付くことができていて、スムーズにすべての問題を終えていました。 ステージ8の上級問題では、変数を使って2種類の音を使い分けることができていました。', null, '時間帯: その他
盛り上がり: 問題をクリアすることで自信もついたのか、終始落ち着いた感じで、完成したときに先生を呼ぶことにも積極性が見られました。'),
  ('0f941daf-6bcb-5ba3-9742-ff21449304d3', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-13', null, null, '通常 / くじ引き問題でデバッグに取り組む', '6あたりから、見たことのないリストのブロックのが増えたりしてとまどっていましたが、リストの問題ではなく条件分岐の問題として注目させたら問題に気づくことができていました。 自分で正解にたどりついていても、先生に確認してから直し始めたいというような、やや慎重すぎる傾向が見られました。 問題自体は楽しそうに取り組めていました。', null, '時間帯: その他
盛り上がり: ゲームにツッコミを入れたりして、楽しそうにできていました。デバッグができたゲームも丁寧にプレイして確認をしていました。 3等を当てて賞品選びに迷っていて、お父さんと弟君にカップラーメンセットを選んでもらい、嬉しそうに帰りました。'),
  ('781c22cd-f554-5f20-a4e5-760b67ee4601', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, null, '2024-01-13', null, null, '休み（未対象）', null, null, '時間帯: その他'),
  ('96c68be4-29fc-5ca2-9a9f-eb1052a2bdf5', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-12', '18:40:00', null, '通常 / デバッククイズ', 'バグ直し絵t最初は、直す方向性が違く、何かを付け足すことがあり、その場のコードを作り直すことだと教えました。そこからは、一つ一つ試しながら確認して、残り5分で最終問題にたどり着けました。最後の問題は、まだ習っていない不等号の問題が含まれていたんので、とても難しく理解が追い付いていませんでした。だけて、何かしらは試そうとする気力は良かったです。', null, 'タイピング: ひと指ずつ確認してやっていました。'),
  ('d79057ee-c862-5469-aba9-350fda766661', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-12', '17:30:00', null, '通常 / デバッククイズ', 'デバッククイズをやりましたが、どこがおかしいかはわかるが、コードで把握することが時間かかっていました。まだ、習っていないクローンや不等号に対しては、なおさらどうしたらよいかわからず苦戦していました。不等号に関しては、その場で向きと意味を教えたら、関連付けて最後の問題を解くことができました。', null, 'タイピング: スムーズにできていました。'),
  ('1d0b1445-d1cd-5a1f-849f-5a9be225f370', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-12', '17:30:00', null, '通常 / デバッククイズ', 'デバッククイズをやりましたが、どの問題に対してもバグを正確に読み取ることができました。それで、最終問題まで止まることなくできました。チャレンジ問題に対しては、難しく途中であきらめてしまいました。', null, 'タイピング: よくできていました。
盛り上がり: 3等が欲しかったが、全部参加賞でした。'),
  ('89f876af-42be-5bf2-808a-3ddcbf49970a', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2024-01-12', '16:30:00', null, '通常 / 福引大会', 'レベルてきに４～くらいでしたが、最初から6から難しい順にやっていきました。特にやっていいる最中は悩むことなく、30分ちょっとで全問解き終わりました。チャレンジ問題については、リストをまだ習っていなかったので、苦戦していました。「と」でつなげてなど思考を巡らせていましたが途中で終わってしまいました。でも、チャレンジしたので、3回分引きました。', null, 'タイピング: 何回もやっていました。
盛り上がり: 3等が当たりました'),
  ('dc653e84-9221-5416-b420-769fe3e1a391', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-12', '17:30:00', null, '通常 / デバック問題１〜いけるところまで', '今日はデバック問題を行いましたが、ゆづきくんにとって初めての挑戦。最初はどうなるかな〜と思いましたが、最初の問題から初めてなんと８問目まで解くことができました。 いくつか、単元的には習っていない部分であったため、ヒントをもちろんもらいながらではありましたが、プログラミング脳としてはとても成長していると思いました。', null, 'タイピング: タイピングはゆづきくんは苦手みたいですが入校の時よりははるかに打てる文字数が増えてきているので、今後も頑張ってほしいものです。
盛り上がり: くじを引いても参加賞しか当たらなくて悔しがってはいましたが、途中けいとくんと相談しながら問題を解いてみたりして、彼にとってはとても有意義な時間になったようでした。'),
  ('22ad9672-3516-5d79-9838-bba943232e78', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-12', '17:30:00', null, '通常 / デバック問題１〜いけるところまで', 'デバック問題自体がそうちゃんにとっては、少し難しいかなと思ったのですが最初の問題が解けた後からすこしずつ意味がわかってきた様子で６問も解くことができました！ もちろん全てを自分の頭で解いていたわけではないですが、説明を聞くことで理解をした部分もあるし、コードをちゃんと読むことで「これは間違いだな」ということに気が付く機会が増えたように思いました！', null, 'タイピング: くじ引きが気になってどうしても集中力にかけてしまっていましたが、真ん中の列のキーはなんとかタイピングの練習をできたようでした
盛り上がり: くじが５等あたって嬉しそうでしたが、自分が好きなものではなかったのでちょっと悔しがっていましたが、問題を解くこと自体にそうちゃんにとっては意味があったみたいだったのでとてもよかったです。'),
  ('f09e1847-5719-5638-9583-1cc8405b2cd7', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2024-01-12', '16:30:00', null, '通常 / デバック問題中級３〜いけるところまで', '結局問題１〜問題７までチャレンジすることができました。 年明けだから覚えていない〜と言っていましたが、ヒントがあることで思い出したり、発想の転換をしていたりすることができたようです。', null, 'タイピング: 得意な部分なのでとても楽しんで行っていました！
盛り上がり: くじを引くというお題があることでモチベーションが多少は上がっていたようでした！'),
  ('4ae660fb-1e35-5850-b017-372ec906abc7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-11', '17:30:00', null, '通常 / くじ引き問題でデバッグに取り組む', '問題のレベルは易しかったようですが、休み明けのスタートとしては気軽でちょうどよかったのか、それぞれの問題のバグにツッコミを入れながら、それなりに楽しそうに取り組んでいました。細かい動きまで見てしまうとどこまで直したらよいのかわからなかったようで、7や8などは、自分だったらもっと作りこむ、といった話もしていました。 8の上級問題では、リストは苦手だからと変数で解決していました。こちらも正解ではありましたが、リストへの苦手意識を取り除いておきたいところでもありました。', null, '盛り上がり: もともとバグ探しは得意なせいもあったのか、楽しそうに取り組んでくれました。 ステージ8のテストプレイが、デバッグよりも苦戦したことを面白がっていました。'),
  ('ff7aea74-bc0f-5b7f-bf30-dc228ca79647', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-11', '16:30:00', null, '通常 / くじ引き問題でデバッグに取り組む', 'ステージ4までは、簡単だと言って一気に解いていました。 そこで少し疲れたのか、くじ引きを2回引いて「もういいや」と言い出しましたが、休憩で飴をなめたら元気が出たのか、あと2問やる、と言って頑張り始めました。 クローンがたくさん出てしまうのをどうすれば良いか、なども一発で「待つ」ブロックを持ってきたりと、経験値のわりには正解ブロックを的確に選べていました。 タイピングのリスト問題はさすがに始めてみるブロックで混乱していたので、条件式の中を一緒に見ていくことで正解にたどりついていました。', null, '盛り上がり: 最後に5、6問題に頑張ってチャレンジして引いたくじがはずれでがっかりしたようで、しばらく落ち込んでいましたが、最初に5等を当てたことと、周りの当たり率を見て納得したようでした。自分でも予想外に？6問もチャレンジして、やり切った感があったようです。'),
  ('9c26899d-e0de-5825-9cfc-a484b3f8f9b3', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2024-01-08', '16:30:00', null, '通常 / くじ引き問題でデバッグに取り組む', 'クラスで一人だけ3からのスタートで不安そうにしていましたが、実際にやってみたらすぐにバグを見つけられてあっさり解決できたので、一気にやる気モードになっていました。 1問解き終わるごとに、嬉しそうに先生を呼んでいました。7までは行き詰まることもなく、スラスラとできていました。タイピングの課題のみ、正解、不正解の問題がクリアできたら完成、と言っていて、カウントが動いていないのを見落としていましたが、こちらも指摘したらすぐに直せていました。 座標と不等号の関係についてはまだ完全に把握していないのか、問題8のy座標の演算式で、一緒に具体的に考える時間が必要でした。 くじを3回引いて、残り時間は問題1のオレンジコスチュームを編集したりして楽しそうにしていました。', null, '盛り上がり: 一人だけ問題が難しい、と言われた後で、それが自力で解けると納得したときに、とても嬉しそうな笑顔になっていました。 くじ引きで当てたミニお絵描き版を早速活用して、Scratchのゲームのパスコードを書いて帰っていきました。'),
  ('56d6f547-0c01-54f1-a313-87b7eb31401b', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-11', '16:30:00', null, '通常 / くじびきの問題', '少し間があいたからか忘れ気味の内容もありましたが、座標や繰り返しの基本的な内容を思い出すとステージ4まで正解にたどりつきました。ステージ5と6にも挑戦し、クローンやリストなど見たことのないブロックも出てきましたが、一緒に流れを追っていくと最終的には直せばいい場所がわかったようで、解くことができました。', null, '盛り上がり: くじびきを引くことをモチベーションに頑張って取り組みました。'),
  ('4898c586-fa46-56dc-aa3b-c681a86c17cd', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-11', '17:30:00', null, '通常 / くじ引き問題問題1~', '1は問題点に気づくのに少し時間がかかったようでしたが、スムーズに取り組めていました。2はすぐにプログラムが完成していましたが完成後にゲームクリアをするのにかなり苦戦してました。3もすぐに完成させていました！4はボイパの部分のプログラムを理解するのに少し時間がかかったようでしたが、音を鳴らす部分はうまくプログラムを作成できていました。5ではクローンの説明をしました。あまりなじみがなかったようです。6ではリストの説明をしました。一緒にプログラムを最初から確認して、条件の間違いを見つけることができました。', null, null),
  ('b7d2fb84-c6d4-59f4-b8cc-e2534da0429c', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-11', '16:30:00', null, '通常 / くじ引き問題問題1~', '１、2に関しては自力で丁寧に取り組むことができていました。着眼点も良かったです。3も回数に注目してプログラムを変えることができました。4は、音に気付くのに少し時間がかかりましたが、すぐにプログラムを変えることがでいました。5はオレンジの数に注目して時間を細かく調節してくれました。6も条件をよく確認プログラムできていました。リストの使い方、役割をよく知らなかったそうなのでかなりしっかり説明しました。', null, null),
  ('c027edea-3a6b-58c1-b5f5-579f437d38e0', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2024-01-11', '17:30:00', null, '通常 / くじ引き問題問題5~', '5は難しく考えすぎていたようで、ゆっくり考えると分かったようです。6については、条件分岐がややこしかったようで一緒に最初から読み直すと理解できた様子でした。7に関しては自分で改善点を見つけにくかったようですが、ジャンプの条件に注目してもらうとうまくプログラムすることができていました。8もプログラムを読み直して取り組んでもらいました。上級アレンジもなかなかアイデアが思い浮かばなかったようで、変数を使うことをアドバイスしました。 最初にプログラムを確認することをもう少し意識づけてもらいたいです。', null, 'タイピング: 集中して取り組めていました'),
  ('5e93e0f0-940b-58b2-989b-ca4d4a3bfef5', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2024-01-11', null, null, '通常 / くじびきの問題', '集中力をもって問題に取り組みました。座標の移動についての問題のステージ2はすぐにできていたので、座標の理解はしっかりしているようです。その他の問題は試行錯誤しながらで大変そうなことが多かったので、時々ヒントを出すと正解までたどり着けました。その答えにも納得したようでした。特にステージ3ができたときは繰り返しについての理解が深まっていたと思います。 デバッグという言葉が印象に残ったらしく意味を覚えたようです。', null, '時間帯: その他
タイピング: 久しぶりに最初の数分やっていました
盛り上がり: 3等のパイナップルが当たったことにびっくりして、今年の運を使い果たしたとか言っていました'),
  ('75e4feca-7339-5d6e-90e0-7133b9364d9d', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-22', '18:40:00', null, '通常 / 右に消える（背景スクロールを理解できていればクリアできるはず）、5秒タイマー、５０で終了', '3問挑戦する予定でしたが、本人が眠いとのことだったので座標のみにし、後半はプログラムをアレンジしてもらいました。 前回の復習をしました。本人にポイントを聞いたら「座標」とのことでやったことはしっかりと覚えられているようです。「端」の話がイマイチまだ理解しきれない様子だったので、画面の端のx座標を考えてもらい、それよりも小さい値にするか大きな値にするかを考えてもらうような説明をしました。後半は座標のプログラムにたくさんのスプライトを追加したり背景を加えたりしていました。楽しく取り組めていてとても良かったです。', null, 'タイピング: 集中してできていました！'),
  ('5f616388-8d49-56b5-9922-173ba24c08d2', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, 'ea993e6e-50a7-56b1-bcb2-551c8f750b4e', '2023-12-22', '18:40:00', null, '通常 / 先週やったお猿のゲームを保存忘れていたみたいなので、5秒、５０、280で隠れる、リストのバグ潰しの問題＞その後にゲームで遊んでいました', '色々と今まで学習していた成果がバグ潰しでも生きていた様子でした。特にリスト〜の部分はほとんどの子たちが難しいと不満をもらしていたのも、少しだけヒントを与えただけで目印になるコードは変数だなと理解し、ものの5分ぐらいで解いていました。 本人にとってはとても簡単な感じだったので次回なにかバグを潰す系のものであればやはり何かと関わりがあるもので動作が動かないという作品でやったほうがいいかなと思いました。', null, 'タイピング: タイピングには自信がある様子でした！
盛り上がり: 変数の理解がとてもよく理解できていて素晴らしい！と思いました'),
  ('e1f84714-7743-5f8a-b889-c47cd0277a30', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-22', '17:30:00', null, '通常 / 5秒タイマー（簡単）、５０で終了（簡単）、これはチャレンジ→後ろから削除（リストの問題、むずい）', '座標、5秒タイマー、50で終了のプログラムはすぐに終えていました。演算の使い方が胆だということが少しずつ分かっているようで、不等号をしっかり使うことができていました。チャレンジ問題の「後ろから削除」のプログラムについてはかなり苦戦していました。1秒待つを使って工夫しようとしていました（考え方は◎）。変数を使うようにアドバイスをするとなんとなく方向性が見えたようです。', null, 'タイピング: やる気が低かったです。'),
  ('b910b205-5f91-547b-97d8-a22e3f753a7a', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-22', '17:30:00', null, '通常 / バグ潰し、5秒タイマー（簡単）、５０で終了（簡単）、できたら後ろから削除（リストの問題、むずい）', '座標、5秒タイマー、50で終了はどれもスムーズに終えることができました。50で終了に関しては、きちんと50で終わらないことにモヤモヤしていたようです。方法を2パターン紹介してくれました。 「後ろから削除」に関しては、新しい独自の方法でプログラムを作っていました。もはや元のプログラムの面影はなく、周りくどい方法ですが、条件分岐や「１秒待つ」、演算のブロックを論理的に組み合わせることができていました。一度画面がごちゃごちゃしてしまったので綺麗にする手伝いをしましたが、ほぼ自力で作成することができました！すごい！本人も満足そうでした。', null, null),
  ('f9093d74-26fb-53d1-bff0-c7e34ddfa870', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-22', '16:30:00', null, '通常 / バグ潰し、5秒タイマー（簡単）、後ろから削除（リストの問題、むずい）', '5秒タイマーでかなり苦戦していました。自分があまりタイマーを使わないことも原因にあるようです（好きじゃないのかな）。リストの問題がやはり一番難しかったようです。変数を使うようにアドバイスをしましたが、本人は違う方法でやりたかったようです。絶対値を使ったり、演算をたくさん使ったりでいろいろ言考えてくれましたが、最終的には変数を使う方法で落ち着きました。たくさん考えられていて素晴らしかったです。', null, 'タイピング: やりたくない様子でしたが、取り組んでもらいました。'),
  ('fecc0fe3-2b46-53ee-95c3-c61c83d879ad', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-22', '17:30:00', null, '振替 / チーズを探せ〜をヒントありでプリントを見ながら最初から作成してみる「幽霊が出現するところまで」', '最初のタイピングでおそらく20分ぐらい楽しんでいたのでレッスン自体集中力がもつか心配ではありましたが、最後の幽霊が出現する部分まで完成することができました。 ヒントを出しながら、こちら側が「なんだっけ？」と話すと「それはこのコードだよ！」とすぐ話してくれたので、ネズミの動き、チーズを出現、幽霊を出現させる部分は難なくクリア。 ただし、ランダムに出現させるというところで、座標の数をとんでもなく大きな数字にしていたので、画面の中の端と端の数字は決まっているのでその間で考えた方がゲーム性として多分成り立つよと話したら、その数に収めて乱数を作成してたので、とても理解力はあるのだなと感じました。', '邪魔者を追加する部分から', 'タイピング: 第２話を全てやり切っていました。ローマ字でおそらく３〜４文字を打つ練習に入ったようで、自分でも難しい！と言いながらも頑張っていました。
盛り上がり: 幽霊の出現をさせて何にも起こらないのはつまんないじゃんというので、じゃあ当たったら、点数かネズミが止まるようにしたらと伝えたところ、点数がゼロに戻るというコードを書き加えていました！'),
  ('8d9d5467-8783-54fc-8132-aa951f3cd77b', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-22', '17:30:00', null, '振替 / 基本操作コース_06', 'レッスン内容に関しては、現在のレベルでは作るのは簡単な様子でした。本人としては、元となっていた物語よりは、オリジナルの部分を多く含ませたい様子でした。特に、セリフに関してはかなりこだわっていたようで、何度も録音をし直している様子でした。他にも、キャラクターの場面移動や背景の切り替えなど工夫できる部分ではさまざまなオリジナル要素を入れて制作をしていきました。', null, '盛り上がり: 自分のアイディアを作品にしっかりと取り入れることができていたので、本人としては、この作品ではやりたいことは全部やれたようで満足していました。'),
  ('fa24f871-750c-57d5-b737-77b6d29aca0b', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-22', '17:30:00', null, '通常 / 5秒タイマー（簡単）、５０で終了（簡単）それが終わったら遊んでOK', 'ちょうど学校で不等号を習った時期みたいでくの字の右と左でどっちの数が大きいか小さいかを最初におさらいしました。 いままで点数という変数を使う時に、イコールしか使っていなかったので「〜まで繰り返す」のコードに変わった時には不等号を使うことでゲームがより楽しくなるということを話しておきました。 今回理解できたものを、今まで作った作品の中に当てはめてみるということで、ピンポンを使って＝ではなく不等号に変えてクリアを出現させることを試してみたほか、スプライトを追加して、ボールが鉄砲の弾に当たったらゲーム自体が終わってしまうというアレンジを加えていました。', null, 'タイピング: いい具合にタイピングしていたと思います。
盛り上がり: 自分で何かの作品をもっと作りたい！という気持ちがあってとてもよかったです'),
  ('c618cec9-5292-5e29-8065-69dfa0fcf48b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-22', '16:30:00', null, '通常 / カエル～のアレンジ', '前回から製作していた横スクロールアクションゲームを完成まで持っていくことができました。本人としては、スタートからゴールまでの一通りの内容を入れることができたようなので、かなり満足していました。ジャンプについては少し苦戦していたようでしたが、色を使ってしっかりと解決することができていました。', null, 'タイピング: 自信を持って取り組むことができていました。正確さはあるので、速度を上げていくことが課題だと思われます。
盛り上がり: 作品を完成させることができていたので、年内に終わらせるという目標をしっかりと終えることができていました。'),
  ('a35819d0-4276-5793-96bf-e3fbfecf3296', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-22', '16:30:00', null, '通常 / バグ潰し 5秒、50で止める、右に行ったら消える（座標の問題） カエルが家にカエルのアレンジの続き', '最初に右に消えた〜の座標の問題をやってみました。なんとなく数字をこれにしたら消えるだろうという「なんとなく」の部分を理由があってちゃんとやって欲しいんだよねということを伝えると、わからないと話していたので、先週カエルがお家〜の授業で動画を見た時に数字を明確に右端と左端を覚えていなかったので、２４０だったよねということを伝えたところ、その数字をいれて隠すのコードを使っていました。 そのほかの問題も不等号の問題で、たくやくんには少し難しいと思われましたが、くの字だとどっちが大きいか考えてみてと伝えたところ、そうか・・という感じで解いてクリアしていました。', null, 'タイピング: 楽しそうにやっていました
盛り上がり: 最後にカエルが家に帰るというゲームをアレンジしていたのですが、背景を自分で創意工夫して、人が歩いていくと色々な風景の中を歩いていく〜という作品にしていました。 今後このアレンジを使ってゲームへと変更することもできるのかなぁと思っています。'),
  ('d8e73456-654e-5fb4-8641-f36039646f6d', '28d52d6e-7571-5090-a2d9-492c997b719e', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-16', null, null, '通常 / キャッチゲーム', 'フリエのキャッチゲームなどを提案しましたが、先週作っていたオリジナルキャッチゲームがまだ作り終わっていないとのことだったので続けてもらいました。キャラクターとアイテムの当たり判定を、色を使って作っていました。スコアをつけるときに、変数の値を増やすのと0点に戻すのも自力でできたのですが、一気に何点も増えてしまって困っていました。「"1ずつ変える"を何回もやってしまっているから、1点増やしたら1秒くらい待とうか」とアドバイスすると直せました。途中、ブロックA→ブロックB→ブロックA→ブロックB...のように同じパターンのブロックを何度も置こうとしていたので、こういうときに繰り返しブロックを使うと簡単だよと伝えました。繰り返しの対象をどこからどこまでにするかは少し難しかったようですが、一緒にそのコードを作り「これは便利だね」と感心していました。ゲームは完成までしたようです。', null, '時間帯: その他
タイピング: 楽しく進めていました
盛り上がり: 新しいことを理解したり、好きなものを創作したりしようとする意欲を感じます'),
  ('458afa3b-2835-53ce-9a71-fa12c7d94f21', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2023-12-21', '17:30:00', null, '休み（未対象）', null, null, null),
  ('78d3d11a-3e31-5161-96fe-4c8f0ad21f91', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-21', '16:30:00', null, '通常 / プラットフォーマゲームの基礎スキル習得', '背景スクロールの確認をした後で、オリジナルゲームの作成に楽しそうに取りかかっていました。背景が動くにつれて入れる画像効果を色々試して色を調整したりと、凝ったデザインを熱心に作成していました。出てくる敵キャラも、マウスでとても器用に描いていました。 敵キャラスプライトが背景と同じ速さで動くように、背景のスクリプトを複製して使っていましたが、その際どのブロックが不要でどのブロックの数値を直すか、出てくる位置を変えるためにどこに乱数を入れるかなどは、よく理解していて、自分でスムーズにコードを書きかえることができていました。 ジャンプしたときにブロックに乗れるようにするのがわからないとのことだったので、ジャンプからおりるときにブロックに乗るということは、コードにするとどういう動きになるかを一緒に考えました。ジャンプのコードに、ブロックに触れたらという条件分岐を入れるところまでは考え付いたようだったので、ジャンプが降りている動きのとき、変数はどうなっているかなど、こちらが細分化をして答えさせ、ブロックに乗ることができるようになりました。スプライトに触れた判定と色判定を両方試して、満足そうにしていました。', 'ブロックの上に乗ったらジャンプのスクリプトを止めているので、そのあと下まで降りられるようにコードを修正していく予定です。', 'タイピング: 簡単な文字での早打ちを楽しそうにしていました
盛り上がり: 自作のゲームが形になっていくのが嬉しそうで、一生懸命に取り組めていました。'),
  ('b5a6e6d5-26f8-57af-a5ba-e5a34b97eb97', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-21', '17:30:00', null, '通常 / ツムツム完成', '前回からの続きで、なぞり部分を作っていきました。途中、右側に勝手にスライドしていくバグがあったが、自分で発見して直せていました。その後は順調に作れて行き、完成にたどり着けました。 残り時間はゆきちゃんとともに自由時間にしました。', null, 'タイピング: お得になるか瀬戸際でした
盛り上がり: 検索履歴が学校回線を避けるものになっていて笑いました。'),
  ('4e97a2ee-ad19-5f25-9944-a8318deb3da4', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-21', '17:30:00', null, '通常 / アルスタジオレッスン/ボールキャッチ1 作成続き ボールが落ちてくるときの表示設定と、ボールスプライトの複製をして完成させる', 'ボールを複製させてうまく落とすことができていたので、落とす時間の間隔を変えてみようと提案しました。その直後に、やりたくなかったのか分かりませんがキーボードを雑に触ってしまい、プログラムが7分前の状態に戻ってしまいました。本人的にかなりショックだったのか、その後やる気がかなり落ちてしまったようです。再度複製をしてもらうときに、x座標にとくに注意して配置してもらいました。しょっちゅう「面倒くさい」と言っているのが気になります。適当に配置したスプライトを画面を邪魔するように激しくアレンジしているのも残念です。', null, 'タイピング: かなり気乗りしない様子でした。途中Sがでていました。'),
  ('728556c2-ff2e-58ec-9cd5-b2070e834db6', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-21', '17:30:00', null, '通常 / 【DKゲーム】02迷路 チーズをさがせ！②邪魔者ver 作成続き 虫に触れたらゲームオーバーのバグを修正して完成させる 完成したら 【小技】超初級 きも目玉 クローンの学習と、ボタンを押したらゲームスタートの作成', 'おばげの当たり判定がうまくプログラムされていなかったので、見直しました。途中、一気に点数が下がってしまう現象が起きましたが、自分で解決策（1秒待つ）を見つけることができていました。虫あったときに背景を変えるプログラムもしっかりできていました。メッセージをおくった直後にまたメッセージを送ってしまうことがあったので、メッセージの考え方にも今後慣れていきたいです。 後半はきも目玉をやりました。かわいいコスチュームを作ってくれました。クローンの機能は知らない様子でしたが、親分子分の話をするとなんとなく理解できた様子でした。今までやってきたこともよく覚えているようで、しっかり完成させることができました。', null, 'タイピング: 集中して取り組めました。'),
  ('db92ae64-a20f-563f-ac5b-25494a3f208e', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-21', '17:30:00', null, '通常 / ツムツムの完成', '前回でコードをすべて組みあがっているが、変数のグローバルかローカル変数かの違いでバグっていたので、直していきました。そのままグローバル変数からローカル変数へ変更ができず、新たに作る必要があり、同一の名前が設定できず、変数消すとコードも消えてしまうことがありました。だが、そこは賢く少し名前を変えて新しく作り、コードが消えることなく作る対応力がありました。 30分で完成できたので、あとは自由時間にしました。', null, 'タイピング: 速いです
盛り上がり: この時間は承太郎君と二人だったので、じゆうな会話が弾みました。'),
  ('a7fac65c-6121-57ea-aa1f-f1a029d51306', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-21', '16:30:00', null, '通常 / アルスタジオ/【Prg】10 レースゲームを作ろう！ 作成続き 完成したら、単元別演習F-6かけっこゲーム スプライトが複数のスクリプトを持つことと、マウスが押された条件分岐の復習と、「マウスが押されたではない」の学習', '丁寧に進められていました。途中、ライバル2がうまく画面にでてこないバグが起きましたが、座標や速さを見直して解決することができました。変数や色判定の使い方を最後におさらいしました。 後半のおいかけっこはネコのプログラムを作成しました。レースゲームで長押しの部分に注目できていたので、取り組みやすいようでした。「～ではないまで待つ」の使い方について少し確認しました。ライバルのクマが強すぎたようで、プログラムで歩く速さを調整していました。', null, '盛り上がり: 最後に遊んだマリオゲームはクリアでした！！'),
  ('3240a9d2-4985-5a66-912d-b8ab6e3cc90f', '57f45872-1f3e-5540-b676-bf9023444e39', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-21', '16:30:00', null, '通常 / 連打防止を作ろう', 'レースゲームは長押しで進むコードが印象的だったので、逆に長押し防止の連打できるレース順位ゲームを作りました。連打防止の核となる「ではないまで待つ」作っているときに、どうゆうコードなのか聞きました。割っていなそうだったので、実演してどうゆうことなのか答えてもらいました。長押し防止のことがわかると、結構納得した顔していました。素早い作業で移し終わっていました。順位が先についた方が1となる仕組みも変数であることに気づけていたので、よかったです。', null, 'タイピング: 良い展開でした。
盛り上がり: 初期のころと比べ作る意欲が増してきています。 なかなかアメの量を食べます'),
  ('f8229b6c-fbb8-5728-bd5c-71e4b2c5526f', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-19', '17:30:00', null, '振替 / 引数のある定義の確認', 'ゲームをプレイした後、じっくりとコードを見てからおもむろに作り始めていました。 一通り理解してから作成を始めたせいか、とくに行き詰まることや疑問点もなく、作成を進めていました。 途中で昨日の部活の「コンピュータは小数計算が苦手」の話になり、自分から「Scratchで試してみる」と言って、0.1+0.2だと計算結果が昨日の通りになるのを確認し、1+3/10だと0.3になるのを確かめて感心していました。', null, 'タイピング: さらっとこなしていました
盛り上がり: 今回の課題のようなゲームはやったことがなかったそうで、面白そうに作成していました。'),
  ('5894fd4b-b53b-5973-b164-83adf4de5f8a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-19', null, null, '通常 / 自作ゲームを考えて作成する', 'こちらに提案の用意もあることを伝えましたが、今作成しているものを引き続き作りたいとのことで、そのまま作業に入っていました。 本人が熱心に作り込んでいるため、定期的にコードを見せてもらい、困ったことがないかの確認もしていましたが、特に問題なくモクモクと取り組んでいました。作成中の操作盤の機能や電車についての説明は、普段よりもよくしてくれました。', null, '時間帯: その他
タイピング: 相変わらず高得点の結果を出していました
盛り上がり: ひいろくんなりの完成予想図があるのか、とにかく一生懸命作成していました。'),
  ('329d72fc-82e8-57fa-84d8-e6e8fbde9e15', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-19', '17:30:00', null, '通常 / 【Prg】30 さんそを集めて生き残ろうゲームを作ろう', 'プログラム内容としても30番台に入っているのでそれなりに長くなっており、本人としても制作はかなり疲れていた様子でした。しかし、今回の制作では一度つまづいた箇所を自分の力だけで解決したり、理解の難しい箇所は動画を見返して確認したりとかなり積極的に作っている様子が見受けられました。そして、本人としてもかなり頑張っていたので、次回には完成まで持っていきたいようでした。', '今回の続き', '盛り上がり: 今回の単元はかなり長い内容となっていたので、半分ほどまで進めることができて非常に達成感を感じているようでした。
備考: 動画の9:24~'),
  ('0c1a8bf9-b3a2-50ee-9aa4-67036dba4c0a', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-19', '16:30:00', null, '通常 / 作品の完成を目指す', '隔週の為、前回作成したところを思い出すためにコードを確認して何度かプレイをしてから始めました。 ライバル1のスプライトが必ず2周するため、絶対に勝ててしまう理由を探させました。コードを一生懸命見て、コードは合っているとのことだったので、スプライトの先端についているピンクの〇がどんな役割をしているのかを説明させ、背景の車のコースを確認するようにとのヒントで、ライバル1とライバル2のコースが近すぎて、ゴール間際でライバル2のコースにうつってしまうことに気付くことができました。 学校でGoogleスライドを使っているらしく、背景のパーツの編集は得意！と言って、楽しそうに修正していました。 学校でもパソコンをよく使っているのか、Ctrl＋zやコピー、ペーストなどのショートカットキーを多用していました。タイピングもだいぶ速くなりました。ファイル名を作るときに、Defaultの長い名称を一気に消すためCtrl+aを教えたところ、とても喜んでいました。 ライバル1からライバル2のスプライトを複製した際に直すべきメッセージや変数名なども、動画を見ないで完璧にできていました。メッセージの関係なども、理解して作成できているようでした。', null, 'タイピング: 濁音や拗音の練習を中心にやっていました。
盛り上がり: 残り15分くらいのところでゲームが無事に完成し、満足そうにしていました。お父さんに見せるときも、うきうきした感じで説明をしていました。'),
  ('61d7fa6b-acb0-5d99-92d7-8a7d6298aece', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-19', '16:30:00', null, '通常 / アルスタジオレッスン/エキスパート/5秒で止めろ（タッチ操作可能）', '今回のレッスンに関しては、定義を再び使って作成でしたので、その部分をどのように使っているのかに着目して取り組んでいました。さらに、タイマーのスタートとストップやタイマーが消える仕組みについても動画を通じてしっかりと理解することができていました。来年からは、さらにレベルアップしたことへ挑戦できれば良いと思います。', null, 'タイピング: 今回は難易度を一つ上げて挑戦をしていました。タイピング速度はかなり速く、結果としてはスコアをプラスに持っていくことができていました。人差し指しか使っていなかったようなので、次回からは5本しっかりと使っていければ尚良いと感じました。
盛り上がり: このプログラムのゲーム性がシンプルなこともあり、できているのかがはっきりと確認することができていたので、楽しそうに作ることができていました。'),
  ('d37bc9de-f659-5a56-b8d8-8eda80b48237', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-19', '17:30:00', null, '通常 / 【Prg】47 シュンカンきおく順番当て演算＿変数＿定義を使って場合分け 動画の続き 16:53~', '丁寧に進められていました。30分ほどで終わりましたが、最後に定義の使い方の確認やクローンしたときのプログラムの工夫について共有しました。（リンゴの出現場所が被らないプログラムが短くも効果的だと感じたので） 後半は、クローンが固体によって別々の動作をさせるプログラムを作成しました。今までは全てのクローンが同じ挙動をしていたのですが、変数設定時に「このスプライトのみ」にすることで、タイム変数を使って出現するスプライトに別の言葉を喋らすことができました。今すぐに本人的に応用が思いつくわけではなかった様子でしたが、なんとなく理解してプログラムできていました。', null, 'タイピング: スコアも高かったです！'),
  ('d38b8abc-38bb-527e-89db-8ef2e7181cbe', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-19', '17:30:00', null, '通常 / プラットフォーマーゲーム続き ネクストステージ、ゲーム性アップ', '前回作ったプログラムを初めに見せてもらいました。ジャンプや地面の判定もよくできていたので、今回は2ステージ目を作ることにしました。スクロールを縦方向にやることも検討しましたが、プレイしやすさや製作の観点から通常通り横についたら背景がかわるようになるそうです。 どういうギミックを追加するかに悩んでいましたが、エレベーターをつけることになりました。横移動するエレベーターから落ちない工夫が必要で、かなりいろいろと考えていました。（相対と絶対） 次回以降も続きをしたい様子です。', null, 'タイピング: あまり気が進まない様子でした。'),
  ('e4b5eeb7-823c-5099-b73e-9f7da29c5a5f', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-18', '17:30:00', null, '通常 / アレンジを加えよう', '前回手つかずだった新たなスプライトにアレンジを加えました。前半は夢の国へ飛び立とうとする場面が多いかったです。しゅうくんのアレンジには条件が複雑に絡み合うことがあるので、ひと理解するのに労力がかかります。独立なアレンジが少ないので、ほかの条件とのバグが起こりやすいです。その解消途中で今回は終わってしまったので、条件を整理したいです。パッと条件がわかりにくいので、コスチュームvsほかのスプライトで表に書いて整理してもらいたいです。書いたものを見ながら作る動作が情報を整理することに身につくと思います。手書きもいいが、エクセルなどで打ち込むこともいいかと思います。', null, 'タイピング: 寒さで点数が伸びなかったそうです。'),
  ('dd022c4f-9ea8-5a47-91f8-20c351eeb842', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-18', '17:30:00', null, '通常 / インベーダーゲームの作成', '1か月も空いたので、何を作った忘れているか思ったが、意外と覚えていて早速作り始めました。作ったコードを見ていると、見た目上では問題ない動きをしているが、コードが少し無駄な作りになっていることがありました。せっかくクローンで作っているのに、クローンなし作った方がいいみたいなコードがありました。とりあえずクローンを使うことに分別をつけることが欲しいです。 本人的には完成できたぽいです。', null, 'タイピング: 強敵にはかなわないそうです'),
  ('e10f89a1-b3f3-53bd-98a6-3f29704aaadc', '7d01236e-620e-5177-a6f4-af325a582aae', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-18', '16:30:00', null, '振替 / アイテム脱出ゲームの完成', '週が開いたので、まずは、作ってきたものを振り返ってもらいました。その時点で、壁に触れたらステージがランダムに切り替わってしまうことが起こっていたので、バグ探しから始めました。まだ、4級の検定を合格したばっかのだったので、バグ探しの手順を画面で追ってみてもらいました。ある程度進んだら、どこを直したらいいか手を出して直してくれました。その後は順調に進み、完成できました。', null, 'タイピング: めちゃくちゃはやかったです
盛り上がり: アレンジをする時間はなかったですが、こーづのきわ際を責めることが多かったので、マップ製作もしてもいいかも'),
  ('6b15dcd0-f468-5707-a9cd-96190134c8a5', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-18', '16:30:00', null, '通常 / 太鼓の達人ゲームをリニューアルしよう', '先週の続きで今回は難しいモードを作っていきました。動くスピードや待機時間などを変えて、先生からの合計スコアが高くなるようにしてもらいたいと提案したら、全体の繰り返す回数を増やしてくれました。その後のデバック操作も流れるようにこなしていて完成度が高いものができました。 まだ、クローンやリストなどの難しいスキルの習得がありますので、それによるさらなる改善(リズムよく球が流れてくるなど)をもう1年か半年後に習ってからやってもいいかもしれないです。', null, 'タイピング: タイピング速度を上達してきました
盛り上がり: IDとパスワードを教えてもらい家族に自慢するそうです'),
  ('545f7307-c7f9-5787-95ec-0169c0384931', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-12-15', '17:30:00', null, '通常 / だるまさんがころんだ（乱数を使う）', 'チュートリアルで「さるまさんがころんだ」を作成。特に難なく作り終えるが。それぞれのブロックの使い方、内容の理解にまでは至っていない様子ではあった。一度作り終えてしまったので、ブロックの確認はちょっと気が進まない雰囲気であったので、アレンジを提案。インベーダーの敵が上下に動いてアル君を邪魔すると言うアイデアを発案。 ★スプライトを上下に動かそうとすると、手がとまりました(* ´艸｀) 上下に動かしつつ、端についたら跳ね返るというイメージを持っていましたが。 ⇒私が座標と向きの難しい方を話してしまいました💦 失敗しました。 でも、「向き」が角度であることと、「何歩動く」がその角度で動くという認識があまりなかった様子？「向き」の理解が低かったようなので。一度、その単元だけおさらいすればOKと思います。', '⇒上下に動くパターンのみを、別の教材でやりなしてみてください。', 'タイピング: ─'),
  ('71c3d317-56c6-58b4-9527-b69985fec1e3', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-16', null, null, '通常 / チーズを探せのアレンジ', '最初遊んでもらったときに、そのまま関せ品をいじろうとしていたので、これを一から作るように仕向けると、えーできないよと自己流に作り始めした。アレンジの内容は面白いものですが、跳ね返りの動作は作ってあげたかったです。何度も作っては納得いかず消しの繰り返しだったので、今度来た時に上記の注文を作らせたいです。', null, '時間帯: その他
タイピング: やれてました
盛り上がり: 迷路のデザインはとても個性的でした。'),
  ('56750f16-0b90-5145-93dd-12dba21f8ed8', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-16', null, null, '通常 / 脱出ゲーム', '前回半分くらいは作っていましたが、バグが出たとのことで動画の最初からミスがないか確認していました。変数の名前や値に変なところがないか確認しようと助言すると、しばらく集中してその場所を探していました。結果、縦と横のスピードを取り違えていたり、-0.1のマイナスが抜けていたりというミスを自力で発見できました。そのあとは鍵の複製などを勧め、完成に近づきました。', null, '時間帯: その他
タイピング: 時間が始まってすぐに取り組み始めていました
盛り上がり: デバッグのとき、そうたくんも同じバグがあったらしく、直った時は教えてあげていました。'),
  ('8a45b94a-e7bc-5897-8d10-10ff2da9bccb', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-16', null, null, '通常 / 前回の続き', '今回も最初のロボロックスのやる時間が伸びていました。コード作成を続けても、ある程度は集中できるが、わからなくて詰まると、ほかのことをやり始めるのは良くないです。詰まったらすぐ来れなくても読んでほしいです。', null, '時間帯: その他
盛り上がり: 1級合格は素晴らしい'),
  ('db0da441-6209-5211-8449-7206f567455a', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-16', null, null, '通常 / オリジナル作品の完成', '今回はゲームオーバーになるときの前動作を作りました。一回上がって下に落ちる、昔のゲームオーバーみたいな動きを作りましたが、前回ジャンプの作り方がしっかりしていたので、ほかの動き干渉することなく、きれいに作れていました。また、背景の配色をより奇怪なものになっていて一度完成することができました。さらに、背景に戦闘機を加えて、にぎやかなものになっていました。', null, '時間帯: その他
タイピング: お得な額になっていました。
盛り上がり: 周りの楽しい雰囲気に流されず、集中していました。'),
  ('daba86c8-1406-5a59-8aea-a1fc57caf8c5', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-16', null, null, '通常 / 小技の背景動く〜プラットホームの部分をおさらいしながらいくつかやり方があることを学ぶ', '以前やったというので、最初にやった内容を確認。小技の方に関してはクローンをしようして背景を動かしているので、メッセージをおくりあっても背景を動かすことはできるんだよの説明へ移行しました。 小技のチュートリアルを見せながらどうして座標の方が不等号の小さいにくるのか？を図を示しながら説明。-460 よりも-500ならどっちが大きい？の質問にやっとマイナスの不等号の向き方が理解してくれたようです。マイナスがはいると混乱するのかな', null, '時間帯: その他
タイピング: 400点以上をマークできたようで嬉しそうでした。
盛り上がり: 今日は色々なやり方を学んだ上で不不等号の向きをおさらいできたのがとてもよかったようです。'),
  ('5af02262-d246-57d3-b388-d47bed78548d', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-16', null, null, '通常 / ゾンビを倒せの完成', 'ゾンビをたおせは動画を見ながら作りました。ただ、上下の移動については「前にもやったからできる」と自信ありげに言って、動画を見る前に作れました。「○○に触れたなら」を何回か使いましたが、何に触れたかを間違えることがあったので確認していきました。その他は順調に理解しながら進め、完成しました。 少し残った時間はオリジナルゲームの続きを作りました。さっきの「ゾンビをたおせ」でキャラクターの向きを変えることをマスターしたので、このゲームにも応用することができていました。ゲームクリアの画面を作りたかったとのことだったので、新しく「○○秒待つ」を伝授して、今までもやった「隠す/表示する」を活用して実現することができました。', null, '時間帯: その他
盛り上がり: 好奇心が感じられます'),
  ('4842661c-7839-5a13-8ece-c97ff7f5fb4f', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-16', null, null, '通常 / うさぎとオオワシのレースゲームで〜ではないまで待つのコードを学ぶ', '途中まで一人でやっていたためやる気が下がっていましたが、こうしろうくんと一緒にやることで「そういうコードを書くやり方もあるのか」ととても楽しそうに最後までやり切ることができました。（おおわしのゴールが完成していませんが・・・） 動き〜や、もし〜、制御のあたりに関してもきちんと文章を理解してコーディングしているような感じがあって、理解力としてはこうしろうくんよりも上かも・・', null, '時間帯: その他
タイピング: タイピングはとても得意な様子で途中からコードの名前を変える時にはスムーズにタイピングするぐらいだったので、文章を打ち込む方は今後検定を案内してもいいのかなと思いました。
盛り上がり: 今年最後の授業がとても楽しそうに終わってよかったです。'),
  ('96af427f-89a0-58b3-9680-510ee15fc0cc', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-16', null, null, '通常 / アイテム脱出ゲームを続き', '先週の続きで、ボールが勝手に動いてしまうバグがから、直していきました。バグっているからもうやりたくないと投げ出しなかんじがあったため、画面からわかるバグの内容を伝えました。性格的にわからない所には突っ込まないので、わかる視野まで情報を与えてあげると、やる気が戻ってきました。一面のゴールができるところまで作成できたので、次で完成はできると思います。', null, '時間帯: その他
タイピング: タイピングへの拒否し続けます。
盛り上がり: 集中したときのスピードは速いです。'),
  ('f97765ac-e696-5a41-ad0f-d2e5eb032edc', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-16', null, null, '通常 / うさぎとオオワシのレースゲームで〜ではないまで待つのコードを学ぶ', 'ゆき先生に途中まで〜ではないまで待つのコードを教わったようで、途中まで自分でヒントなしでも動きを作ることができたようです。その後ノアくんと一緒に作業をすることになったのですが、色々２人で話し合いながらコードを一生懸命書くことをしていました。 順位を決めるコードの際も一番に気がついて触れたら〜のコードで考える〜の部分も難なくクリア。', null, '時間帯: その他
タイピング: 一生懸命タイピングしていました
盛り上がり: 今年の最後の授業がとても楽しそうでよかったです。'),
  ('40f6b5eb-e0c1-5bdf-b68e-bb43bd9b66ac', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-16', null, null, '通常 / 【Prg】14 イライラゲームを作ろう！」続き', 'いらいらゲームのポイントはレベルが上がっていくごとに場面が増えることが難しいので、今日はそこの部分にとても時間をかけてコードを書いていました。 かつ、または〜の部分は時間がなくて復習はできなかったですが、〜ではないまで待つのコードがシュチュエーションが違うけれども出てきていたので、「このコード何かのゲームで出てきたよね？」と話したら、固まってしまいました。 ただ、レースゲームの話をしたら、思い出してくれたので彼女もまた真剣に勉強してきた成果だなと思います。', null, '時間帯: その他
タイピング: いつも通りにタイピングも早くできていました！
盛り上がり: 試験が受かったことにとても嬉しそうにしていました！'),
  ('74d65ac7-75f6-50b4-8a0d-517a16613846', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-16', null, null, '通常 / 【Prg】29 カミナリをよけろゲームを作ろう！」続き', '今日は雷が落ちてきたあとの動きを主に行っていました、PCで２つの画面を出しながら作業することに戸惑っていたようで、最初はコードを書きずらそうにしていましたが、PCの中で全てが完結することでとても集中力が以前にも増したような感じがしました。 またどんなゲームと一緒だったか？を聞いた時に一瞬検討もつかないという感じではありましたが、「りんごをキャッチする」のと同じだよと伝えた時に、思い出してくれたので、ゲームの中身としては本人のレベルに合っていたのではないかなと思います。', null, '時間帯: その他
タイピング: テンポよくタイピングしていました。
盛り上がり: りんごキャッチのことを思い出した時にとても嬉しそうでした。今まで集中して勉強をしてきた成果がでているなと感じました'),
  ('9afa5c32-6a36-57c0-bd1f-b49e1f0d09dc', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-16', '18:40:00', null, '通常 / 先週の続き、背景スクロール。先週は調子が悪そうだったので覚えてないかと 最初から説明するか、カエル～ジャンプ～の背景スクロールで遊んでもらって今自分がどれをやるのかを定着させるのでもいいかも', '今日は先週のことをどこまで覚えているのか？を確認。全く覚えていなかったので、横の動きはどうやる？の部分から入りました。 右と左に動く動きの時に、ずっとプラスの数字を入れてプログラミングしていて、どうして左に動かないのか？をおおよそ１０〜１５分ぐらい考えていました。 今までは文章を文として読むのが苦手ということもあり、やはりブロック自体を絵として捉えていた感じでした。 今後の課題としては少しづつ文章を読む訓練をお家でしたほうがいいかも〜とお伝えし、文を文として理解することを、増やしてあげたいなと思いました。 一応今日やりたい背景が右から左に動く動きはできたので、しばらく本人に定着するまで何回も教えた方がいいかなと思いました。', null, 'タイピング: ある程度タイピングにも慣れてきた様子でした。
盛り上がり: 座標の理解はできているので、そういう意味では低学年としてはとてもGood！'),
  ('4d752b06-694b-550a-bb3e-e2a9b93a8c76', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-15', '16:30:00', null, '通常 / 今日は先週の続きから～主に背景が動く～の部分を重点的に行いたい 座標の部分をどう理解するか？が肝。動きをもう一度ジャンプの背景が変わるもので再度確認してみることと、カエルジャンプ～の動画を見せてあげてもいいかも NHKの動画 https://www2.nhk.or.jp/school/watch/bangumi/?das_id=D0005180315_00000', 'たっちゃんとやっていましたが、考え方がとても大人なのか？それとも数学的な頭の発想なのか？動画をみてすぐに理解をした様子でした。またスピードという変数がある種アンカーの存在になっていることにも気がついた様子で、演算と変数の組み合わせをどのように使ったらいいのかも、自分のものにしていたような感じはありました。', null, 'タイピング: いつも素早いタイピングで手に汗握りながら行っていました。
盛り上がり: さくさくと作業をすすめて自分の思い通りの場面を作成。左に動くと色々な障害物がでてくるように工夫をしていました'),
  ('b9f3bccc-5bcd-57a5-a2e8-5baf6f66bfd5', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-15', '16:30:00', null, '通常 / 今日は先週の続きから～主に背景が動く～の部分を重点的に行いたい 座標の部分をどう理解するか？が肝。動きをもう一度ジャンプの背景が変わるもので再度確認してみることと、カエルジャンプ～の動画を見せてあげてもいいかも NHKの動画 https://www2.nhk.or.jp/school/watch/bangumi/?das_id=D0005180315_00000', '今日はカエルジャンプで背景が動く〜という部分を重点的に。座標に関してはよく理解できていますが、端と真ん中の座標の考え方はちょっと難しかった様子（数字が画面には書かれているわけではないので） ただ、動画をみながら、数学と絵の互換性がどのように接続されているのかを真剣に学んでいました。', null, 'タイピング: 自信をもって行っていました
盛り上がり: ちょっとたっちゃんには難しい内容（不等号と座標と算数の要素が関わるので）だったが、本人は最後に画面が動いているように見えてとてもご満悦でした。'),
  ('19436201-5f26-5245-9d07-87b35be4e3a4', '80660755-d846-5cdd-91a4-0ab78fe29034', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-15', '18:40:00', null, '通常 / 背景スクロールの作成', '前回キャラクターのジャンプについてやったので、今回は背景スクロールを作成していきました。結果としては、動画を見ながら作っていきどのようにして背景が動いているように見せて、背景を続かせるのかを自分で説明することができるほどに内容をしっかりと理解することができていたので、次回は今回作っていた背景スクロールを応用してのアクションゲームを進めていければ良いと思いました。', null, 'タイピング: なし
盛り上がり: 背景スクロールを実際に作ってみて、本人としてもさまざまなものに使うことが可能であると気づいていたようなので、どのようなものを制作していくか楽しそうに考えていました。'),
  ('8887ae05-1ea7-5460-bf69-49e2f4d7225d', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-15', '17:30:00', null, '通常 / ツムツムゲームの続き', 'ツムツムのツムが落下とクローンをする部分については作ることができていました。しかし、変数を作る際にこのスプライトのみにチェックを入れ忘れていたようなので、次回はその箇所の修正から始まると思います。本人としては、できれば頑張って次回までには終わらせたいようなので、少しペースを上げて制作していくことも必要になってくるかもしれません。内容に関しては、定義について少し教えてあげたところ大体の内容を把握することができていました。', null, '盛り上がり: ツムツムゲームはコードがそれなりに複雑になっているので、キリのいい箇所までいくことができたので、達成感は感じていました。'),
  ('b17c2403-f511-588c-8611-b058e045ced8', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-15', '17:30:00', null, '通常 / じゃんけんぽん', 'じゃんけんのプログラム内容に関しては、早く終わらせることができました。内容に関しては、自分でも変数の使われ方やプログラム全体の流れについてもしっかりと説明することができていたので、ちゃんと理解できていると感じました。本人としては、今回のプログラムに関しては内容としては少し簡単だったようなので、次回はもう少しステップアップしてみても良いかもしれません。', null, '盛り上がり: レッスンの内容をしっかりと理解することができ、自分でもしっかりと理解できたと感じられていたようなので、非常に満足していました。'),
  ('167717df-e830-5203-b5c1-27d939e0a441', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-15', '16:30:00', null, '通常 / PRG41_あっち向いてホイ', '今回は前回途中で終わっていたあっち向いてホイの続きを作っていましたが、一応最後まで作り上げることができたようですが、勝敗判定に関してエラーが残っているようなので次回で修正を終わらせつつ、今回やる予定でもあったピンポンゲームの制作に取り掛かることができば良いと思います。数字のプラスとマイナスを間違いやすいようなので、しっかりと見直しをしていくことができればミスもまた減っていくのではないかと思います。', null, 'タイピング: 最初のスピードはかなり速めで売っていましたが、時間が経つにつれてスピードダウンをしていたので、指が疲れやすいのではないかと感じました。もしくは、タイピングを一度打つ内容を覚えてから打っている場合もこんな感じになることが多いので、どちらかではないかと感じました。
盛り上がり: ひとまず引き続き作成したあっち向いてホイを最後まで制作することができたので満足していました。しかし、エラーに関しては正解のコードと比較して次回直していくと言っていました。'),
  ('3970c369-d3aa-547b-bc71-e47f2b128ad5', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-15', '16:30:00', null, '通常 / 走り幅跳び～の続きから。ジャンプの放物線系のおさらいは先週できているので、最後までやり切るのが今日の目標 （走り幅跳び自体は２週間前からやっているものの、集中力がプログラミングになると弱くなるので、最後までやることを意識）', '今日の感じは、ジャンプ〜メートルが幾つになったら応援隊が声援を出すかのあたりまで行うことができました。ただ、やはり集中力がなく最後までやり切るというのが難しい様子。 コード自体が長くなる&理解力が難しくなるとやっぱり逃げるという姿勢になってしまう。 ただ、一生懸命やりきろうとしているのはよくわかるので、眞子ちゃんの場合は自分が納得して、進めるというスタンスなのかも・・・', 'ラストまで', 'タイピング: 自分が自信があるもに関しては何回でも行う感じで息抜きとして使っている感じ
盛り上がり: 息抜きとしてタイピングをしているのはとても良い兆候だなと思いました（画面を見続けるということはできるので）'),
  ('0a67c6be-0b81-5f0f-b2e1-70723e42b2e9', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-15', '17:30:00', null, '通常 / 検定の見直し', '前回の続きをやるか、検定のやり直しをするかを選んでと伝えたところ、検定をやるとのことで一緒に見返して行いました。主語と述語の順番にやはり迷っているようで、概ね使うコードは理解できているものの文章読解の部分でつまづいているようでした。 バグが一個ずっと続いている部分も私もきちんとみないといけない部分ではありますが、1個わからなくなるとほかの部分もわからない！と癇癪を起こしてしまったようで、そのせいでか試験に集中できなかったのかなと思います。', null, 'タイピング: なし
盛り上がり: 今日は自分でできている部分もきちんと理解し、弱い部分も意識して受け入れようとしていたのがとても成長したなと思いました'),
  ('8d9bce2b-86db-5fc0-88a6-9bbfc795bbc8', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-09', null, null, '通常 / レースゲーム', '動画を見ながら進めました。途中メッセージの間違いなどがあったので一緒に確認して直しました。今日は今週2回目ということもあって集中力が途切れ気味で、休憩を多めに挟んだのでゆっくりめの進みでした。車を道に沿って移動させるところまではできたので、あとはゴール判定だけ作れば完成になりそうです。', '本人の意思次第で続きを完成させる', '時間帯: その他'),
  ('345c4ae6-9c31-5348-bd5a-e11ed84ba39a', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-14', '17:30:00', null, '通常 / ツムツム続き', 'こちらもバグ探しでした。球が積み重ならないバグでした。数字の打ち間違えもありましたが、一番厄介だったのが、色判定でした。スポイトで色を抽出できるが、玉のふちが細かったので、周りの色が重なり、色の3つのスケールがずれていました。そこで、スケールをもとの数字と同じにすると、正しく反応しました。これは、たまにありましたが、ほんとに厄介です。承太郎君もなかなか切れていました。', 'つづき', '備考: ツムツム作成注意ポイント ①色判定 ②ローカル変数の使用 作り方の3枚目を先に見せる'),
  ('380833af-e9ac-5594-8775-54128824f86c', '57f45872-1f3e-5540-b676-bf9023444e39', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-14', '16:30:00', null, '通常 / レースゲーム完成', '前回の様に動画を見ながら進めましたが、コードを書くスプライトを間違えたり、変数名(プレイヤーのスピードとライバルのスピード)を間違えたりとかなり混乱した様子でした。そのため、様子が一度で見られる完成版のコードを見ながら写経という形にしました。スプライトをきちんと区別して、まずはステージとプレイヤーのコードを完成させました。途中、「マウスが押された」ブロックや「○○と○○」ブロックなどの少しわかりづらい部分は意味を確認しながら進めました。', '続き(ライバル1,2のコード)', 'タイピング: いい成績を出して満足そうでした
盛り上がり: 難しい所がありながらもあきらめずに続けられました。'),
  ('99c5ffe4-e33b-59ca-ab8f-214ff7fa8355', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-14', '17:30:00', null, '通常 / ツムツム続き', 'コードはほぼ写し終えたので、今日はバグ探しでした。ふわふわな原因を一緒に探していたが、なかなか見つからず、ほぼ終盤で何とか1つ見つかりました。ただその時、もう時間がなかったので、来週への持ち込みです。 そのバグとは、玉番号やキャラ番号、馬向きの勢い、向きがローカル変数でなくグローバル変数で作っていたことです。この変数の使い分けは、検定でも注視されていなかったので、ゆきちゃんにはなじみがなかったと思います。クローンで各々を変数で制御するには、独立したローカル変数が必要でした。グローバル変数のままだと、1つの変数の箱で、クローンを動かすことになるので、このようなふわふわが生まれたと思います。 最初に作っていた承太郎君もこの間違えに数週前に気づいて直して、大変がっていたことがあったらしいので、気づきにくいと思います。 今までは変数はデフォルトでグローバル変数を使っていたので、高学年には違いを意識始めるのもいいと思います。', '直しは大変だが、ローカル変数への作り直し。', 'タイピング: 速いです
備考: 要望：高学年向けにローカル変数とグローバル変数を意識できる簡単なゲームがあればいいなとおもいました。'),
  ('dddd567e-6f89-5702-8457-0661b516d9ad', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-14', '16:30:00', null, '通常 / チーズを探せの完成', '幽霊の動きは、「表示/隠す」と乱数をうまく組み合わせて作れました。虫の動きについては難しいようだったので部分的に写経してもらいました。「もし～なら」のネストが複雑で読むのも大変そうだったので、上から順番に読み解いていくと理解できたようでした。ここで使った乱数についても、ランダムに違う数が出てくるものだと覚えていました。虫に触れたらゲームオーバーになるはずですがならないので、そのバグを直したら完成でよさそうです。', '続き', 'タイピング: ミスが少なくなっています'),
  ('fb9f719d-74e4-52a0-95ac-4ba051f0927c', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-14', '16:30:00', null, '通常 / レースゲームの続き', '先週の続きで、今回は変数とセリフをつながげることが新しく出てきました。変数ブロックの多様な使い方に一瞬戸惑いありましたが、取り組めていました。複数のブロックを組み合わせて使うことににまだ慣れていない感じがありました。あと少しで完成できそうです。', null, 'タイピング: 打てるひらがなも増えてきました。
盛り上がり: 検定の合格にとても喜んでしました。'),
  ('fea0b432-373e-59d0-b867-c929e5d63d3d', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-14', '17:30:00', null, '通常 / ゆうれいから逃走の完成を目指す', '以前作ったところを復習し続きに入りました。ずっと「どこかに行く」を繰り返していて敵の動きが速すぎたので、もうちょっと遅く動かす方法ない？と聞くと、「1秒でどこかに行く」を思い出せました。ぶつかったときに音を鳴らす、スコアを加算するなどの動作は、お手本の動きを見せてどのように動いているか観察してもらいました。ゲームクリアの途中まで作れて、あと少しで完成です。', '続き', 'タイピング: レッスン時間の前に始めていました
盛り上がり: 少し間があいたからか集中力がやや散漫になってしまった様子でしたが、ゲームの細分化された動きを見せると少し効果があったと思います。'),
  ('d81d25b0-2396-5491-8a8b-7306dc76bcf4', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-14', '16:30:00', null, '通常 / 学習したスキルを組み合わせてゲームを作成する', '検定の認定証を渡したら嬉しそうにしていました。合格基準が80点だったらギリギリ合格だと思っていたようなので、合格基準60点を大幅に超えていると知って喜んでいました。 プラットフォーマーゲームを作成する意図を伝えてから、ジャンプの復習に入りました。 10/5に、基本操作コース09のジャンプゲームを学習する際に変数ジャンプについて少し触れたようではあったのですが、あまり覚えていないとのことだったので、等速ジャンプのはじめから復習をしました。 ジャンプの高さや繰り返し回数を変数にする意味を、数値を色々と変えることによって実感させましたが、これだけでもかなり楽しそうにいじっていました。 この後、高さをどうすれば自然なジャンプになるか、図解しながら一緒に考えて、上昇時はジャンプの高さをどうしていくか、どの時点で下降に入り、その後はどうしていくかなどをゆっくり考えさせ、自分でどういうコードを作ればよいのかまでを導き出すことができました。演算式の書き方についてはヒントを出しましたが、ジャンプの動きとはどういうものかというのをりょうやくん自身で考えていけたのは、よく頑張っていたと思います。 左右の動きを作成するところで、ジャンプしていないとき=y座標が○○のとき、という条件が入っていて、スプライトの初期位置のy座標と見本のy座標が異なっていたため、コスチュームが変わらないというのでしばらく悩んでいました。上記の「ジャンプしていないとき」というのをどこで判定しているかというヒントで、気づくことができました。 横スクロールの導入についても、熱心に取り組めていました。', '【小技】簡単な横スクロール② 完成版 クローンを使う', 'タイピング: 普通のタイピング練習をした後、一文字の連打をして楽しんでいました。
盛り上がり: 本格的なゲームらしいものを作れそうだということに喜んで、熱心に取り組めていました。 ジャンプについての説明も、りょうやくんがわかると思うから、と前置きすると、一生懸命自分で考えて理解しようと頑張っていました。'),
  ('a549208b-e5f5-50fb-8b57-46f591037f28', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-14', '16:30:00', null, '通常 / ボールキャッチゲームを作ろう', '座標の感覚を身に着けるため、ボールキャッチゲームを作りました。動画通りに作ってほしいところはあったが、自由にいろんなところを作り始めてしまうことがあります。それで、作ったことも忘れるので、一度仕切り直してしっかり動画を見ながら作らせました。xy座標の感覚はついてきたのか作り間違えることはなかったです。一動作ごとに見てもらいたい感じだったので、次を表示させることで後半は少しコードで取り込むことができたと思います。', 'つづき', 'タイピング: 楽しそうにやっていました。'),
  ('139de090-900f-59b0-a0ab-a7b2cee17700', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-14', '17:30:00', null, '通常 / 風船ゲーム完成', '早々に動画の通りに作り終わったのでアレンジに入りました。まずは、ダミーのこうもりを風船に近い見た目にして紛らわしくして、ゲームとしての難易度を上げていました。また、素早く動く流れ星を追加して、これを取るとボーナス点が得られるようにしていました。星の動きは風船の動きとだいたい同じでしたが、速さと得点だけ変えないといけなかったので、コードのどの部分がそれにあたるか考えて直すことができました。色々考えながら、ゲーム性の高い作品になるように工夫して完成できました。', null, '盛り上がり: フォートナイトのswitch版がサービス終了することを嘆いていました'),
  ('52d0bce7-c748-5289-885d-46e98772c32c', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-05', '16:30:00', null, '振替 / レースゲーム', '背景をうまく描くためのビットマップとベクターの使い分けについて少し教えたのですが、「今回の背景はこのまま直さなくていいや」とのことでした。「○色に触れたら」でコース上を動かすコードが登場した時、これはどういうコードかなと問いかけると、車の丸部分で当たり判定をしていることを答えられました。これは前回も触れた内容だったのでしっかり身についていることがわかりました。メッセージが何回か出てきましたが、メッセージを送ってから違うスプライトが受け取るという流れを理解している様子でした。途中セリフをタイピングする場所がありましたが、日本語のタイピングを学校で習ったらしく、ローマ字表を少し見ながら打てていました。', '続き', 'タイピング: 楽しくやっていました
盛り上がり: よく集中できていました'),
  ('2379c8fb-9388-5232-af33-38e1dd5b108f', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-05', '17:30:00', null, '振替 / レースゲーム', '「今まで変数を使うときはスコアが多かったけど今回みたいにスピードとかにも使えるんだよ」というポイントを伝えると、少し興味を持ったようで、車のスピード変数を色々な値に変えて動きの違いを見ていました。足し算ブロックと乱数ブロックを使って演算の入れ子を作る場面では一度組み合わせ方を間違えてしまったのですが、どっちのブロックが内側に来てるかな？などと問いかけるとお手本をきちんと観察して修正することができました。また、車がうまく道の上を走らなかったときは一緒に原因を考えたのですが、こうしろうくんが「最初の場所が道の上じゃないからじゃない？」と予想して直してみると当たっていたようでした。', '続き', '盛り上がり: 上手くいかないことがあってもめげずにできたと思います。'),
  ('5b365c8d-62a6-5574-9fce-2ad95b5ddebb', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-12', '16:30:00', null, '通常 / ディズニーツムツム＿special thanksビンゴおじさん', '前回までで解消することができなかったバグを潰していきました。今回のバグでは主にコードの文が一部違っていたり、順序が間違っていたりといったかなり見つけにくい内容が多くあり、発見に時間がかかってしまいました。しかし、その中でもいくつかのバグに関しては本人が自力で見つけることができていたので、同じように調査をして全てのバグを潰していくことができました。', null, 'タイピング: タイピング速度は申し分なく、ミスも少なく打つことができていました。今回は、一つ難易度を上げての挑戦をしていましたが、総合評価としてプラスになっていたのでこの調子で頑張っていければ良いと感じています。
盛り上がり: 自分で間違っている箇所を見つけることができた際には、だから動かなかったのかとしっかり納得して修正することができていました。'),
  ('7b23345f-0174-52fa-b152-8095a2ee4eb8', '7d01236e-620e-5177-a6f4-af325a582aae', null, null, '2023-12-12', '17:30:00', null, '休み（未対象）', null, null, '備考: 体調不良のため欠席。当日連絡。'),
  ('3464e04a-ee09-5af1-8d25-0fe8b1134d81', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-12', '17:30:00', null, '通常 / ゲームのアレンジを考える', '前回で動画の分までは完成していたので、今日は本人の希望でアレンジに取り組みました。 以前のアレンジは、音楽を付け加えたり、手書きでコスチュームを編集したりと、工夫はしているものの、完成度としては幼さのある感じのものが多かったですが、今回はスプライトの追加や画像効果をうまく使ったりして、だいぶスッキリと見やすいアレンジをするようになっていました。 ゲームオーバーの画像効果と音に満足そうにしていたので、公開を提案してみるととても嬉しそうにして、説明もがんばって入力していました。', null, '盛り上がり: 検定合格おめでとうと声をかけると少し笑顔になって何度もうなずいていました。 アレンジが完成したときも、珍しくそうすけくんから、こんな風にしたと話しかけてきました。'),
  ('f5462d45-5d8a-5bd8-b8d0-9bc43beeba75', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-12', '17:30:00', null, '通常 / ラットフォーマー系ゲームの作成の続きをしながら、ジャンプやスクロールの確認', '来室するなり、「検定の賞状きた？」と言ってきたので、楽しみにしていたようです。認定証を渡すと嬉しそうに目を通していました。100点だったことも嬉しかったようです。 授業においては、100点のワクワク感が続いてしまったのか、集中力はイマイチでした。プラットフォーマー系ゲームを作りたいとはいうものの、少し手をつけると、色々なアレンジのスイカゲームを探していました。 今日は手を動かすのはイマイチでしたが、話にはよく乗ってきたので、プレイしているスイカゲームで気になるところを探させて、みずきくんだったらどう作成したり修正したりするか、という話をしました。', null, '盛り上がり: 検定100点が嬉しかったようで、今日は終始ふわふわした感じでした。
備考: Monacaの教科書を渡しました。'),
  ('9cec5301-e617-54d0-9d82-c4e270312b1e', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-12', '17:30:00', null, '通常 / 【Prg】48 おさると仲良くなるゲーム＿定義を使ってRGB系', '基本的には動画を見ながら作成していました。動画内容がかなりボリュームのあるものだったので、作成する量がかなり多くなっていました。作成しているものも基本的なコードは同じにして、それ以外の部分で自分なりのアレンジを取り入れることができていました。動画の再生バーからして来週には完成まで持っていきたい感じでした。本人としても今年中に完成させたいようでしたので、この調子で頑張っていければ良いと思います。', '今回の続き', '盛り上がり: 作品の進み具合がいまいち芳しくなかったときもありましたが、自分で納得のいく内容へと持っていくことができているようでした。'),
  ('9bcceffb-6963-5cf3-b541-9ef333d7055a', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-12', null, null, '通常 / オリジナルの駅員操作盤ゲームの作成続き', '今日はこれを作る！と決めて来室したようで、席に着くなり熱心に作成していました。 作り込みたいところがあったようで、ほとんど手も止めずに作業をしていたので、たまに声掛けをする程度で本人に任せていました。 現在作り込んでいるところ（車両によるアナウンス？）ができたら一度見せてほしいと伝えてあるので、その時点でまた中身の確認をしたいところです。', null, '時間帯: その他
盛り上がり: やりたいことがはっきりしていたようで、ひたすら熱心に作成をしていました。'),
  ('e93b684d-2cc6-5fe2-987f-d2214e0e1af7', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-12-11', '17:30:00', null, '休み（未対象）', null, null, null),
  ('cb98077c-6811-5305-9219-43e399a2c60e', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-11', '17:30:00', null, '通常 / 自作ゲームのバグつぶし', '前回でバグが残っていたので、直していきました。 ジャンプがたまに沈み込んでしまうことを直しました。ジャンプ中にほかの座標移動ができないように、フラグ変数「ジャンプ」とりあえず作ってもらい、まずはジャンプのコードでどこが始まりと終わりなのか探して入れることができました。次に、座標移動するコードに追加条件を加える際に、すぐに「かつ」がでてきて検定の効果があったと感じました。演算の形もどの値が判別できているかわかっていてよかったです。 ほかにも沈み込み帯してはジャンプを強制終了する必要があったため、ジャンプの終わりと気のIの条件をかんがえてもらい、時間がかかることなく答えらえれいたので、変数に対しても成長が感じられた。 以前はバグに対してもバグという認識がなかったので、久々で成長を感じられました。', null, 'タイピング: 依然見た時よりかなり速くなっていました。
盛り上がり: 久々で成長を感じられました。'),
  ('b0a5729e-028b-5f09-a15c-eb295db4642e', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-11', '16:30:00', null, '通常 / 過去に作ったものをよりよいものにしよう', '前回から続きで、まずははじめからと本番を区別するボタンを作りました。メッセージ名が数字で分かりずらかったので、本番が始まるメッセージから名前の変えるよう提案したところ、とても分かりやすくなると感心していました。ボタン作成後の始まりのメッセージのやり取りも迷わず直せていました。 ほかにも「すべて終わった後にボールが表示が残ってしまうこと」や「押したタイミングと消えるタイミングにラグがあること」と気になるところを助言したところ、自分でどこを直せばいいかよくわかってできていました。 ほかにもコンボの仕組みをつくりました。変数の「にする」の中に演算ブロックを入れる形は初めてでしたが、間接的なヒントだけで直截なブロックの支持をせずとも作れていました。 久々に見ましたが、コードの順序の感覚が検定でしっかりと身についているように感じました。', null, 'タイピング: スコアが伸びました'),
  ('225547b0-d07a-5f76-a3bc-dcf6d3a99395', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-09', null, null, '通常 / 基本的なスキルを身に付ける', '基本操作コースの「滑るように動かそう」がクリア出来てスタンプを押したら、ノルマ達成した！という感じでオリジナルゲームに戻りました。 キャッチする側のネコのスプライトが進行方向に向かないと言って右向きと左向きのコスチュームを作成して複雑にしようとしていたので、〇度に向けるブロックを学習しました。右向きは90度というのを見たらすぐに、左は-90度だと即答していました。-90度に向けた時にスプライトがさかさまになるのを回転方法ブロックで直すことを教えると、新しいブロックを覚えた！と嬉しそうにしていました。 上から落ちてきたミッキーのスプライトのコスチュームを変えるのも、コードの中のどこに入れたらよいのか自分で判断してできていました。 コスチューム名も、こちらが提案する前に、ブロックを選ぶときにわかりづらいからと自分で名前を変更していました。', '下まで落ちたミッキーのコスチュームが変わった後、すぐに消えてしまうのではなく1秒くらい見せたいということで、最後に1秒待つを入れましたが、そうすると上にミッキーが戻るのも1秒あいてしまうため、ゲームが簡単になってしまって嫌だということでした。 とりあえず今回の仕様を初級ということにして完成させ、中級モードのときはすぐにスプライトが落ちてくるようにしたいとのこと。（スプライトを複数にするか、クローンを使うか？？） レベルわけのためのオープニング画面も作る気満々です。', '時間帯: その他
盛り上がり: 作成したいゲームのイメージがどんどん明確になってきて、目をキラキラさせて展望を語っていました。'),
  ('3c4980ed-443f-5dfd-b945-fea41e557489', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-09', null, null, '通常 / 基本スキルの習得', '前回、乱数を使ってサイコロのコスチュームを変えるところまではできていたので、今日はこのゲームをもっと作り込みたいという本人の希望に沿ってレッスンをしました。 サイコロの出た目によって、景品が表示されるようにしたいということで、条件分岐の学習をすることを説明してからアレンジに入りました。 ゆうとくん自身は、条件分岐は知っていたけれども1回しか使えないと思い込んでいたようで、サイコロの目の数だけ条件分岐ができるということに驚いて感動していました。 残り時間10分くらいでサイコロが完成し、次回の予告としてチーズを探せをプレイしていました。', '【DKゲーム】02迷路 チーズをさがせ！②邪魔者ver', '時間帯: その他
タイピング: 家で練習してきたようで、先週に比べて薬指、小指のキーを打つのがだいぶ速くなっていました。
盛り上がり: 条件分岐を6つ使って思い通りのゲームにすることができたようで、Scratchはこんなことまでできるんだ！！ととても感激してはしゃいでいました。お父さんにも見せて得意そうにしていました。'),
  ('0347494f-f071-5afd-a3ad-51133370953b', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-09', null, null, '通常 / prg', '最初はロブロックスで遊んでしまいましたが、今から作るゲームを一度遊ぶとスイッチが入ったようです。リストを使って自分の動きのゴーストを作る練習ということを伝えると理解していました。リストの扱いには慣れてきているようです。全体の7割くらい終わりました。', '続き 動画の15分頃から', '時間帯: その他'),
  ('19ce217d-c4bd-559f-9480-746719c3ad63', '13bd73d0-f535-5291-8362-6712e5cd7384', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-09', null, null, '通常', '家でも少しずつ作成を進めているオリジナルプラットフォーマー系ゲームの続きをやりたい、とのことだったので、せっかく教室に来ても、家にいるのと同じようになんとなく作成を進めるのではなく、今日、教室で解決、完成させたい項目の目標を立てさせました。 隔週のため、教室で何をしているのかわからなくならないよう、プラットフォーマー系ゲームの基礎スキルのプリントを渡し、クリアできた項目に〇をつけ、今日の目標を書き込んでおきました。 今日は背景スクロールの修正、ゲームオーバーの作成、ジャンプの動きの改善を目標にして進めました。 背景は、スプライトの数を変えたら動きがおかしくなったとのことだったので、もともとのスプライト数をもとにしたスプライト名やメッセージ名の整理をさせました。後から見直したときに、自分で混乱しないように、というこちらの提案にも納得していました。 自作のブロックを数十個使ったメロディをメインのコードに入れていたので、定義の使い方を教えました。曲を変えたりするのがやりやすくなると喜んでいました。 定義を学習した流れで、ジャンプの動きにも定義を使用し、だいぶコードをスッキリさせることができて満足そうにしていました。 ゲームオーバーの判定も、「すべてを止める」ブロックの3種類の使い分け、スプライト内での処理と、他のスプライトが絡む処理に混同が見られたため、説明しながら整理しました。', null, '時間帯: その他
盛り上がり: 今日の目標を達成できた上に、コードがかなり見やすくなったので、スッキリした様子でした。'),
  ('0ec8cc87-79b1-51eb-9ff3-f485a29511dd', '24455e07-ae10-5d8a-9760-d5d0616c5de2', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-09', null, null, '通常 / 検定練習', '定義や複雑な入れ子を使った難しい問題でしたが完璧にできていました。合格は余裕だろうからどこまで点を伸ばせるかだねと伝えました。', null, '時間帯: その他
盛り上がり: 検定の本番直前でしたが余裕のある様子でした。'),
  ('0997b523-403c-5376-80b5-8f78b568919a', '1c81b84d-5f96-5b53-ab70-aec64c37c05e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-09', '16:30:00', null, '通常 / 検定３級応用問題８', '基本的にはしっかりと完成させることができていましたが、不等号が反対になっている箇所がいくつかあったので、問題文をしっかりと読んでいければこのようなミスを無くして完璧に作ることができると感じました。時間配分に関しても、余裕を持って完成させることができていたので、見直しをしっかりとしていくことが点数を稼ぐのにも有効ではないかと思います。', null, '盛り上がり: 自分のミスをしっかりと理解することができ、改善方法まで辿り着くことができていたので、納得のいく問題だったようです。'),
  ('3bb0215d-e9bb-5251-bf56-ada2476b27b8', 'f7ea5cce-acab-5005-bd7e-be1de996e1aa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-09', null, null, '通常 / 自由作品、レッスン', 'まずは「先週のゲームで直したいところがあったんだった」と言って、ゲームクリアの画面や上下左右の移動を作りました。その際に座標の復習をすることができて、x座標とy座標の違いを思い出しました。 次にゾンビをたおせを勧めると興味を持ってくれました。先週作ったのに少し似てるねと気づいていましたが、あれはゾンビから逃げるゲームだけどこれは倒すゲームだよと伝えると納得して作り始めました。レッスンの動画を見ながら最初の方だけできました。', '続き', '時間帯: その他
タイピング: 体力が足りなくて大変そうでした
盛り上がり: 何にでも楽しく取り組んでいます'),
  ('5f4c397f-ce0b-544d-aeda-6528175af397', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-09', null, null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！', '今回で全体の半分ほどまで完成させることができました。本人としてはあまりやりたくないのか、いまいち集中力が続いていないようでした。その結果として、動画の内容を一部飛ばしてしまっていたので、正常に動かないと言うこともありました。しかし、それ以外の箇所についてはきちんと完成させることができていたので、こまめに休憩を挟んでいけばしっかりと作り上げることができるのではないかと感じました。', '今回の続き', '時間帯: その他
盛り上がり: 自分でどこをどのようにしていきたいのかが明確になっていたので、次回で完成させた後に取り入れてみても良いと思います。
備考: 動画 13:39~'),
  ('3efa160f-830b-5644-adcb-a72125fbefc0', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-09', null, null, '通常 / 新しいゲームを楽しく作成する', '検定の合格については、あまり自信がなかったそうなので、ほっとしたようでした。 今年は今日を入れてあと2回、勉強！というよりは楽しく何かを作ろうと声掛けをすると嬉しそうにしていました。 prgの10～20番台を目安にゲームを選んでもらい、カミナリよけゲームを動画を見ながら作成していました。 さすがに動画があると詰まるところもなかったようで、何度か様子を見ても、問題はなさそでした。 今日は検定明けなので、キリの良いところで自由時間にしても構わないと言っておいたのですが、本人が熱心に、時間ギリギリまで作成を進めていました。', '作成の続きから', '時間帯: その他
タイピング: よくできていました
盛り上がり: プレッシャーがかからない作成だったせいか、最後まで集中を切らさず、楽しんで作成できているようでした。'),
  ('56b66691-71d3-5e72-b9d4-b9e58b0c8378', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-09', null, null, '通常 / ゆるめにprgに取り組む', 'まずはprgのゲームをいくつか遊んでもらい、興味を持ったイライラゲームを作ることになりました。迷路のルートを描くときはけっこうこだわっていました。背景番号や「かつ/または」など紛らわしいポイントもありましたがしっかり認識して作れていました。全体の半分くらい進みました。', '続き', '時間帯: その他
タイピング: 早めに切り上げてプログラミングの方に行きたそうでした
盛り上がり: 検定後の最初でしたが、テーマをゆるめにしたのもあって集中してできていました。'),
  ('e59e6449-81c1-52c7-9cdb-b79cef673ef2', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-09', null, null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！', '今回のレッスンでは動画全体の半分ほどを進めることができていました。集中力はそれなりに続いていてはいましたが、細かいミスがいくつか目立つ箇所があったので、動画をしっかりと見ながらゆっくりとでもいいので作っていくことが大切になってくるのではないかと感じました。そのこと以外はしっかりとこなすことができていたのでこの調子で続けていければ良いと思います。', '今回の続き', '時間帯: その他
盛り上がり: 動画内での解説で自分なりのアレンジを入れたがっていたので、完成することができた際にはアレンジをしてみても良いと思います。
備考: 動画 13:39~'),
  ('140233fa-6dad-5408-9194-f523b9b3239a', '80660755-d846-5cdd-91a4-0ab78fe29034', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-08', '18:40:00', null, '通常 / プラットフォームを行おうと思いましたがそもそもジャンプの応用がやっていないことに気がついたので、そちらを先に行いました。', 'ジャンプ〜の部分はイマイチ忘れているかもと、復習しながら聞いてみると思ったので、一旦応用の方を行うことにしました。ただし、本人ができるという自信を壊したくないので一旦、等速ジャンプで再度変数の使い方と、敵が前から動いてくる動きをやってから背景を動かす〜への流れで持っていこうとしました。 応用編に関してはまだ途中ではあるものの、なんとなくやること、必要なコードは理解しているようで、自力でできるところまでを行ってもらいました。 特に座標に関しては自信もあるためか、サクサクと手が動いていたので、次回も引き続きヒントを渡す&見本を少しみながら、自作してみるという傾向に持って行った方がいいかなと思います。', null, 'タイピング: 今までと変わらず、タイピングスキルも概ね良好でした
盛り上がり: 検定の結果がわかりとても嬉しそうでした！'),
  ('5036c31c-13bb-5f4f-8cc3-c6d3b4a3e803', 'ba35f81b-1e47-577c-9281-81fbdb64e6b9', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-08', '18:40:00', null, '通常 / 横スクロールを作ろう', '最初は、横スクロールの仕組みを考えてもらう際に、こちら側からひと通り説明をしたが、受けごたえは上の空でした。それで、頭が痛く、早退をしたので、まだ、背景を左に動かすところまでしかできてないです。', '横スクロール続き', 'タイピング: 何週も取り組んでいました。'),
  ('5fffb010-8806-5b40-b7e2-ef3352d3b72a', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-08', '17:30:00', null, '通常 / 基本操作コース ピンポン', '途中までは言葉のヒントのみでほぼ自分でコードを作成することに成功（もちろん知らないコードは真剣に聞きながら、コードの紙をみて理解をしていました） 変数ではお約束があるよとの説明をした時も、「だれが主語で、どこに書いたらこのコードはきちんと動くのだろうか？」を頭の中で瞬時に考えられる様子でした。', '基本操作コース０８', 'タイピング: 腕試しー自分でもうまくタイピングできたと思ったのか点数をみて驚いていました。
盛り上がり: 最後アレンジをしてもらったのですが、今まで使ったコードでとのことで、あえて敵を増やして、ランダムに出てくるようにし、球が動かないようにしていました。そのコードがちゃんと動いたときはとても嬉しそうにしていました。'),
  ('eea3a2b2-b5e7-5889-80fb-efb6ebbd4ec0', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-08', '17:30:00', null, '通常 / 風船割ゲームを作ろう', '前回のテニスが速く終わっていたので、少しクローンで動く、風船割ゲームを作ました。乱数の変化で、大きく動きが変わっていたので、そこに驚きを感じていました。クローンと乱数を使ってあちこちに動くので、少し自分でアレンジして範囲を広げて楽しんでいました。絵描き以外は黙々と集中してできていて、今回は半分くらいまで進みました。', '動画9：40～', 'タイピング: 上位35％以内に入っていました。
盛り上がり: 独自キャラの動きを作る作業が細かった'),
  ('0da7c8ba-6a83-5073-9d57-aed200c130f0', '159d4aa3-0014-5629-ba33-6d6088fa522f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-08', '17:30:00', null, '通常 / ダイヤを探せを最後まで作ってみる！', '最初先週のお話から始めて、この時間までは頑張ろうねというお約束のもとダイヤが出現〜から触れたらどこかの場所にいく、変数を作って設定する〜、クリアを出すという部分までヒントをもらいながらも一生懸命やっていました。 途中ヒントを出しても、「ぼくわかんない！」と投げやりになるシーンもありましたが、最後まで作成できたことにとてもご満悦な様子でした。', '新しい単元でキャッチでもいいのかな（やってない系のものので）', 'タイピング: 第二話がやっと全て終わった！とても満足していました！2ヶ月みない間にとても成長していたのが嬉しいです。
盛り上がり: 今日は一生懸命やったんだよ！というアピールがとても可愛かったです。 また、クラスの方も真剣に先生の言葉を理解しようとし、分かった時の嬉しそうな顔がとても良かったです。'),
  ('3853ba9b-dfc9-52e9-a9c3-3255139e04ab', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-08', '16:30:00', null, '通常 / 走り幅跳びの応用でカエルジャンプをどこまでできるか？', '一旦、走り幅跳びがどこがポイントだったのか？を思い出してもらい、〜ではないまで待つってどういう意味だったのか？放物線ジャンプは過去の教材でどのスプライトが出てきたものに使われていたか？（ひよことあるくんジャンプ）だったのでは？などをおさらいしました。 その上でカエルジャンプをやってもらい、走り幅跳びと同じ部分があるよね〜ということを再度認識。 自分でどこまでできるか？をやってみたい！と話していたので、自分でカエルジャンプをどこまでやれるかを試してみることに。ただし最初からは難しいので、今自分がならったジャンプ〜の部分と〜ではないまで待つ〜のコードを最初に使ってから作成してみようと話しました。', '今日の続きから、プラットフォーム系が苦手かもしれないので、少し時間をかけておさらいした方が良さそうです', 'タイピング: Playgram で大会みたいなモードが作成されていて、それを仕切にやりたがって言いました。登録しないと出来なさそう
盛り上がり: 拓也くんと一緒にやっていましたが、やはり古くからやってきたプライドもあるのか、質問に自分から率先して答えていた様子は、とてもプログラミングを一生懸命学習した！という自信があるように見えました。実際座標の理解もとてもよくできているので頼もしいです。 ただ掛け算系になるとマイナスの部分などが出てくるため、ちょっと戸惑う部分もありました。拓也くんと同じように同じコードを使ってやってみようということも時間がかかりながらではありましたが、しもくんに質問を途中でしながらできていた様子でした。'),
  ('54d89b50-05ee-51aa-8e11-ebf4bed07123', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-08', '16:30:00', null, '通常 / 検定で習った変数の使い道の復習', '変数による場合分けが多用されているあっち向いてホイを動画を見ながら作りました。変数は得意げだったので、止まらずに作っていました。仕組み自体内容を尋ねても、答えられていたので、検定のことがしっかり身に就ていいると思いました。 ただ、このコードの作成がスムーズにやっても時間がかかるので、途中でやめてもいいかもしれません。', '検定練習の合間にリストの学習をしていたので、リストを使うゲームもいいかもしれません', 'タイピング: 集中してました。'),
  ('1fea1270-dc8c-5721-9ea1-d6309adbc0fb', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-08', '16:30:00', null, '通常 / 走り幅跳びの応用でカエルジャンプをどこまでできるか？', '一旦、走り幅跳びがどこがポイントだったのか？を思い出してもらい、〜ではないまで待つってどういう意味だったのか？放物線ジャンプは過去の教材でどのスプライトが出てきたものに使われていたか？（ひよことあるくんジャンプ）だったのでは？などをおさらいしました。 その上でカエルジャンプをやってもらい、走り幅跳びと同じ部分があるよね〜ということを再度認識。 自分でどこまでできるか？をやってみたい！と話していたので、自分でカエルジャンプをどこまでやれるかを試してみることに。ただし最初からは難しいので、今自分がならったジャンプ〜の部分と〜ではないまで待つ〜のコードを最初に使ってから作成してみようと話しました。', '今日の続きから〜、プラットフォームあたりはまだきちんと再度説明していない、背景が動く動きもおさらいしていないのでそこの部分を確認した方が良さそう。', 'タイピング: いつも通り集中して行っていました！
盛り上がり: 自分で作品を作りたい！と話していたので一定に覚えたら使ってみたいという気持ちがとてもあって良かったです。'),
  ('c63f963b-dc89-5045-80bd-e256d086f205', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-08', '17:30:00', null, '通常 / ツムツムの基礎的なことを知ろう', '前回作ろ気になっていたので、まずはリンゴキャッチから導入していきました。落ちる位置のランダムは得意げに作れていてよかったです。そこから、本文のコードを作り始めると、まだ習っていない「リスト」が出てきてかなり難しい顔していました。それで、なかなか手が進まなかったので重力のコードを作られせて、リンゴキャッチと放物線のコードを比べて、どこが対応しているか考えてもらいました。大体はどこに対応しているか見れた。 ただ、ケイト君にはコードが難しく感じていたので、お題を変えてもいいかもしれません', null, '盛り上がり: 本人的には検定ギリギリな感じしていたが、喜んでいました。'),
  ('0f0dee91-6977-53aa-839e-365f5c583797', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-08', '16:30:00', null, '通常 / 前回の続き走り幅跳び、ジャンプがではないまで待つ〜の部分のコードの追加とジャンプの考え方の復習', 'ではないまで待つ〜のコードをおさらいする際にジャンプも関わっていたので、どこまでなにをやっていたか？を最初に確認。 ジャンプ系の変数の使い方が怪しかったのでもう一度等速ジャンプ②からおさらいし、その上で、〜ではないまで待つ〜のコードがどう反応しているのか？を丁寧にみていきました。 結局動画自体を見ることになったのですが、ネットワークトラブルがあり、うまく最後まで進まず。次回も〜ではないまで待つ〜のコードを移すところから走り幅跳びの作品作成です。', '今日の続き、連打しないと動かないという部分を作成する', 'タイピング: 今日はタイピングをいっぱいやりたいと話していたので、20分ぐらい？タイピングをひたすら行っていました。上位2％の順位になるまでとても頑張っていたので、本人的にはタイピングが唯一の息抜きみたいな感じになっているのかなと思います。
盛り上がり: 今日はいっぱい自分のやりたいことができたのが嬉しかったのか、最後まで集中して行っていました。途中色々な話をしながらだったのもとても良かったのかもしれません。'),
  ('b914916f-6cdc-5976-9c50-098be23d6797', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-02', null, null, '通常 / うさぎとわしのレースゲーム', '今日は検定前なのでレースゲームで一旦、新しい項目をやってみることに。 変数の使い方を一回おさらいし、それまで得点、タイムのみでしか使ってなかった変数を順位を測るやり方を今日はやるよと伝えて行いました。 すこしずつ、自分がわかる範囲内で順番にやってみよう！と伝え ①動き ②ではないまで待つ〜の使い方 ③ゴール判定 の３段階に分けて行いました。 ゆうかちゃんと共にやっていたからか？どちらかがわからない、などの質問があったときに私も同じ質問でした〜的な感じになっていたので、２人は相乗効果でプログラミングのスキルを上げているのかな？と思いました。', '来週は遊びでもOKかなと思います', '時間帯: その他
タイピング: なし
盛り上がり: とても細部までこだわる性格なのか？動きの部分を意地でも自分で解きたい！という真剣さがとても印象的でした。最後少し時間が余ったのでアレンジを提案したときに、画面上でざっくり作ってみるというよりかは、ある程度自分の頭の中でストーリーを作り、論理がここのスプライト同士で互換性ができるのか？方にとても重きを置いていた様子でした。（なのでアレンジ自体はあまり進んでいなかった） そういう意味では、とても自分で納得する部分をプログラミングに反映させることに対しての真剣さが良かったと思います'),
  ('d1644bde-d981-5931-9f19-d72462f1a01d', 'abc1bbf6-2784-5c1a-b118-79473c1bb4e1', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-02', null, null, '通常 / うさぎとわしのレースゲーム', '今日は検定前なのでレースゲームで一旦、新しい項目をやってみることに。 変数の使い方を一回おさらいし、それまで得点、タイムのみでしか使ってなかった変数を順位を測るやり方を今日はやるよと伝えて行いました。 すこしずつ、自分がわかる範囲内で順番にやってみよう！と伝え ①動き ②ではないまで待つ〜の使い方 ③ゴール判定 の３段階に分けて行いました。 夏目ちゃんと共にやっていたからか？どちらかがわからない、などの質問があったときに私も同じ質問でした〜的な感じになっていたので、２人は相乗効果でプログラミングのスキルを上げているのかな？と思いました。', '来週は遊びでもいいのかなとおもいます', '時間帯: その他
タイピング: なし
盛り上がり: ゆうかちゃんは、動きの部分が特に理解が最初はできなかった感じではありましたが ボタンを押してないときを判定させないといけないんだよ〜と伝えたら、8割理解していたようでした。また最後ゴール判定を自分なりに変数をうまく使うことにできることに感動していたようでした！'),
  ('cfa34f68-fc4d-57d8-8a07-ff960b47021c', 'd7c19f87-12d8-5c24-80ff-7d368916511c', null, 'fcc37942-b380-5ce8-afdb-ddacfba389d2', '2023-12-02', null, null, '通常 / 【Prg】51 どこまでいける？ネコのお散歩ゲーム」をやってみる', '最初にどの部分を自分で覚えているのか？どういうゲームでPRG５１と同じようなコーディングがあったのか？を思い出しながら自分で途中まで作品作成してみることに（動画をみると結局遊んでしまうので） ジャンプゲームでの部分を思い出して背景が上から下へと動くことを自分なりに作成してみました。ただ全てがわかるわけではないので、一定部分は移すことをし、始まりのコードがこのコードであれば、他のメッセージを受け取る側のコードはどうなるか？などを一緒に考えてみました。', 'Java Script?か今日の続き〜', '時間帯: その他
タイピング: なし
盛り上がり: 座標の部分は概ね理解ができている様子でした。また猫ちゃんが動く動きも左右のボタンを押した時に方向が変わることにもキチンと着目できていました！一緒に何かを作るというスタンスの方が集中力が増して勉強する気になるので、動画を見せることよりかは、最初に一緒に考えてその後に動画をみるというスタンスの方がいいのかな？と思います'),
  ('49d983bc-2b11-5297-8fd7-25142335432e', 'ddd2f217-f446-50ce-a6a2-aed572a67c0b', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-02', null, null, '通常 / プラットフォーマーゲームの作成', '軽くスキルを復習し、アルくんがライフル弾をよけるという方向で作り始めました。最初弾の動きを一から作ろうとしていましたが、「弾の動きって背景の動きになんとなく似てない？」とヒントを出すと、クローンを使って自然に動かせました。アルくんのコスチュームを変えて走っている風にすることや、ゲームオーバー・クリアの画面を表示することもできて、少し手慣れた感じで完成しました。', null, '時間帯: その他
盛り上がり: いつもよりは脱線が少なかった気がします'),
  ('1692fe84-a93f-58dc-9d49-926cfafb4650', '5eab28ff-2a8c-5093-a246-bcdd45e941fa', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-02', null, null, '通常 / モンスターハント', '違った変数の使いかたを覚えてもらいました。作成途中、「コスチュームをランダムに変えたいんだけどどうすればいいかわかる？」と聞きましたが見当もつかない感じだったので、コスチューム番号を変数にしてみようとヒントを出し、変数はスコア以外にも使えるということを共有しました。その後、その変数に乱数を代入すればいいことは自分でわかり、乱数の範囲もきちんと設定できていました。また、触られたらゆうれい効果で消えることに気づいて再現しようとしていましたが、一気にゆうれい化していたので、段階的に薄くするのと動きを止めるのもやってもらいたいです。', '続き', '時間帯: その他
盛り上がり: よくわからないと言いつつも一緒に考えるとわかったりしていました。'),
  ('5ad53909-4b3b-52e4-a2dd-8a0a15856fd0', '0dd06faa-d9b2-50a3-a2d8-30740f1484cf', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-07', '17:30:00', null, '通常 / 風船割ゲームを作ろう', '最初は動画を見ずに作ろうとしましが、なかなかイメージ通りに作れず、動画を見て補うようにしました。でも、その段階で基礎的な動きはできていてよかったです。動画見て霧のいいところまで作り上げると、判定が上手くいかない所があったので、探しましたが、音の終わるまでになっていて判定が遅れていただけでした。そこをじっくり見直して見つけられてのは良かったです。', '動画11：11～', '盛り上がり: 残った時間で、本棚の本を読んでいました。'),
  ('0abe19d0-9b4e-5fd3-9057-23a15770a13c', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-07', '17:30:00', null, '通常 / 検定対策', '淡々と解いていて、終了5分前くらいに、「ここのコードの正解がわからないので動きがおかしい」と申し出てきました。 「作ったものに注文のリスト番号番目が含まれるではないなら」というところで、「含まれる」が抜けていたようでした。 問題文が複雑で、見落としてしまったとのことでしたが、間違えた理由や間違えた箇所、それによる全体の動きへの影響もきちんと自分で把握できていました。', null, '盛り上がり: 今日の問題も、1か所以外はよくできていたので、自信もついたようでした。 前回の2級の結果を渡したら、熟読して嬉しそうにしていました。'),
  ('da1d22be-da73-5c37-8c8c-f45336b04af9', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-07', '17:30:00', null, '通常 / 変数の使い方の違いを見よう', '最初は外で遊び疲れてぐったりしていたが、ゲームを少しして、レースゲームを作り始めると、とても集中して作りました。セリフの打ち込みが多かったですが、タイピングもそこでうまく進んでいました。色から色の判定は初めてだったので、目新しく扱っていました。', '動画7：44～', '盛り上がり: 検定の結果を早く気になっていました。'),
  ('41bcf09c-92e5-5415-84cf-1a1bcf00a43a', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-07', '16:30:00', null, '通常 / 変数の使い方、色判定の使い方', '動画を見て熱心に取り組めていました。 セリフやメッセージ名の入力なども、当初は面倒と言っていましたが、今日は「ローマ字を習い始めたから」と言って、なるべく見ないで打ってみたりと、努力する姿勢が見られました。 プレイヤーとライバルのスピードの変数が少し混同してしまっているようではありましたが、動画に素直に、授業終了まで頑張っていました。 変数の使い分けについては、また何度か復習をしてやりたいところです。', '動画7:52から', 'タイピング: ローマ字を習い始めたそうで、丁寧にやっています
盛り上がり: 酸っぱい飴を食べてはいそいそと作成に戻る、の繰り返しでした。 結果的に集中時間はいつもより長く頑張っていましたが…'),
  ('6496769d-5f34-543f-8b51-1354af5d08e2', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-12-07', '16:30:00', null, '通常 / キャッチゲームを作ろう', '検定明けだったので、ゆるく基礎のキャッチゲームを作りました。座標感覚はだいぶ慣れてきたので、手を止めることなく、作ることができました。それぞれのコードに対して、いう前に初期化のコードを作れていたので、大会、検定で創作感覚が身についていることが感じられました。', null, '盛り上がり: アレンジも独特な絵柄も面白かったです、'),
  ('c4325412-e80f-5dc8-8184-8af0b4c60f8c', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-07', '17:30:00', null, '通常 / ディズニーツムツム＿special thanksビンゴおじさん コードを読んで理解しながら進められるように', '前回の続きをしました。途中、定義の中で引数を使う場面がありましたが、あまり深く使い方を理解していなかったようなので、引数について説明しました。つなげる部分の解説を丁寧に読めていたところが良かったです。 一通り資料を読んで取り組んだようです。最後に玉が上にいってしまったりうまく消えなかったりしていました。リストの働きや重力のプログラムの意味について資料を見ながら一緒に考えた後、もう一度見直しをしてもらいました。 かなり改善されましたが、まだうまく消えないので、来週再度取り組みます。', null, 'タイピング: 投資額の2倍ほど食べていました！！'),
  ('092424fa-461f-5241-a403-3b836f4e292f', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-07', '16:30:00', null, '通常 / 基本操作コース_04_ゆうれいから逃走 スコアが10点に達したら「YOU WIN」のスプライトを表示させるところから。できたらアレンジ、または、えみちゃんと同じ教材に進んでも', '前回の復習をしましたが、本人が言っている内容とプログラムの中身が大幅に違ったので再度復習をしました。スコアを10点にして背景を変えている部分を自分で発見することができず、残念でした。プログラムを後から見直すのがかなり苦手な様子です。背景の初期設定ができていなかったのですが、伝えても気がつくまでにかなり時間がかかりました。 スプライトを表示するときも、今まで自分がやってきたことをなかなか思い出せないようでした。表示させるときは自分で手を動かせていたのでよかったです。 最後に迷路チーズをさがせ！を遊んでもらいました。', null, 'タイピング: 集中して取り組めました。'),
  ('b354da75-3106-5478-abb5-014857a24897', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-12-07', '16:30:00', null, '通常 / 【DKゲーム】02迷路 チーズをさがせ！②邪魔者ver 乱数の習得、壁にあたった時の動きを考える', '初めにミミの動きのプログラムを作りました。条件分岐をつかってしっかりプログラムすることができました。角度は苦手なようです。チーズの動きを作るときに「もし」を使っていたのですが、「まで待つ」を使うように伝えると自分で書き換えることができていました。ばっちり。 乱数の使い方は忘れてしまっていたようです。いくつか具体例を使って説明しました。スコアも丁寧にプログラムできていました。次回は虫の動き、幽霊の動きを作っていく予定です。', null, 'タイピング: ミス率とタイピングはやさのバランスがよかったです！'),
  ('4b032af1-4c72-54b8-ad0f-786fee9bec85', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, null, '2023-12-07', '17:30:00', null, '休み（未対象）', null, null, null),
  ('5c39c6c2-970c-5fac-b8c0-b0d578f67914', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, null, '2023-12-07', '17:30:00', null, '休み（振替対象）', null, null, null),
  ('edb490bb-9a4d-5768-9c89-a78089821732', '7d01236e-620e-5177-a6f4-af325a582aae', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-05', '17:30:00', null, '通常 / 【Prg】21 アイテムで脱出ゲームを作ろう！', '動画を見ながら作成していきました。△△△かつ△△△のスキルの習得や、コスチュームの名前で条件設定をしていくなど新たなスキルを覚えながら作成していきました。内容としての理解はきちんとすることができていました。新しく出てきた部分に関しては、少し戸惑うところもありましたが、ちゃんと覚えて作ることができていました。今回で動画の半分ほどまで完成させることができたので、次回で完成させられると思います。', '動画の続き 13:27~', '盛り上がり: 作成をスラスラと続けていくことができ、順調に進めていくことができていて本人も特にわからない箇所もなかったようなので、きちんと理解しながら作っていくことができていました。'),
  ('65c5ec5a-7166-50a0-b1ed-3248d2c09955', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-05', '17:30:00', null, '通常 / Scratchの楽しさを思い出す', '検定で疲れたようだったので、今日は好きなゲームを選ぼうというと、久しぶりに嬉しそうにしゃべりながら「これにする」とカミナリゲームを選んでいました。 動画を見ながらの作成になりましたが、今日は机の下に沈むこともなく、熱心に取り組めていました。途中で動画通りの動きにならないと一瞬ぐだりかけましたが、繰り返しのコードを見直すように伝えると、数値の半角全角違いに気付いて解決することができました。 今日は、疑問点や要望があると、きちんと手を挙げて目を合わせて質問をしたり、こちらの了承を得たりすることもできていました。', null, 'タイピング: さっさと済ませて、プログラミングに切り替えていました
盛り上がり: 久しぶりのゲーム作りが楽しかったようで、レッスン中や退室時の態度もとてもよかったです。
備考: 応用課題に入ってからの試験対策期間はぐだぐだした態度も多かったため、ご両親も気にされていたようで、今日もお父さんが心配そうに、レッスン中の態度について聞いてこられました。 今日はとても集中できていて、態度も良かったことを伝えると、安心したようでもあり、試験前の態度について困ったようでもありました。 今日は帰りがけのそうすけくんの顔を見てすぐに察しがついたようで、御礼を言って帰られました。'),
  ('a8a7e37b-ec8d-511d-8c94-d9c2d26957c2', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-05', '17:30:00', null, '通常 / 定義や変数の活用', 'ゲームをプレイしてもらってから、この教材で何を勉強してほしいのか（定義や変数を使って、選択肢によって結果を変える）を説明すると、興味深そうに聞いてくれました。 基本は動画を見ながら進めてもらいましたが、作成していくうちに色々とアイディアが湧いてきたようだったので、アレンジOKをしたところ、とても熱心に取り組めていました。 定義や変数についても納得のいく使い方だったようで、特に悩むこともなく進めることができていました。', '続きから', '盛り上がり: コンテストや検定が終わって久しぶりの作品づくりになりましたが、楽しんで取り組んでくれているようでした。お話系が得意なはるちゃんなので、性に合ったようでした。'),
  ('71727ea3-668e-5ce0-ba57-41704fe0c1ee', '5c9bb4b1-2f4b-5e1e-9f34-bcc4d0dea21a', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-05', '17:30:00', null, '通常 / 【Prg】47 シュンカンきおく順番当て演算＿変数＿定義を使って場合分け', 'お手本のビデオを見ながら作成していきました。制作は特に詰まるようなこともなく順調に作成していくことができていました。今回のレッスンで動画の半分ほどまでは作ることができていたので、次回で恐らく完成させることができると思います。今回の作成したプログラムの肝である部分までは辿り着くことができていなかったので、次回でもしかしたらつまづいてしまうかもしれません。', '動画の続き 16:53~', 'タイピング: スコアは高い位置で安定しているのですが、ミス率が少し目立ってしまっているので速さよりも正確さを重視して挑むとさらに成長できると感じます。
盛り上がり: 作成はかなり順調に進めることができていて、自分でも内容をしっかりと理解することができていたので満足していました。'),
  ('ece4283a-0892-5354-915d-fc8bc3303abb', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-05', null, null, '通常 / 外部データとリストを活用した作品づくり', 'Monacaの教科書P117 に、曜日をすべて条件分岐で書く方法と、リスト化して書く方法の解説が載っていたので、それを見せてから、なぜScratchでリストをしつこくやっているのかを説明しました。素直に聞いてくれていましたが、都道府県クイズの教材はやったことを覚えていたので、とりあえず自分の作品を勧めさせました。 400ある新幹線の号数によって対応する番号を取り出したいというところで、珍しくひいろくんからヘルプがありました。Scratch画面でその数のリストを入れていくのは大変なので、都道府県クイズの時のデータのようにメモ帳で入れようとしたらしいですが、それもかなり大変だと実感したようだったので、Excelの連続データの入れ方を教えました。連続データが入れられるのは知っていたけど、やり方はわからなかったのと、Excelで作成してよいのかどうかがわからなかったとのこと、Excelで作成したデータをテキストデータとして保存する方法を説明し、本人も納得できたようでした。 Excelのデータをcsvとしてエクスポートし、Scratchに取り込むところまで、無事に終えることができました。', null, '時間帯: その他
タイピング: レッスン前に、一人でさくっと終わらせていました
盛り上がり: Excelでの連続データや、範囲の一括選択などを教えると、楽しそうに実践してくれました。'),
  ('6c5decc6-cff3-5e52-99fa-26ee0abb90c2', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-05', '17:30:00', null, '通常 / プラットフォーマー系ゲームの作成', 'これまでに作成していたスプラトゥーン風ゲームについては、一度寝かせておくと言うことでしたので、代わりとして作りたいと言っていたプラットフォーマー系ゲームを作成していきました。検定にも合格することができたので、やる気はいつもよりも少し高いように感じました。これまでに覚えてきた内容を使っての作成となるので、より高度で完成度の高いものを作成したいと言っていました。', null, '盛り上がり: 本人の中でも現在はかなりやりたいことの部類に入っているようなので、このまま完成まで作成していきたいと言い、頑張っていました。'),
  ('c5d656aa-ec56-500b-9944-e67151896704', '6622be5f-a49f-55dd-9618-72f5e9f04ab3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-05', '16:30:00', null, '通常 / 新しい変数の使いどころ、色に触れたら判定を使いこなす', '今回の課題で何をマスターしてほしいかを説明してから、動画をスタートしました。 最初の5分間くらいは、動画を見つつ、先生にもそばにいてほしいという感じで、動画を止めては一緒に作成する感じでしたが、慣れてきたら自分で進められるようになりました。 途中で席を立つこともなく、最後まで良い姿勢で、とても集中して取り組んでいました。 動きがおかしかったら、自分で動画を少しさかのぼって見直したりすることもできていました。', '動画の10:32から', 'タイピング: まじめに取り組んでいました。
盛り上がり: ゲーム自体にも興味が持てたのか、一人でとても集中していました。できたところまでをお父さんに見せて、得意そうにしていました。'),
  ('6f2f434d-1f09-599e-934f-dd04f54fdd50', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-05', '16:30:00', null, '通常 / ディズニーツムツム＿special thanksビンゴおじさん', '主に完成したもののデバッグ作業をメインとして行いました。しかし、一部のバグは解消されましたが、完全には解消することができなかったので次回に持ち越すと言う形になりました。本人も内容についての理解自体はすることができていたので、色の数値ミスなどでのバグでしたので、次回以降で洗い出せると思います。', null, 'タイピング: お手軽難易度で常に1000円以上の利益を出してクリアすることができていたので、次回以降はより難易度の高いものに挑戦してみるのが良いと感じました。
盛り上がり: 一部ではありますが、バグを発見してより完成へと近づけることができたので、次回で完成させようと張り切っていました。'),
  ('9b7816d2-6e3c-5881-8dc1-06fdcacf9e83', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, null, '2023-12-04', '17:30:00', null, '休み（未対象）', null, null, null),
  ('f3fa5f87-12db-5c18-9f13-0820e4ef345b', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-04', '17:30:00', null, '通常 / 自作プラットフォーマー系ゲームの作成続き', 'ジャンプしたときに、せっかくトラックモードや飛行モードになっていたのが解除されてしまう原因と対策を考えました。 ジャンプのときにコスチュームを変えているため、どのモードになっていても、ジャンプを降りるときのコスチュームに戻ってしまうことに気付けたため、そのときのコスチュームによって動きを変えられるような条件分岐を考えさせました。 HPの変数を作成し、ゲームオーバーが作れるようにしました。 いずれの時点においても、直したいところ、やりたいところはあるのですが、どこから手を付けるのか考えると難しくなってしまって、「もうこのままでもいいかなあ」とくじけそうになる様子が見られました。 こちらで「そこを直すにはどのスプライトのコードを見直すか」「該当するコードはどこか」「どんな動きが問題で、それをどういう動きに変えたいのか」と発問していくと、ほとんどヒントはなくても素直にコードを見直して直すこともできていたので、問題への取っ掛かりに自分で気づけるかどうかがポイントなのではないかと思われます。', 'ゲームオーバーの作成、トラックでジャンプしたときに下に沈んでしまう現象の解決', 'タイピング: 授業前と授業後に挑戦し、授業後に100店が取れたことをとても喜んでいました
盛り上がり: 面倒がっていた問題を、こちらが答えを教えずに解決できたときは、満足そうにしていました。'),
  ('527d1d78-269e-5444-82c9-d11ea9421f1a', '7e081f4d-10b0-5bec-8462-c253ef64a932', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-04', '16:30:00', null, '通常 / 好きなゲームを作ろう', 'プラットフォーマー系ゲームの続きを勧めたところ、1年前に作成しいていた作品が今なら作れるかもしれない、とのことで再チャレンジすることにしました。 作成途中のゲームを振り返ってみて、今日の目標を「音を入れる」「スコアをつける」「コンボをつくる」の3つに定めました。 右からボールが出てくるときに、次のボールが見えてしまっているのに悩んでいたので、「繰り返し」の中のコードが順序通り実行されることを強調して説明してみました。そこで、「表示する」と「隠す」のタイミングがおかしいことに自分で気づき、ブロックの順序を入れ替えることで想定通りの動きを作成することができていました。 ボールが出てくるタイミングに乱数を使用したことを嬉しそうに報告してくれたので、ボールのスピードも一定ではない方が面白くないかと提案したところ、とても喜んで、いそいそと追加をしていました。変数の範囲をいくつか試しては、楽しそうに検証していました。 オープニングのチュートリアルを丁寧に作っている分、ゲーム部分の検証が大変そうだったため、いずれ開発者ボタンの作り方をやろうと予告しました。ヒロト君も納得していました。 「コンボを作る」以外はかなり思い通りに進めることができたと喜んでいました。', 'コンボの仕様を考えて作成する予定', 'タイピング: まじめに取り組んでいました。
盛り上がり: 1年前には、この先どうしてよいかよくわからずに放置してしまった作品が、今の自分の力でどんどん完成に近づいていくのがとても嬉しそうで、とても集中して取り組んでいました。'),
  ('c9f1dd46-0e28-593c-b955-8c426471968f', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-02', null, null, '通常 / 基本のブロックを習得する', '前回の続きから作成しました。 やすのりくんなりのイメージ映像があるようで、それを形にしようと頑張っていました。 アリエルの動きや音楽にこだわって作成していました。 時間のカウントダウンについては、自分で考えて、「変数に数を挿入」と1秒待つを10回分つなげて作成していました。思い通りのカウントダウンができたようで、本人は喜んでいましたが、次回以降どこかで、くりかえしと演算式を使ったカウントダウンを教えたいところです。', null, '時間帯: その他
タイピング: ストーリーを熱心に進めていました
盛り上がり: 思っていた映像が形になったようで、とても得意げにしていました。'),
  ('ce4ab9a9-51fb-559f-a789-31ef6ceabddf', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-12-02', null, null, '通常 / バグの探し方と修正、乱数の使い方の確認', '家でやりかけたスプラトゥーンゲームのバグ探しをして、それを直したいとの本人の強い希望で、予定していた教材を変えてレッスンしました。 本人の希望だけあって、熱心に授業に取り組んでいました。現状起きているバグをどうしたいかということも、自分の言葉で丁寧に説明できていました。 条件分岐の見直しで、ほぼ解決できました。 完成したゲームをこうしろうくんがプレイしてくれてとても嬉しそうだったため、ゆき先生の許可を得て公開いたところ、おおはしゃぎでした。 残りの少ない時間でも、何かを進めてみたいということだったので、乱数の復習にサイコロを作成させました。口頭の説明だけで、あっという間に作成できていました。', null, '時間帯: その他
タイピング: 指の位置を覚えたいというので、ホームポジションを教えました。間違いが続くと少しキレそうになることもありましたが、頑張って自制して、正しい指で打とうと努力していました。最後の当たりでは、キーによって打つ指を守ることができるようになってきていました。
盛り上がり: 自分の作ったゲームを誰かがプレイしてくれるのがとても嬉しそうでした。教室内で公開できるということも、とても魅力だったようで、モチベーションが大いにアップしたようでした。'),
  ('d735bc24-9e3e-5839-b59d-f223af370ff1', '2c3118a3-8fac-57f0-94a9-f1b5198eede4', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-12-02', '16:30:00', null, '通常 / レースゲーム', 'まずは見本通りで完成させるという目標を改めて共有し、prgの動画を見せると集中して取り組めました。スプライトを用意するときに、コスチュームを必要以上にいじったりなどという脱線もあまりありませんでした。ゲームスタート時にメッセージを送るところは混乱せずにできていて、何種類かの変数を使い分ける場面でもきちんと区別できていました。 今回はレース開始するところまで終わりました。', '続き', '盛り上がり: 本人と親御さんとの話し合いで納得できる結論に至れたようです。'),
  ('3aa789cb-8865-5f03-b8c0-920efd0d1653', '8870ed92-6ea8-58d6-ad08-17acd6fabff5', null, '77143ef8-5bef-5f62-8043-9bbd1cf3724f', '2023-12-02', null, null, '通常 / 新しいスキルに挑戦という意識を持ってもらう。 ①変数の違った使い方を知る ②色を使ってコントロール ポイントがたくさんあるので、ひとつづつ新しいコードだと伝える', '【Prg】10 レースゲームを作ろう！のゲーム説明にポイントが書いてあるので、2つの新しいスキルを意識してもらう。 最初に、車がどうやって動いているか聞いた。すぐにはわからなかったのでヒントで「色」というと、なんとなくわかった様子でした。 その後、動画をみながら車のレーンを書いていく作業に。 その途中で、車のバンパー部分に丸い色がついているのを発見し。「これ、なに？」と聞いてきたので。GoodQuestionだよ～～と。この●い色が「レーンの色」を追いかけて、ゴールの色に触れるとゴール判定だね、と説明すると非常に納得した様子でした。最初にこの仕組みに気づいて凄いね！と伝えるとちょっと自慢気な雰囲気がかわいかったです。 背景のコスチュームで黒いレーンを描いている途中までで終わり。今日は「眠い」を何度か呟いていたので、少し早めに息抜きタイムに。学校で学芸会があったそうで、お疲れだったみたい。 ⇒コスチュームについて、「次回の予定」に記入', '後半は黒いレーンをコスチュームの筆で描いていましたが。途中で「ビットマップ」になってしまったので、レーンを動かせなくなったりして、ちょっと残念になりました。 今日、人数少なくて余裕があったら。 別の画面でコスチュームの描き方、各ツールの使い方やビットマップとベクターの違いを教えてあげたいところです。', '時間帯: その他
タイピング: 余裕がなくて、みれてないです
盛り上がり: 久しぶりにお父さんがお迎えにきて、私と話をしていたのを聞きながら。頑張っているね～という内容だったので、嬉しそうでした。このところ、わからないところや質問を言葉に出せるようになってきていると、お父さんにもお伝えしました。'),
  ('85b0cb02-ffc1-5a0f-a598-37053a54041c', '0b4f4d38-2ec6-5e28-9961-5491c719f7c2', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-01', '17:30:00', null, '通常 / 【Prg】26 ウェイトリフティングゲームを作ろう', '今回のレッスン内容は本人にはあまり合わなかったようで、それほど進めることができませんでした。恐らく、やることが増えているのでコードがだんだんと複雑化しておりどのコードがどの動きをする、どのコードがこのコードへ繋がるのかなどを考えるのが嫌になっていた様子でした。', null, '盛り上がり: 自分で考えることを諦めていたので、動画を見ながら作成していても手が止まることが多かった印象です。'),
  ('082bdc85-edb0-5b52-bf1e-c35c9c48e508', '0ef6dd41-b9d5-5158-a931-5168cf3732e1', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-01', '17:30:00', null, '振替 / 【Prg】39 テニスゲームを作ろう！', 'テニスの内容に関しては終わらせることができて、キャラクターや敵を大きくしたり色を変えたりと様々なアレンジをして遊んでいました。元々アレンジしたがっていたこともあり、アレンジ中は既に考えていたアイディアを次々と作品に取り込んでいました。', null, '盛り上がり: アレンジ中のやりたいことをやっているので楽しいという気持ちが見てとることができました。'),
  ('e24eb195-8d8e-554a-a01c-4924dced20aa', 'f434e370-6d28-504f-939a-9942f6e8c7db', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-01', '16:30:00', null, '通常 / 【Prg】39 テニスゲームを作ろう！', 'テニスゲームの内容はそれなりに長いコードでしたが、動画を見ながら作成していた結果つまづくこともなくかなり早く完成させることができていました。完成後はそのゲームで遊んでいたり、さまざまなアレンジを加えて試行錯誤しながら納得のいく内容へと仕上げていました。', null, 'タイピング: 寿司打の金額をプラスにすることができていたので、タイピングの速さと正確さはとても高いと感じました。なので、次回以降はノーミスを目指してタイピングをしてみるのもいいと思います。
盛り上がり: コードをアレンジしてオリジナル性を持たせた作品にしようと色々なものを試して、楽しそうに挑戦していました。'),
  ('6d2383d9-3342-598c-ac4f-5e9294d95983', '0c1b282c-7edd-5964-8fd3-ff04de739d24', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-01', '16:30:00', null, '通常 / 【Prg】23 走り幅とびゲーム', '今回作成していた内容の7〜8割ほどは完成させることができていました。動画の画面が小さく見にくいということもあり、作成はゆっくりと行っていました。それでも大体の部分は完成させることができているので、次回以降ですぐに完成させることができると思います。', null, 'タイピング: 次々と出てくる単語に対して淡々と処理をすることができており、的確なタイピングをすることができていたのでかなり早い速度で処理することができていました。長文に関しても、本人の苦手意識もあまりないようでスラスラと鬱ことができていました。
盛り上がり: ゆっくりでも少しづつできてきているのをみて完成に近づいているという実感は感じることができていました。'),
  ('837f00f7-5ba5-5ed8-8d94-06ac69385d1b', '0753cb8b-7237-56d6-b85b-b8fd0d447b9f', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-01', '16:30:00', null, '通常 / 【Prg】23 走り幅とびゲーム', 'レッスンの内容を三人中最も早く終わらせることができていました。内容の理解もなぜこのように動いているのかをしっかりと理解することができており、演算部分に関してもつまづくことなくやり遂げることができていました。', null, 'タイピング: タイピング速度、正確性ともにかなり高く仕上がっていました。文字を考えることなく打つことができているので挑戦しているレベルを一つ上げていっても問題ないと感じました。
盛り上がり: 今日は早く完成することができたので、残りの時間でさまざまなことができて楽しそうでした。'),
  ('936651a2-26b6-5c82-9050-0b390541cc69', 'b875a998-eadb-5208-8d3f-1f87e1701f44', null, '8c273935-fe2d-5dc8-8c41-4c4a03f08ccc', '2023-12-01', '16:30:00', null, '通常 / 【Prg】23 走り幅とびゲーム', '動画を見ながらの作成をしていましたが、動画内の説明でもひっかるような箇所はなくスラスラと作成することができていました。このレベルの問題はしっかりと習得することができていると感じました。', null, 'タイピング: 速度自体は制限時間に間に合う速度ではあったので、正確に打つことを意識して練習をしていくことが重要だと感じました。
盛り上がり: 作品の完成時に途中で詰まることがなかったので、達成感を感じていたようでした。'),
  ('83f4f8e0-8a84-5d17-9e48-34661d8cffe9', '02dd7371-03ef-5a43-ba96-1206a7c43f98', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-30', '17:30:00', null, '通常 / ゆうれいから逃走', '細分化された動きを見せながら進めました。家で飼っているインコをスプライトとして描くのに結構時間を使い、大変だったら近いオウムのスプライトがあるよと伝えましたが、最後まで描いていました。 最初に矢印キーでの移動を作りましたが、x座標とy座標の違いなど、座標の理解はしっかりできていました。逃げる側のスプライトも用意して、ランダムに移動させる方法もわかっていました。', 'ゆうれいから逃走 続き', 'タイピング: 成績がよくなっていました
盛り上がり: 今日は体育などで疲れていたらしく、プログラミングに対する集中が続かずに色々なことをしゃべる場面が多かったです。ただ、休憩しようかと言うと逆に頑張る気になっていました。'),
  ('0c42158e-37f0-5d37-9d1f-b4df2a240202', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-30', '17:30:00', null, '振替 / モーションセンサーの機能を知ろう', 'リンゴたたきのゲームは初めて使うモーションセンサーの機能だったので、やすのりくんともに単身でいました。コード作り途中では、ミスづくりをなく、少し速めの店舗に変えてアレンジを楽しめていました。 後半は自作のスプラトゥーンのゲームでバグが発生していたので、直していきました。バグの内容が体力がゼロになってもインクも出て動き続けてしまうことです。それぞれの動きを作った場所を聞いたが、全部把握していてとても自分が見やすい作り方になっていてすごいと思った。動きの関しては、ほかのスプリクトを止めるで解決をしたが。本体と別になっているインクの方のバグが時間が切れてできませんでした。 ねこのインクが出て続けてしまうバグの解決案として、ねこのインクのクローンの発生方法が、イベントの「キーが押されたら」になっているので、もしの形に直し、体力が0になった時のコードにメッセージか変数スイッチを用意して、メッセージをインクの方で受け取り、止めるのコードを作ればいいと思います。変数スイッチだったら「もしのキーが押された」の中に変数スイッチのコードを追加して止めればいいと思います。', '猫のインクのバグ直しをするって約束しました。5分もかからずに終わると思います。', 'タイピング: かなり進めました。
盛り上がり: ツムツムの高得点のやり方を承太郎君からやすのりくんとともに教わっていました。'),
  ('0ebe592f-74fa-5324-bacb-0753b9f8f865', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-30', '17:30:00', null, '通常 / 検定対策', '少し早めに来室したので、自作のゲームを見せてもらいました。そんなに完成させたわけではないと謙遜しつつも、Scratchに保存した作品が400を超えたと教えてくれました。毎日いじるのが大事だよね、という言葉に喜んでくれたようでした。 試験対策問題は、残り5分ほどで「もう無理」と目で合図をしてきたので一度切り上げました。時間いっぱいまで粘るよりも、きちんと答え合わせをしたいとの希望だったため、一緒に問題を見ていきました。 「変数をある数で割った時の値を切り下げた」というところで、「変数をある数で割った時の余りを切り下げた」にしていたところがバグの原因でした。式の入れ方は合っていたので、問題文に注意して、「値」なのか「あまり」なのか注意するように伝えました。本人もしっかり納得できていたと思われます。 演算式において、間違えやすい不等号の向きや条件分岐の入れ子の位置などはしっかりできていたのですが、修正するプログラムの変数名を直し忘れていたりと、惜しいミスがいくつかありました。 「日本語に注意しよう」ということで、はるとくんも納得して授業を終えました。', null, '盛り上がり: あえて馴染のなさそうな問題を選んだこともあり、試験直後は「難しかった…」と疲れていましたが、できているところがほとんどだったため、少し自信をとりもどせたようでした。1級の問題は長いため、途中で日本語の見落としがあって先に進んでしまうと、あとから見直すのが大変なため、問題に印をつけたりしてゆっくりやってみて、というこちらの発言も素直に聴いてくれて、がんばってみる！と前向きな感じを見せてくれました。'),
  ('861c90ce-a561-57fd-a264-2e1e48c58c62', 'c4095f7b-abb4-5084-90b8-85f2fc80693a', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-30', '16:30:00', null, '通常 / 追跡ゲームの続き', 'まずはスコアをつけました。画面を見せるとやっていることはすぐわかりましたが、変数には慣れていないようなので少し誘導しながらやりました。「敵に触れたなら→1点増やす」は比較的すぐわかりましたが、「旗が押されたなら→0点に戻す」は少し迷っていました。得点リセットはゲームが終わったときにやらないといけないと思っていたようなので、終わったときに何かするよりも次回を始めるときにやったほうが楽というヒントを出すとできました。途中疲れたようでコスチュームいじりばかりやってしまったので、しっかり休憩してまた最後に頑張りました。これも少し困っていましたが、「まで待つ」と等式を組み合わせるというヒントを出すと、スコアが10点に到達したら背景を変えることができました。そのときにYou win などの文字を出すことになっていますが、これだけ残してあとは作成が終わりました。', 'ゆうれいから逃走 最後の文字だけ？', 'タイピング: 新しい文字が出てきても少しずつ慣れていました。
盛り上がり: 慣れない内容が多かったですが吸収できたと思います。'),
  ('1f90bba6-ab44-5d79-b678-04fc2994b26a', '5b845d9e-ae9d-542e-821e-429bc0c9dd65', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-30', '17:30:00', null, '通常 / 試験後の息抜きに、お手本を見ながらゲーム作成', '昨日試験が終わったばかりだったので、今日は気楽にお手本を見ながらのゲーム作成を勧めました。当初は「ツムツムは難しそう」としり込みをしていましたが、プリントを見せて、昨日の試験ができたのだから大丈夫、と勧めると、納得して取りかかっていました。 定義の作成のところで少しとまどったようでしたが、それ以外は黙々と作成していました。承太郎くんと話をしながらだったのもあり、丸写しではなく、コードを理解しようという姿勢が見られました。', null, '盛り上がり: メインは写経でしたが、難易度がちょうどよかったようで、きちんとコードを読みながら熱心に作成できていました。'),
  ('0efc9062-5114-5bb1-943c-35ac868cc927', '30a27e64-1043-537e-87c5-6cf81272b1ca', null, null, '2023-11-18', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('d4b5bd3d-235d-52e0-b11c-fb1a6dedeaa4', '28d52d6e-7571-5090-a2d9-492c997b719e', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-30', '17:30:00', null, '振替 / 自作ゲームを完成させよう', 'お家で作っていた人魚から追いかけまわす自作ゲームのわからない所の手直しから始めました。クリアorオーバー画面をそれぞれスプライトとして出すにはどうすればいいか悩んでいたらしく、ゲームの詳細を聞ながら一緒に作っていきました。新しく画面から色を抽出の仕方を教えたり、「まで待つ」のコードを使ったが、知っているか聞いたとき、何となくな感じがしたので、そこをしっかり固めることもあっていいと思います。最初にクリアのコードを作ったら、オーバーのコードはほとんどパターンを見抜いてそこまで補助いらずに作れていました。もう１つ、あやふやだなと感じたブロックは「メッセージ」です。送ると受け取るの機能の区別ができてなかったので、基本操作コースでそこはしっかり取り組んだ方がいいと思います。 時間は半分くらいで完成できたが、満足していたので、あとは遊んでよい風にしました。', null, 'タイピング: 丁寧にやっていました
盛り上がり: 久しぶりの教室だったのかずっと集中を切らさず取り組んでいました。'),
  ('354a8f67-69bf-5fe4-90da-86e6cd3c9ae7', '51314a24-5644-5ff1-acb7-e15b53d010e3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-30', '17:30:00', null, '通常 / 少し複雑なコードの構築', '前回は自己流で作成していたのですが、少し行き詰まったようで、一度お手本を見て作りたいとのことで、プリントを見ながら修正したり追加をしたりしていました。 変数の使い方については承太郎くんの考えとは少し違ったようでしたが、とりあえずこれでやってみるとのことでした。 前回は完成作品で遊んだだけで作成に入っていましたが、やはり、そこからすべて、設計図やメモもなしに作るには複雑だった、という感じで、今日は熱心に元のコードを見ていました。', null, '盛り上がり: ゆきちゃんと一緒に、ツッコミを入れたり感心したりしながら、楽しそうに作成を進めていました。 途中で「ツムツムのランキング1位の人だ！」と藤田兄弟とそうちゃんに囲まれて、ゲームのやり方を披露してくれました。'),
  ('4f1cc450-024f-59dc-a0e8-1fe5e947e832', '57f45872-1f3e-5540-b676-bf9023444e39', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-30', '16:30:00', null, '通常 / 基本的なジャンプゲームの作成', '前回の続きとして、ジャンプゲームの02から始めようとすると「コードは長い？」としり込みする様子を見せました。ドーナツキャッチでは写経を頑張っていましたが、本人なりに、理解するには手に余ると思っていたようです。 カードの表とファイルの表を見せて、一つ一つのステップで作成するコードはとても少ないことを説明し、簡単なコードを組み合わせて作品を仕上げてみようと誘うと、それなら最後まで頑張ってみると言ってくれたので、今日の目標はファイルの表を一段、スタンプで埋めることにしました。 お手本の動作をさせるために必要なブロックはなんとなくわかっていて、名前も出るのですが、それがどこにあるのかがまだ曖昧な様子でした。 課題を与えてこちらがそばを離れることはでき、その間、自分で取り組むこともできていますが、できるとすぐに先生を呼びに来るところがあります。 繰り返しの「ずっと」や「～まで待つ」などは覚えていましたが、座標はちょっと怪しいです。 敵のスプライトを増やすところやスコアを作成するところなど、初めは面倒なのか「これで完成でもいい」と言ってはいましたが、少し目を離すと自分で作成を始めていて、それをほめると得意そうにしていたりしていました。必ずしも言っていることが本心ではないこともあるようです。 今日はきちんと一つの課題を仕上げたことをファイルを見せながらほめると、満足そうにしていました。授業後はいそいそと宿題まで済ませ、がんばった、という感じで帰っていきました。', null, 'タイピング: S～Aをとろうと頑張っていました
盛り上がり: 口ではぼやくこともありましたが、課題はきちんとやろうと思っているようで、結果としてどこも飛ばさず手抜きもせず、しっかりとやり遂げて満足げにしていました。'),
  ('578c5ea1-0803-57d0-a318-156ff4fdf403', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-30', '17:30:00', null, '通常 / 検定練習', '制限時間ちょうどくらいで解き終わり、バグが1つ残っていたので確かめると変数名を間違えていただけでした。他はミスなくできていました。', null, '盛り上がり: 少し珍しいタイプのゲームがテーマでしたが、冷静に作れました。'),
  ('936721b5-eda4-57a9-831a-fe4d340bb8d9', '28d52d6e-7571-5090-a2d9-492c997b719e', null, null, '2023-11-18', null, null, '休み（振替対象）', null, null, '時間帯: その他'),
  ('735a3e76-e60a-599e-95fa-1529cc95d950', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-30', '17:30:00', null, '振替 / ゲーム作成', 'prgのゲームをいくつか遊び、その中から脱出ゲームを選択して動画を見ながら作りました。一番最初の、メッセージを使ったゲームスタートの処理だけできました。', null, '盛り上がり: リラックスした様子でした'),
  ('c8ea65dd-2176-50d5-bb16-e49a697fc02e', '32f6cea5-91f1-545b-abe7-bea7a0910e0f', null, '235dd485-0c35-5796-b48e-16ad99a59b5a', '2023-11-30', '16:30:00', null, '通常 / 検定練習', 'もう5回目の練習もあって、20分程度で問題文はミスなく作り終わり、アレンジを十分に楽しむ時間があったので、安心して受けられると思います。過度なアレンジをしすぎて本文からそれたことになることは、心配ですが。', null, 'タイピング: ミスタイプ少なめでした'),
  ('75a13529-2efc-5bce-88ab-5044c888af1f', 'e124842b-0dc5-56a0-a4cf-cd0dadf8adde', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-30', '16:30:00', null, '通常 / 検定練習', '少し時間に余裕をもって解き終わり、アレンジの作成と内容の説明の記述までできました。答え合わせすると、軽いケアレスミスが1個あっただけでほとんど完璧にできていました。', null, '盛り上がり: 今日が本番前最後だと伝えると、集中力を持って取り組んでくれました。'),
  ('46eaa63a-fef3-50e4-bfa4-a6f293e56ee9', 'e7e92ea3-12aa-5b3d-8960-284fd1a2a1b3', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-21', '17:30:00', null, '振替 / 検定対策', '「りんごとばなな」のブロックを使ったことがなかったというので、そこだけ軽く説明しました。すぐに理解して、間に変数をはさんだブロックを作成することができていました。 「でなければ」のある条件分岐の入れ子をしたことがなかったようで、問題文の通りに作成したパーツを並べて迷っている様子が見られました。答え合わせのときに、問題文の通りに、りょうやくんが思う通りにつなげるように促すと、きちんとできていました。見たことのない組み合わせだと思っても、3級のレベルではりょうやくんが思う通りに作成してみてもほぼ間違っていないので、本番では最後まで作成するように伝えました。 作成後に、丁寧にすべてのパターンでゴールをして、3つの条件分岐がきちんとできていることを確認していました。', null, '盛り上がり: 何度か問題にチャレンジして、だいぶ慣れてきたようでした。答え合わせや実際の動作チェックを、とても楽しそうにしていました。'),
  ('5b642258-b3f1-5e23-8f0a-d64f1cd68566', 'a0df2d24-980c-5fcc-bd49-2164017e8a7c', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-21', '17:30:00', null, '通常 / 検定対策', '今日は応用課題に戻ったためか、問題文への集中力にはかなり欠けていました。 ステージに書くと指定のあるコードをスプライトに作成していたりして、本人は、その部分のコードはちゃんと動いているとぼやいていましたが、これは試験なので、こんなことで減点されたらもったいないと伝えると、しぶしぶといった感じではありましたが、わかったと言っていました。 やはり、問題文の文章が長くなると丁寧に読む気がなくなるようで、1か所、ここはわからなかったと飛ばしているところがありました。答え合わせの際にこちらが問題文を読むと問題なくできていたので、読むのが苦痛なのかと思われます。', null, '盛り上がり: 授業終了時は、前々回と同様にぐだぐだとお母さんのところに行っていましたが、授業の最後に、検定が終わったらどんなことをしたいか考えておいてと伝えた時だけは、少し笑顔を見せていました。
備考: お母さんに、検定の応用課題を苦手としていることは伝えました。お母さんとしては、苦手だとしても、今回がんばって3級を受けようとしたことは必要だったと思っているとのことでした。'),
  ('3dd99661-1915-57ed-9794-b926fb2485dc', '404e6df9-9bfe-539a-95f0-68d304d0e013', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-21', null, null, '通常 / 自作のプログラムの作成', '今日はScratchの気分だとのことで、熱心に電車のシステムを作成していました。 操作パネルの見た目などにも小学生のときよりこだわって作成しているようでした。 番号を選んだら該当の音声が流れるところを延々と条件分岐で作成していたため、車両やダイヤの変更などがあって、この中で複数の箇所を変えるとしたらどうするか問いかけ、現行のシステムを作る場合はメンテナンスもミスなくやりやすいようにする必要があることを伝えると、素直に考えこんでくれました。 メインのコードにひたすら条件分岐をたくさんつけて作成するとメンテナンスが大変なこと、コードを別にした方がすっきりすることは理解してくれたので、番号と音声ファイルのデータを別に持つことを提案し、今回の場合はリストを使ってみることを勧めると、すぐに作成し始めていました。 リスト自体は少し忘れているとのことだったので、【単元】リスト＿完成版 都道府県と県庁所在地クイズを見せて思い出させると、時間を10分くらいオーバーするまで熱心に作成していました。', null, '時間帯: その他
盛り上がり: Scratchでのオリジナル作品作成でしたが、他のサイトを見たりという脱線も今日はほとんどなく、熱心に取り組んでいました。'),
  ('690a2201-e8ea-5fec-b15d-b4b325ea9b80', '4a40504a-7fb4-526c-93d1-ae7d759e1631', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-21', '16:30:00', null, '振替 / 検定問題4級応用課題4', '日本語が少し慣れず、混乱してしまっていたようです。とくに、「端につくまで繰り返す」の部分を「端についたらはねかえる」と誤解してしまっていたようで、「もし」がないとなかなか条件分岐と思えない様子でした。紙面にはやった部分をひとつずつチェックしたり、最後まで考え続けたりしていてとてもよかったです。アレンジとしてゴールの旗を作っていました。', null, null),
  ('eac0af9b-3bdd-57c2-b590-8249a9f7a696', '7d01236e-620e-5177-a6f4-af325a582aae', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-21', '17:30:00', null, '通常 / 検定問題4級応用課題4', 'おわったときにかなり自信がありそうな様子でした。プログラムの読み飛ばしが１箇所あって残念でした。またコスチュームを変えるときに自分で考えた方法でプログラムを作っていたので、「次のコスチュームにする」のブロックを思い出してもらいました。アレンジとしては、結果を楽しみにするペンギンを追加していました。メッセージをうまく使ってきれいに作成できていたと思います。', null, null),
  ('4ff2f98f-1ca7-5839-a9c1-1e0e43a3d284', 'ab3fb892-bd0d-59cc-82c8-75e087dd040e', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-21', '17:30:00', null, '通常 / 検定問題1級応用課題1', '時間前にアレンジまで終えることができていました。すごい！かなり自信もありそうな様子でした。 条件分岐の部分でいくつかミスがありました。文章も入り組んでいるので、a, bと続くなかでどこまでが「もし」に含まれる部分か分からなくなってしまうようです。「もし」と迷う文の位置関係に注目するように伝えました。（もしと同じ文中なのかそうでないなのか）他の部分はよくできていました。アレンジも面白かったです。', null, null),
  ('64b6f424-dc7c-5b09-beb4-53c2f33e18a6', '36b32225-ef6e-58f8-add5-c3bfbcfffc48', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-21', '16:30:00', null, '振替 / 検定対策', '自宅で取り組んだ時は途中で混乱した、と言っていましたが、教室にきて試験モードになったのか、自力でやらせてほしいとの申し出があったため、自力で最初から解きなおしてもらいました。 時間内にアレンジまで一生懸命完成させていました。 プログラムの動きはほぼ問題なくできていたようですが、条件式の作り方などに、正答例との違いがありました。（条件式に「かつ」を入れるか、入れ子にするか、など） 問題文よりもムービーを見た動きから作成してるところもあるとのことだったので、通常はそれでも良いけれど、満点を狙うのなら問題文の通りに作成した方が減点の心配がないので良いかもしれない、と伝えると、とても納得したようでした。正答例と違う書き方をしているところの問題文を一緒に確認して、さらに納得していました。', 'パッと見て苦手そうな問題にチャレンジしておきたいとのはるとくんの希望で、応用課題3をする予定です。', '盛り上がり: お母さんによると、久しぶりで緊張しているとのことでしたが、問題に取りかかると熱心にできていて、こちらの問いかけなどにも丁寧に受け答えをしてくれていました。 家では途中であきらめてしまった問題が、こちらでは自力で完成まで持っていけたので、少し安心したようでした。'),
  ('f766963a-a48c-5b67-9672-039267889f3a', 'df943b73-1f10-5ba9-81cf-d0be33cc8a9d', null, '57409c47-bd61-561f-89f4-fb91227864f8', '2023-11-21', '16:30:00', null, '通常 / 検定問題1級応用課題1 具材がひたすら増殖するバグの確認 できれば応用課題2か3', '具材のプログラムにミスがありそうだったので一緒に確認しました。具材バグはメッセージの後に「ずっと」を置いてしまっていたことが原因だったようです。また正しい中身を選んでもきちんと判定されなかったので、判定の部分も一緒に確認しました。条件分岐の部分を１箇所間違えていたり、リストのリスト番目などの独特な言い回しの部分で間違えたりしていました。プログラムの修正が少し苦手なイメージです。 30分ほど時間があまったので、応用課題2に挑戦してもらいました。引数を知らないようだったので、定義を作る部分で一緒に引数の使い方や考え方を確認しました。なんとなく理解できたようです。', null, null),
  ('5eb71f99-6e61-5c8e-90a8-b6e9c79257dd', '73cda0ef-d9c0-5d87-a0db-3c9fef794f25', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-21', '16:30:00', null, '通常 / 少し難しい作品を完成させる', 'プリントを見ながら一気に完成させていましたが、ツムツムの動きがなかなか意図した通りにならずに悩んでいました。 プリントに頼って作成していたので、どのコードが何をしているのかをイマイチ把握しきれていないようでした。 どのスプライトの動きがおかしいのか、どの時点でどのようにおかしい動きになっているのか、順に考えさせながら、バグを探すコードを見つけさせました。ヒントはかなり出しましたが、自分でもコードをよく見てバグを探そうとする態度は見られました。 コードを見直すときに、定義がよくわからないまま作成していたせいか、こちらのコードを見ようとしていなかったので、定義にはわかりやすい名前がついていることから、バグの現象に関係していそうな定義を探させ、訂正箇所を見つけさせました。', 'バグの修正と作品の完成', 'タイピング: 一生懸命やっていました
盛り上がり: 基本的にはテンション高くがんばっていました。完成！と思ったところでいくつもバグを発見してしまい、少し気が抜けた様子も見せていましたが、気を取り直してバグ探しに取り組むところは成長したと思います。
備考: 自転車で走行中に異音がするといって、少しだけ遅れてきました。 フレームを少し浮かせて直したところ、とても喜ばれました。'),
  ('dc5efdd7-1b33-5d58-ae40-178a67589a80', 'd6f263f2-9dc6-55f5-b59a-46d9b899a04e', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-20', '17:30:00', null, '通常 / 検定対策', 'タイピングコロシアムが気になったようで、検定問題を早く解いてタイピングをするんだと張り切っていました。気合を入れて熱心に取り組めたのは良いのですが、その分問題文の読み飛ばしが2か所ありました…。 最後まで解いた後、魚が出てこないバグを一緒に探しました。サカナの動作①の最後の文章「ステージに表示される」を読み飛ばしていました。 「セリフが消える」がわからなかったようで、魚がずっと「わー」と言いっぱなしだったため、教えた上で、本番ではブロックについては答えられないので覚えておくように伝えました。 のこり時間が0になってもゲームが終わらなかったため、該当すると思うコードの場所をチェックさせました。ステージの動作のコードを自分で見直して「あってると思う」と言っていたので、問題文ときちんと照らし合わせて、③のメッセージ「エンド」を送るブロックを入れていないことに気付かせました。', null, 'タイピング: タイピングコンテストの結果がとても嬉しかったようで、プレイグラムにも熱心に取り組んでいました。検定課題終了後に、縁くんがやっていたタイピングコロシアムで盛り上がっていました。
盛り上がり: タイピングの結果が良かったこと、縁くんがやっていたタイピングコロシアムが気になってしまったことが重なり、早く課題を終わらせようとがんばっていました。注意力が落ちてしまったのは残念でしたが、本人もそこは反省していたようでした。 タイピングのおかげか、終始機嫌よく、お母さんにも嬉しそうにタイピングの結果を説明していました。'),
  ('4ad3b232-0a4f-5012-94f6-d4ab80fad080', 'b376de86-aec8-50e2-8e94-85d9eb7cade8', null, 'b31424d7-90ac-5732-803d-15f61def0db2', '2023-11-20', '17:30:00', null, '通常 / インベーダーゲームの作成', 'まず「端に触れるまで動かす」という意味のブロックが多数置かれていたので、「同じ事を何度も言われたら人間も嫌だよね」と伝えて一緒に直しました。どれを残せばいいか考えて整理することができました。また、ビームのクローンが消えなかったので削除のタイミングを考えてもらうと処理できました。このあと、スライムが落ちてくるようにしたいとのことだったので、ビームの動きとだいたい同じだねとヒントを出すとできました。このときスライムの初期座標はランダムに決めたいと言って、x座標を乱数にできました。', null, 'タイピング: 対戦ゲーム型のタイピング練習サイトで、自分で検索してやっていました。かなり楽しそうにやっていました
盛り上がり: タイピングコロシアムを周りの子に勧めていました'),
  ('bd3f5f56-aed3-5982-a00e-7eaee5fe90c5', '9a5e810f-f1db-5eda-a4f8-cd9d07542c3f', null, '9fbad4c1-1191-5f6c-bb63-8027ba647a30', '2023-11-20', '16:30:00', null, '振替 / 検定対策', '応用課題から5～8の中から本人に問題を選んでもらいました。 「セリフが消える」のブロックについてだけ質問がありましたが、あとは黙々と最後まで完璧に解いていました。 問題自体はきちんとできていましたが、不安なところはあるかと聞くと、不等号の向きには迷いがあるとのことでした。問題文に直接書き込みをするやり方を教えたところ、納得できたようでした。 タイピングの結果から、残り時間が少なくなると焦る傾向があると思われるため、アレンジについても、本番で残り時間が5分以内だったら下手にいじって動かなくなるよりも、じっくり見直しをした方が良いと伝え、余裕があったら簡単なアレンジをしてみるように伝えると、笑顔で納得していました。', null, 'タイピング: タイピングコンテストの結果を見せて、少し話をしました。普段コンスタントに出していた記録よりかなり低かったのですが、結果からも推測できた通り、開始直後と終了間際にとても緊張して焦ってしまったようでした。 普段のタイピングはよくできていること、中間部分の成績がコンスタントに出せていれば級はすぐに上がることを伝え、緊張対策のためにも、今後のタイピングで定期的に本番としてうでだめしなどにチャレンジしていこうと伝えました。
盛り上がり: 今日の課題は、セリフが消える以外はカンペキにできたので、安心したようでした。 残り時間はサービスで、アルスパークから興味のあるゲームを探すという課題にしたところ、丁寧にゲームで遊んでコードを見たりしていました。
備考: お父さんから、検定当日の空き時間について質問がありました。授業後の空き時間は教室で待つこともできるけれど、試験に集中するためにも一度外に出ることをお勧めしました。お父さんも納得され、授業後に一度迎えにくるとのことでした。')
on conflict (lesson_record_id) do update set lesson_date = excluded.lesson_date, start_time = excluded.start_time, end_time = excluded.end_time, title = excluded.title, content = excluded.content, homework = excluded.homework, memo = excluded.memo;

commit;
